export const updateFirebaseUsage = functions.pubsub
  .schedule('every 24 hours') // Runs once a day
  .onRun(async (context) => {
    console.log('Running daily Firebase usage update...');
    const usageData = await getBillingData();

    const db = admin.firestore();
    const usageRef = db.collection('usage').doc('dailySummary');

    try {
      await usageRef.set(usageData, { merge: true });
      console.log('Successfully updated Firebase usage data:', usageData);
    } catch (error) {
      console.error('Error updating Firebase usage data:', error);
    }
  });

import * as XLSX from 'xlsx';
import { z, ZodSchema } from 'zod';
import {
  collection, doc, getDoc, setDoc, writeBatch, getDocs,
} from 'firebase/firestore';
import { PipelineResult, db } from '@/lib/firebase';
import { trackRead, trackWrite } from '@/lib/firebaseUsageTracker';

export interface PipelineResponse {
  success: boolean;
  result: PipelineResult;
  error?: string;
}

// ─── ID determinístico — 1 doc por pipeline+ano+mês ──────────────────────────
// Antes: cada import criava um novo doc aleatório com TODOS os dados acumulados
// Agora: sempre o mesmo doc → updates incrementais → sem explosão de escritas
export function mainDocId(type: string, year: number, month: number): string {
  return `${type}_${year}_${String(month).padStart(2, '0')}`
}

function toDateString(value: any): string | any {
  if (typeof value === 'number' && value > 10000 && value < 60000) {
    const date = XLSX.SSF.parse_date_code(value);
    if (date) {
      return `${String(date.d).padStart(2,'0')}/${String(date.m).padStart(2,'0')}/${date.y}`;
    }
  } else if (value instanceof Date) {
    return `${String(value.getDate()).padStart(2,'0')}/${String(value.getMonth()+1).padStart(2,'0')}/${value.getFullYear()}`;
  }
  return value;
}

// ─── Parser principal ─────────────────────────────────────────────────────────
function parseSheetWithHeaderDetection(
  sheet: XLSX.WorkSheet,
  sheetName: string,
  fileName: string,
): any[] {
  if (!sheet || !sheet["!ref"]) {
    console.warn(`[actions-utils] Aba "${sheetName}" vazia.`);
    return [];
  }

  const rawData: any[][] = XLSX.utils.sheet_to_json(sheet, {
    header: 1, blankrows: true, defval: undefined,
  });

  let firstHeaderIndex = -1;
  let headerRow: any[] = [];

  for (let i = 0; i < Math.min(rawData.length, 30); i++) {
    const rowStr = String(rawData[i]?.join("|") || "").toUpperCase();
    if (rowStr.includes("MOTORISTA") && (rowStr.includes("PLACA") || rowStr.includes("DATA"))) {
      firstHeaderIndex = i;
      headerRow = rawData[i] ?? [];
      break;
    }
  }

  if (firstHeaderIndex === -1) {
    console.warn(`[actions-utils] Cabeçalho não encontrado em "${sheetName}".`);
    return [];
  }

  const colNames: string[] = [];
  const nameCounts: Record<string, number> = {};
  for (let i = 0; i < headerRow.length; i++) {
    let name = headerRow[i] != null ? String(headerRow[i]).trim() : `__COL_${i}`;
    if (!name) name = `__COL_${i}`;
    const count = nameCounts[name] ?? 0;
    nameCounts[name] = count + 1;
    colNames.push(count === 0 ? name : `${name}_${count + 1}`);
  }

  const placaSisIdx = colNames.findIndex(n =>
    n.toUpperCase().replace(/\s+/g, " ").includes("PLACA SISTEMA")
  );
  const catColIndex = placaSisIdx > 0 ? placaSisIdx - 1 : 5;

  const result: any[] = [];
  let currentRota = "";

  for (let r = firstHeaderIndex + 1; r < rawData.length; r++) {
    const row = rawData[r];
    if (!row) continue;

    const col1 = String(row[1] ?? "").trim().toUpperCase();
    const col2 = String(row[2] ?? "").trim().toUpperCase();

    if (col1 === "DATA" && col2 === "MOTORISTA") {
      const rawCat = String(row[catColIndex] ?? "").trim();
      currentRota = rawCat || currentRota;
      continue;
    }

    if (!row.length || row.every(v => v == null || v === "")) continue;

    const obj: Record<string, any> = {};
    for (let c = 0; c < colNames.length; c++) {
      const val = row[c];
      if (val != null && val !== "") obj[colNames[c]] = val;
    }

    if (Object.keys(obj).length === 0) continue;
    obj.__rota__ = currentRota;
    result.push(obj);
  }

  Object.assign(result, { __colNames__: colNames });
  return result;
}

// ─── FileReader ───────────────────────────────────────────────────────────────
class FileReader {
  constructor(private formData: FormData) {}

  async read(fieldName: string, schema?: ZodSchema<any>): Promise<any[]> {
    const file = this.formData.get(fieldName) as File | null;
    if (!file) return [];
    const buffer = await file.arrayBuffer();
    const wb     = XLSX.read(buffer, { type: 'array', cellDates: true });
    const sheet  = wb.Sheets[wb.SheetNames[0]];
    const rows   = parseSheetWithHeaderDetection(sheet, wb.SheetNames[0], file.name);
    if (schema) {
      const result = z.array(schema).safeParse(rows);
      if (!result.success) throw new Error(`Validação falhou para ${file.name}.`);
      return result.data;
    }
    return rows;
  }

  async readAll(fieldName: string): Promise<any[][]> {
    const files     = this.formData.getAll(fieldName) as File[];
    const sheetName = this.formData.get('sheetName') as string | null;
    const allResults: any[][] = [];

    for (let fileIdx = 0; fileIdx < files.length; fileIdx++) {
      const file   = files[fileIdx];
      const buffer = await file.arrayBuffer();

      if (sheetName) {
        const workbook = XLSX.read(buffer, { type: 'array', cellDates: true, sheets: sheetName });
        if (!workbook.SheetNames.includes(sheetName)) {
          throw new Error(
            `A aba "${sheetName}" não foi encontrada em "${file.name}". ` +
            `Abas disponíveis: ${workbook.SheetNames.join(', ')}`
          );
        }
        const sheet = workbook.Sheets[sheetName];
        const rows  = parseSheetWithHeaderDetection(sheet, sheetName, file.name);
        if (rows.length > 0) {
          Object.assign(rows, {
            __sheetName: sheetName, __fileIndex: fileIdx,
            __colNames__: (rows as any).__colNames__,
          });
          allResults.push(rows);
        }
      } else {
        const workbook = XLSX.read(buffer, { type: 'array', cellDates: true });
        for (const name of workbook.SheetNames) {
          const sheet = workbook.Sheets[name];
          const rows  = parseSheetWithHeaderDetection(sheet, name, file.name);
          if (rows.length > 0) {
            Object.assign(rows, {
              __sheetName: name, __fileIndex: fileIdx,
              __colNames__: (rows as any).__colNames__,
            });
            allResults.push(rows);
          }
        }
      }
    }

    return allResults;
  }
}

// ─── Interfaces ───────────────────────────────────────────────────────────────
export interface PipelineArgs {
  year: number; month: number; files: FileReader; formData: FormData;
}
export interface ProcessorOutput {
  summary: string; data: any[]; [key: string]: any;
}

// ─── Sanitização ─────────────────────────────────────────────────────────────
function sanitizeForFirestore(obj: any): any {
  if (obj === undefined || obj === null) return null;
  if (typeof obj === 'number' && (!isFinite(obj) || isNaN(obj))) return null;
  if (obj instanceof Date)  return toDateString(obj);
  if (obj instanceof Error) return obj.toString();
  if (Array.isArray(obj))   return obj.map(item => sanitizeForFirestore(item));
  if (typeof obj === 'object') {
    const newObj: { [key: string]: any } = {};
    for (const key in obj) {
      if (Object.prototype.hasOwnProperty.call(obj, key)) {
        newObj[key] = sanitizeForFirestore(obj[key]);
      }
    }
    return newObj;
  }
  return obj;
}

// ─── porFilialDia ─────────────────────────────────────────────────────────────
function calcularPorFilialDia(data: any[]): Record<string, Record<string, number>> {
  const porFilialDia: Record<string, Record<string, number>> = {};
  for (const row of data) {
    const filial = String(row["FILIAL"] ?? "—").trim();
    const dt     = String(row["DATA DE ENTREGA"] ?? "—").trim();
    if (!porFilialDia[filial]) porFilialDia[filial] = {};
    porFilialDia[filial][dt] = (porFilialDia[filial][dt] ?? 0) + 1;
  }
  return porFilialDia;
}

function mergePorFilialDia(
  existing: Record<string, Record<string, number>>,
  incoming: Record<string, Record<string, number>>,
): Record<string, Record<string, number>> {
  const result = { ...existing };
  for (const [filial, diaMap] of Object.entries(incoming)) {
    if (!result[filial]) result[filial] = {};
    for (const [dt, cnt] of Object.entries(diaMap)) {
      result[filial][dt] = (result[filial][dt] ?? 0) + cnt;
    }
  }
  return result;
}

function extractDayFromItem(item: any): number {
  const dateStr = String(item["DATA DE ENTREGA"] ?? "");
  const m = dateStr.trim().match(/^(\d{1,2})[\/\.]/);
  return m ? parseInt(m[1]) : 0;
}

// ─── processAndSave ───────────────────────────────────────────────────────────
export async function processAndSave(
  pipelineType: string,
  formData: FormData,
  processor: (args: PipelineArgs) => Promise<ProcessorOutput>
): Promise<PipelineResponse> {
  try {
    const year  = Number(formData.get('year'));
    const month = Number(formData.get('month'));
    if (isNaN(year) || isNaN(month)) throw new Error('Ano e mês devem ser números válidos.');

    const files           = new FileReader(formData);
    const processorResult = await processor({ year, month, files, formData });
    const sanitized       = sanitizeForFirestore(processorResult);

    const { data, extraSheets, dedupKeys: newDedupKeys, ...metadataExtras } = sanitized;

    const savedResult = await saveToFirebase(
      pipelineType, year, month, data,
      { ...metadataExtras, newDedupKeys: newDedupKeys ?? [] }
    );

    // extraSheets volta para o cliente mas NUNCA vai ao Firestore
    return {
      success: true,
      result: { ...savedResult, data, extraSheets } as any,
    };
  } catch (error: any) {
    console.error(`[${pipelineType.toUpperCase()}] Erro:`, error);
    return { success: false, result: {} as PipelineResult, error: error.message };
  }
}

// ─── saveToFirebase ───────────────────────────────────────────────────────────
// ✅ NOVO MODELO — custo linear:
//   • 1 doc determinístico por pipeline+ano+mês (sem proliferação de docs)
//   • Lê apenas o metadata do doc principal (1 leitura por import)
//   • Escreve apenas os NOVOS registros (N escritas, nunca reescreve os antigos)
//   • dedupKeys no metadata = dedup sem ler subcoleção (eliminada leitura O(N))
//
// Antes: 6 imports × (lê N existentes + escreve N+M acumulados) = O(N²) ops
// Agora: 6 imports × (lê 1 metadata + escreve M novos) = O(N) ops
// ─────────────────────────────────────────────────────────────────────────────
export async function saveToFirebase(
  type: string,
  year: number,
  month: number,
  data: any[],           // APENAS os novos registros deste import
  extras: Record<string, any> = {}
): Promise<PipelineResult> {
  const docId     = mainDocId(type, year, month)
  const mainRef   = doc(db, 'pipeline_results', docId)
  const itemsRef  = collection(db, 'pipeline_results', docId, 'items')

  // ── 1. Lê metadata existente (1 leitura) ─────────────────────────────────
  const existing     = await getDoc(mainRef)
  trackRead(1)
  const existingData = existing.exists() ? existing.data() : {}

  const existingDedupKeys: string[]                           = existingData.dedupKeys   ?? []
  const existingPorFilialDia: Record<string, Record<string, number>> = existingData.porFilialDia ?? {}
  const existingItemCount: number                             = existingData.itemCount   ?? 0

  // ── 2. Computa novos metadados ────────────────────────────────────────────
  const newDedupKeys: string[]    = extras.newDedupKeys ?? []
  const allDedupKeys  = [...new Set([...existingDedupKeys, ...newDedupKeys])]
  const newPorFilialDia           = calcularPorFilialDia(data)
  const mergedPorFilialDia        = mergePorFilialDia(existingPorFilialDia, newPorFilialDia)

  console.log(
    `[FIREBASE] Doc: ${docId} | `,
    `Existentes: ${existingItemCount} | Novos: ${data.length} | Total: ${existingItemCount + data.length}`
  )

  // ── 3. Escreve APENAS os novos itens na subcoleção ────────────────────────
  const BATCH_LIMIT = 498 // reserva 2 ops (doc principal + margem)
  const allBatches: ReturnType<typeof writeBatch>[] = []
  let   currentBatch     = writeBatch(db)
  let   currentBatchSize = 0
  allBatches.push(currentBatch)

  for (const item of data) {
    if (currentBatchSize >= BATCH_LIMIT) {
      currentBatch     = writeBatch(db)
      currentBatchSize = 0
      allBatches.push(currentBatch)
    }
    const day = extractDayFromItem(item)
    currentBatch.set(doc(itemsRef), {
      ...item,
      _year:  year,
      _month: month,
      _day:   day,
    })
    currentBatchSize++
  }

  // ── 4. Atualiza (ou cria) o doc principal com metadados ───────────────────
  await setDoc(mainRef, {
    pipelineType:    type,
    year,
    month,
    timestamp:       Date.now(),
    summary:         extras.summary ?? '',
    itemCount:       existingItemCount + data.length,
    duplicadasCount: Array.isArray(extras.duplicadas) ? extras.duplicadas.length : 0,
    dedupKeys:       allDedupKeys,
    porFilialDia:    mergedPorFilialDia,
  }, { merge: true })

  if (data.length > 0) {
    await Promise.all(allBatches.map(b => b.commit()))
  }

  trackWrite(1 + data.length) // 1 doc principal + N itens
  console.log(`[FIREBASE] ✅ Salvo! ID: ${docId} | +${data.length} itens`)

  return {
    pipelineType: type, year, month,
    timestamp:    Date.now(),
    summary:      extras.summary ?? '',
    id:           docId,
    data:         [],
  } as unknown as PipelineResult;
}

// ─── loadItemsFromFirebase ────────────────────────────────────────────────────
// Lê todos os itens da subcoleção do doc principal do mês.
// Usado pela VisaoAnalitica para montar o grid.
// ─────────────────────────────────────────────────────────────────────────────
export async function loadItemsFromFirebase(
  type: string,
  year: number,
  month: number,
): Promise<any[]> {
  const docId    = mainDocId(type, year, month)
  const itemsRef = collection(db, 'pipeline_results', docId, 'items')
  const snapshot = await getDocs(itemsRef)
  trackRead(snapshot.size)
  return snapshot.docs.map(d => {
    const { _year, _month, _day, ...rest } = d.data()
    return { ...rest, _itemId: d.id }
  })
}

// ─── getDedupKeys ─────────────────────────────────────────────────────────────
// Lê APENAS o metadata do doc principal (1 leitura) para obter as chaves de dedup.
// Substituiu a leitura de toda a subcoleção items/ (que causava O(N) leituras).
// ─────────────────────────────────────────────────────────────────────────────
export async function getDedupKeys(
  type: string,
  year: number,
  month: number,
): Promise<{ keys: Set<string>; docExists: boolean }> {
  const docId  = mainDocId(type, year, month)
  const mainRef = doc(db, 'pipeline_results', docId)
  const snap   = await getDoc(mainRef)
  trackRead(1)

  if (!snap.exists()) return { keys: new Set(), docExists: false }

  const dedupKeys: string[] = snap.data().dedupKeys ?? []
  return { keys: new Set(dedupKeys), docExists: true }
}

"use server"

import { PipelineArgs, PipelineResponse, ProcessorOutput, processAndSave } from "./actions-utils"

// ─── Constantes ───────────────────────────────────────────────────────────────

const BONIFICACAO_ROTAS = 16.0

// Nomes de aba para os arquivos _Ajustado (gerados pelo pipeline Coordenadores)
const ABAS_AJUSTADO = ["Relatório Diário", "Relatorio Diario", "01_Analise_Diaria"]

// ─── Helpers ──────────────────────────────────────────────────────────────────

function cleanCol(col: any): string {
  return String(col)
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[\s.\-/]+/g, "_")
}

function findCol(row: Record<string, any>, opcoes: string[]): string | null {
  const normMap = new Map(Object.keys(row).map(k => [cleanCol(k), k]))

  // Exato
  for (const op of opcoes) {
    const n = cleanCol(op)
    if (normMap.has(n)) return normMap.get(n)!
  }
  // Prefixo
  for (const op of opcoes) {
    const n = cleanCol(op)
    for (const [k, orig] of normMap) {
      if (k.startsWith(n)) return orig
    }
  }
  // Contém
  for (const op of opcoes) {
    const n = cleanCol(op)
    for (const [k, orig] of normMap) {
      if (k.includes(n)) return orig
    }
  }
  return null
}

function parseDate(value: any): Date | null {
  if (!value) return null
  if (value instanceof Date) return isNaN(value.getTime()) ? null : value

  const str = String(value).trim()

  // BR: DD/MM/YYYY
  const br = str.match(/^(\d{2})\/(\d{2})\/(\d{4})/)
  if (br) return new Date(+br[3], +br[2] - 1, +br[1])

  // ISO: YYYY-MM-DD
  const iso = str.match(/^(\d{4})-(\d{2})-(\d{2})/)
  if (iso) return new Date(+iso[1], +iso[2] - 1, +iso[3])

  // Excel serial
  const num = parseFloat(str)
  if (!isNaN(num) && num > 40000) {
    return new Date(Math.round((num - 25569) * 86400 * 1000))
  }

  const d = new Date(str)
  return isNaN(d.getTime()) ? null : d
}

function formatDateISO(d: Date | null): string {
  if (!d) return ""
  return d.toISOString().slice(0, 10)
}

function formatDateBR(d: Date | null): string {
  if (!d) return ""
  return `${String(d.getDate()).padStart(2, "0")}/${String(d.getMonth() + 1).padStart(2, "0")}/${d.getFullYear()}`
}

function toNum(v: any): number {
  if (typeof v === "number") return isNaN(v) ? 0 : v
  const s = String(v ?? "")
    .replace("%", "")
    .replace(",", ".")
    .trim()
  const n = parseFloat(s)
  return isNaN(n) ? 0 : n
}

function isSunday(d: Date | null): boolean {
  return d != null && d.getDay() === 0
}

function norm(s: any): string {
  if (s == null) return ""
  return String(s)
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
}

function pickSheet(
  sheetsMap: Map<string, any[]>,
  candidates: string[]
): any[] | null {
  for (const candidate of candidates) {
    for (const [sheetName, data] of sheetsMap) {
      if (norm(sheetName) === norm(candidate) || norm(sheetName).includes(norm(candidate))) {
        return data
      }
    }
  }
  return null
}

// ─── Carregamento do arquivo _Ajustado ────────────────────────────────────────

interface AjustadoRow {
  empresa: string
  cargo: string
  dia: Date | null
  percentualAtingido: number
}

function carregarAjustado(rows: any[]): AjustadoRow[] {
  if (!rows.length) return []

  const firstRow = rows[0]
  const colEmpresa = findCol(firstRow, ["Empresa", "empresa", "filial"])
  const colCargo   = findCol(firstRow, ["Cargo", "cargo", "funcao"])
  const colDia     = findCol(firstRow, ["Dia", "dia", "Data", "data"])
  const colPerc    = findCol(firstRow, ["Percentual_Atingido", "percentual_atingido", "% atingido", "Percentual Atingido"])

  const missing = (["Empresa", "Cargo", "Dia", "Percentual_Atingido"] as const)
    .filter((_, i) => [colEmpresa, colCargo, colDia, colPerc][i] == null)

  if (missing.length) {
    throw new Error(`Colunas não encontradas: ${missing.join(", ")}`)
  }

  return rows.flatMap(row => {
    const empresa = String(row[colEmpresa!] ?? "").trim()
    const cargo   = String(row[colCargo!]   ?? "").trim()
    const dia     = parseDate(row[colDia!])
    let pct       = toNum(row[colPerc!])

    if (!empresa || !dia) return []

    // Normaliza 0–1 → 0–100
    if (pct >= 0 && pct <= 1) pct *= 100

    return [{ empresa, cargo, dia, percentualAtingido: pct }]
  })
}

// ─── Cálculo de desempenho ────────────────────────────────────────────────────

interface DailyKey { empresa: string; diaISO: string }

interface DailyAgg {
  empresa: string
  dia: Date
  diaISO: string
  sumMot: number; countMot: number
  sumAju: number; countAju: number
}

function calcularDesempenho(
  dfMot: AjustadoRow[],
  dfAju: AjustadoRow[]
): { analiseDiaria: any[]; analiseDiariaFormatada: any[]; domingoRemovidos: number } {

  // Agrupa por Empresa + Dia (outer join manual)
  const aggMap = new Map<string, DailyAgg>()

  const upsert = (empresa: string, dia: Date, pct: number, tipo: "mot" | "aju") => {
    const key = `${empresa}||${formatDateISO(dia)}`
    if (!aggMap.has(key)) {
      aggMap.set(key, {
        empresa, dia, diaISO: formatDateISO(dia),
        sumMot: 0, countMot: 0,
        sumAju: 0, countAju: 0,
      })
    }
    const agg = aggMap.get(key)!
    if (tipo === "mot") { agg.sumMot += pct; agg.countMot++ }
    else                { agg.sumAju += pct; agg.countAju++ }
  }

  // Filtra somente motoristas/ajudantes
  for (const r of dfMot) {
    if (/motorista/i.test(r.cargo) && r.dia) upsert(r.empresa, r.dia, r.percentualAtingido, "mot")
  }
  for (const r of dfAju) {
    if (/ajudante/i.test(r.cargo) && r.dia)  upsert(r.empresa, r.dia, r.percentualAtingido, "aju")
  }

  let domingoRemovidos = 0
  const rows: any[] = []

  for (const [, agg] of aggMap) {
    // Remove domingos
    if (isSunday(agg.dia)) { domingoRemovidos++; continue }

    const mediaMot = agg.countMot > 0 ? agg.sumMot / agg.countMot : null
    const mediaAju = agg.countAju > 0 ? agg.sumAju / agg.countAju : null

    // Média ignorando nulls (skipna=True)
    const valores = [mediaMot, mediaAju].filter(v => v != null) as number[]
    const percDesempenho = valores.length > 0
      ? +(valores.reduce((a, b) => a + b, 0) / valores.length).toFixed(2)
      : 0

    const valorBonificacao = +(percDesempenho / 100 * BONIFICACAO_ROTAS).toFixed(2)

    rows.push({
      Empresa:                         agg.empresa,
      Data:                            agg.diaISO,
      Percentual_Atingido_Motorista:   mediaMot != null ? +mediaMot.toFixed(2) : 0,
      Percentual_Atingido_Ajudante:    mediaAju != null ? +mediaAju.toFixed(2) : 0,
      Percentual_Desempenho:           percDesempenho,
      Bonificacao_Dia_Total:           BONIFICACAO_ROTAS,
      Valor_Bonificacao:               valorBonificacao,
    })
  }

  // Ordena por Empresa, Data
  rows.sort((a, b) => {
    const cmp = a.Empresa.localeCompare(b.Empresa)
    if (cmp !== 0) return cmp
    return a.Data.localeCompare(b.Data)
  })

  // Versão formatada para exibição (aba 02)
  const formatada = rows.map(r => ({
    ...r,
    Data:                            formatDateBR(parseDate(r.Data)),
    Percentual_Atingido_Motorista:   `${r.Percentual_Atingido_Motorista.toFixed(2)}%`,
    Percentual_Atingido_Ajudante:    `${r.Percentual_Atingido_Ajudante.toFixed(2)}%`,
    Percentual_Desempenho:           `${r.Percentual_Desempenho.toFixed(2)}%`,
    Bonificacao_Dia_Total:           `R$ ${r.Bonificacao_Dia_Total.toFixed(2)}`,
    Valor_Bonificacao:               `R$ ${r.Valor_Bonificacao.toFixed(2)}`,
  }))

  console.log(`[CCO] ${rows.length} dias consolidados | ${domingoRemovidos} domingos removidos`)
  return { analiseDiaria: rows, analiseDiariaFormatada: formatada, domingoRemovidos }
}

// ─── Resumo Mensal (aba 03) ───────────────────────────────────────────────────

function gerarResumoMensal(analiseDiaria: any[]): any[] {
  const empresaMap = new Map<string, {
    dias: number
    sumMot: number; sumAju: number; sumDesemp: number; sumBonif: number
  }>()

  for (const row of analiseDiaria) {
    const e = row.Empresa
    if (!empresaMap.has(e)) {
      empresaMap.set(e, { dias: 0, sumMot: 0, sumAju: 0, sumDesemp: 0, sumBonif: 0 })
    }
    const agg = empresaMap.get(e)!
    agg.dias++
    agg.sumMot    += row.Percentual_Atingido_Motorista
    agg.sumAju    += row.Percentual_Atingido_Ajudante
    agg.sumDesemp += row.Percentual_Desempenho
    agg.sumBonif  += row.Valor_Bonificacao
  }

  return Array.from(empresaMap.entries()).map(([empresa, agg]) => ({
    Empresa:                  empresa,
    Dias_Analisados:          agg.dias,
    Perc_Medio_Motorista:     +(agg.sumMot    / agg.dias).toFixed(2),
    Perc_Medio_Ajudante:      +(agg.sumAju    / agg.dias).toFixed(2),
    Perc_Medio_Desempenho:    +(agg.sumDesemp / agg.dias).toFixed(2),
    Total_Bonif_Mes:          +agg.sumBonif.toFixed(2),
  })).sort((a, b) => a.Empresa.localeCompare(b.Empresa))
}

// ─── Resumo Simples (aba 04) ──────────────────────────────────────────────────

function gerarResumoSimples(analiseDiaria: any[], month: number): any[] {
  const empresaMap = new Map<string, { bonifTotal: number; bonifAtingida: number }>()

  for (const row of analiseDiaria) {
    const e = row.Empresa
    if (!empresaMap.has(e)) empresaMap.set(e, { bonifTotal: 0, bonifAtingida: 0 })
    const agg = empresaMap.get(e)!
    agg.bonifTotal    += row.Bonificacao_Dia_Total
    agg.bonifAtingida += row.Valor_Bonificacao
  }

  return Array.from(empresaMap.entries()).map(([empresa, agg]) => ({
    Empresa:              empresa,
    MES:                  month,
    Bonificacao_Total:    +agg.bonifTotal.toFixed(2),
    Bonificacao_Atingida: +agg.bonifAtingida.toFixed(2),
  })).sort((a, b) => a.Empresa.localeCompare(b.Empresa))
}

// ─── Processor principal ──────────────────────────────────────────────────────

async function ccoProcessor(args: PipelineArgs): Promise<ProcessorOutput> {
  // Lê as abas dos arquivos ajustados
  let rowsMot: any[] = []
  let rowsAju: any[] = []

  try {
    const sheetsMot = await args.files.readSheets("fileMotoristas")
    rowsMot = pickSheet(sheetsMot, ABAS_AJUSTADO) ?? []
    if (!rowsMot.length) {
      const all = await args.files.readAll("fileMotoristas")
      rowsMot = all.flat()
    }
  } catch (e: any) {
    throw new Error(`Não foi possível ler o arquivo de Motoristas: ${e.message}`)
  }

  try {
    const sheetsAju = await args.files.readSheets("fileAjudantes")
    rowsAju = pickSheet(sheetsAju, ABAS_AJUSTADO) ?? []
    if (!rowsAju.length) {
      const all = await args.files.readAll("fileAjudantes")
      rowsAju = all.flat()
    }
  } catch (e: any) {
    throw new Error(`Não foi possível ler o arquivo de Ajudantes: ${e.message}`)
  }


  if (!rowsMot.length) throw new Error("Arquivo de Motoristas está vazio ou sem dados reconhecíveis.")
  if (!rowsAju.length) throw new Error("Arquivo de Ajudantes está vazio ou sem dados reconhecíveis.")

  console.log(`[CCO] Motoristas: ${rowsMot.length} registros | Ajudantes: ${rowsAju.length} registros`)

  // ── Carregar e normalizar ─────────────────────────────────────────────────
  const dfMot = carregarAjustado(rowsMot)
  const dfAju = carregarAjustado(rowsAju)

  console.log(`[CCO] Após normalização → Mot: ${dfMot.length} | Aju: ${dfAju.length}`)

  // ── Etapas de cálculo ─────────────────────────────────────────────────────
  const { analiseDiaria, analiseDiariaFormatada, domingoRemovidos } =
    calcularDesempenho(dfMot, dfAju)

  const resumoMensal  = gerarResumoMensal(analiseDiaria)
  const resumoSimples = gerarResumoSimples(analiseDiaria, args.month)

  // ── Totais para summary ───────────────────────────────────────────────────
  const totalEmpresas    = resumoMensal.length
  const totalBonificacao = resumoMensal.reduce((a, r) => a + r.Total_Bonif_Mes, 0)
  const percMedio        = resumoMensal.length > 0
    ? resumoMensal.reduce((a, r) => a + r.Perc_Medio_Desempenho, 0) / resumoMensal.length
    : 0

  console.log(`[CCO] ${totalEmpresas} empresas | R$ ${totalBonificacao.toFixed(2)} | ${percMedio.toFixed(2)}% médio`)

  return {
    data:                    analiseDiaria,   // compatibilidade DataViewer
    analiseDiaria,
    analiseDiariaFormatada,
    resumoMensal,
    resumoSimples,
    domingoRemovidos,
    summary:
      `CCO ${String(args.month).padStart(2, "0")}/${args.year}: ` +
      `${totalEmpresas} empresas · ` +
      `${analiseDiaria.length} dias · ` +
      `R$ ${totalBonificacao.toFixed(2)} em bonificações · ` +
      `desempenho médio ${percMedio.toFixed(2)}%`,
    extraSheets: [
      { name: "01_Analise_Diaria",           data: analiseDiaria          },
      { name: "02_Analise_Diaria_Formatada", data: analiseDiariaFormatada },
      { name: "03_Resumo_Mensal",            data: resumoMensal           },
      { name: "04_Resumo_Simples",           data: resumoSimples          },
    ],
  }
}

