"use server"

import { processAndSave, PipelineArgs, ProcessorOutput, PipelineResponse, getDedupKeys } from "./actions-utils"

// ─── Configurações ────────────────────────────────────────────────────────────
const MAPA_FILIAL_REGIAO: Record<string, string> = {
  "Cambe":        "RK01",
  "Cascavel":     "KP01",
  "Curitiba":     "RK03",
  "Campo Grande": "BV01",
  "Dourados":     "BV02",
}

function removeAcentos(txt: string): string {
  return txt.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toUpperCase()
}

function formatarTempo(valor: any): string {
  if (valor == null || valor === "") return ""
  const num = Number(valor)
  if (!isNaN(num) && num >= 0 && num < 1) {
    const totalMin = Math.round(num * 24 * 60)
    return `${String(Math.floor(totalMin / 60)).padStart(2, "0")}:${String(totalMin % 60).padStart(2, "0")}`
  }
  const str   = String(valor).trim()
  const match = str.match(/^(\d+):(\d{2})(?::\d{2})?$/)
  if (match) return `${match[1].padStart(2, "0")}:${match[2]}`
  return str
}

export function montarNomeAba(day: number, month: number, year: number): string {
  return `${String(day).padStart(2, "0")}.${String(month).padStart(2, "0")}.${year}`
}

export function abaDoMes(nomeAba: string, month: number, year: number): boolean {
  const match = nomeAba.match(/^(\d{2})\.(\d{2})\.(\d{4})$/)
  if (!match) return false
  return parseInt(match[2]) === month && parseInt(match[3]) === year
}

function norm(s: string): string {
  return removeAcentos(s).replace(/\s+/g, " ").trim()
}

function findCol(colsKeys: string[], ...patterns: RegExp[]): string | undefined {
  for (const pat of patterns) {
    const found = colsKeys.find(k => pat.test(norm(k)))
    if (found) return found
  }
  return undefined
}

// ─── Chave de deduplicação ────────────────────────────────────────────────────
function dedupKey(row: any): string {
  const viagem = String(row["VIAGENS"]         ?? "").trim()
  const data   = String(row["DATA DE ENTREGA"] ?? "").trim()
  return `${viagem}|${data}`
}

// ─── Processamento de linhas ──────────────────────────────────────────────────
function processarRows(rows: any[], filialNome: string, dataEntrega: string): any[] {
  if (!rows || rows.length === 0) return []

  const headerCols: string[] = (rows as any).__colNames__ ?? []
  const dataColsSet = new Set<string>(headerCols.filter(c => !c.startsWith("__")))
  for (const row of rows) {
    for (const key of Object.keys(row)) {
      if (!key.startsWith("__")) dataColsSet.add(key)
    }
  }
  const colsKeys = [...dataColsSet]

  const colData       = findCol(colsKeys, /^DATA$/)
  const colMotorista  = findCol(colsKeys, /^MOTORISTA$/)
  const colAjudante1  = findCol(colsKeys, /^AJUDANTE$/)
  const colAjudante2  = findCol(colsKeys, /^AJUDANTE_2$/)
  const colPlaca      = findCol(colsKeys, /^PLACA$/)
  const colPlacaSis   = findCol(colsKeys, /PLACA.?SISTEMA/)
  const colEntregas   = findCol(colsKeys, /^ENTREGAS$/)
  const colPeso       = findCol(colsKeys, /^PESO$/)
  const colTempo      = findCol(colsKeys, /^TEMPO$/)
  const colKm         = findCol(colsKeys, /^KM$/)
  const colViagens    = findCol(colsKeys, /VIAGEN/, /LIQUIDA/, /^ID$/)
  const colObs        = findCol(colsKeys, /OBSERVA/)
  const colChapa      = findCol(colsKeys, /^CHAPA$/)
  const colFrete      = findCol(colsKeys, /^FRETE$/)
  const colDescarga   = findCol(colsKeys, /DESCARGA/)
  const colHospedagem = findCol(colsKeys, /HOSPED/)
  const colDiaria     = findCol(colsKeys, /^DIARIA$/, /^DIÁRIA$/)
  const colExtra      = findCol(colsKeys, /^EXTRA$/)
  const colSaida      = findCol(colsKeys, /^SA[IÍ]DA$/)
  const colModelo     = findCol(colsKeys, /^MODELO$/)
  const colOcp        = findCol(colsKeys, /^OCP$/)
  const colValor      = findCol(colsKeys, /^VALOR$/)
  const colStatus     = findCol(colsKeys, /^STATUS$/)
  const colContrato   = findCol(colsKeys, /^CONTRATO$/)
  const colPerforma   = findCol(colsKeys, /PERFORMAXXI/)
  const colEntDev     = findCol(colsKeys, /ENTREGAS.?DEV/)
  const colValorDev   = findCol(colsKeys, /VALOR.?DEV/)

  console.log(
    `[processarRows] ${filialNome} | `,
    `DATA="${colData}" MOT="${colMotorista}" AJ1="${colAjudante1}" AJ2="${colAjudante2}"`,
    `PLACA="${colPlaca}" VGS="${colViagens}"`
  )

  const resultado: any[] = []

  for (const row of rows) {
    const dataVal = colData ? row[colData] : null
    if (!dataVal) continue
    const dataStr = String(dataVal).toUpperCase()
    if (/TOTAL|GERAL|CARGAS|FROTA/.test(dataStr)) continue
    const motoristaVal = colMotorista ? row[colMotorista] : null
    if (!motoristaVal) continue
    if (String(motoristaVal).toUpperCase() === "MOTORISTA") continue

    const rota = String(row.__rota__ ?? "").trim()
    let placa = colPlaca ? (row[colPlaca] ?? null) : null
    if (!placa && colPlacaSis) placa = row[colPlacaSis] ?? null

    resultado.push({
      "ROTA":            rota,
      "FILIAL":          filialNome,
      "REGIÃO":          MAPA_FILIAL_REGIAO[filialNome] ?? "",
      "DATA DE ENTREGA": dataEntrega,
      "DATA":            dataVal,
      "MOTORISTA":       motoristaVal,
      "AJUDANTE":        colAjudante1   ? (row[colAjudante1]  ?? null) : null,
      "AJUDANTE 2":      colAjudante2   ? (row[colAjudante2]  ?? null) : null,
      "PLACA SISTEMA":   colPlacaSis    ? (row[colPlacaSis]   ?? null) : null,
      "PLACA":           placa,
      "ENTREGAS":        colEntregas    ? (row[colEntregas]   ?? null) : null,
      "PESO":            colPeso        ? (row[colPeso]       ?? null) : null,
      "TEMPO":           colTempo       ? formatarTempo(row[colTempo]) : "",
      "KM":              colKm          ? (row[colKm]         ?? null) : null,
      "VIAGENS":         colViagens     ? (row[colViagens]    ?? null) : null,
      "OBSERVAÇÃO":      colObs         ? (row[colObs]        ?? null) : null,
      "CHAPA":           colChapa       ? (row[colChapa]      ?? null) : null,
      "FRETE":           colFrete       ? (row[colFrete]      ?? null) : null,
      "DESCARGA PALET":  colDescarga    ? (row[colDescarga]   ?? null) : null,
      "HOSPEDAGEM":      colHospedagem  ? (row[colHospedagem] ?? null) : null,
      "DIARIA":          colDiaria      ? (row[colDiaria]     ?? null) : null,
      "EXTRA":           colExtra       ? (row[colExtra]      ?? null) : null,
      "SAÍDA":           colSaida       ? (row[colSaida]      ?? null) : null,
      "MODELO":          colModelo      ? (row[colModelo]     ?? null) : null,
      "OCP":             colOcp         ? (row[colOcp]        ?? null) : null,
      "VALOR":           colValor       ? (row[colValor]      ?? null) : null,
      "STATUS":          colStatus      ? (row[colStatus]     ?? null) : null,
      "CONTRATO":        colContrato    ? (row[colContrato]   ?? null) : null,
      "PERFORMAXXI":     colPerforma    ? (row[colPerforma]   ?? null) : null,
      "ENTREGAS DEV":    colEntDev      ? (row[colEntDev]     ?? null) : null,
      "VALOR DEV":       colValorDev    ? (row[colValorDev]   ?? null) : null,
    })
  }

  console.log(`[processarRows] ${filialNome} → ${resultado.length} registros (${rows.length} linhas)`)
  return resultado
}

// ─── Processor principal ──────────────────────────────────────────────────────
async function consolidacaoEntregasProcessor(args: PipelineArgs): Promise<ProcessorOutput> {
  const { year, month, files, formData } = args
  const day     = parseInt(formData?.get("day") as string ?? "0") || 0
  const abaAlvo = day > 0 ? montarNomeAba(day, month, year) : ""
  if (abaAlvo) formData.set("sheetName", abaAlvo)

  const sheetsData = await files.readAll("files")
  const fileNames: string[] = (formData.getAll("fileNames") as string[]) ?? []
  if (!sheetsData.length) throw new Error("Nenhum arquivo ou aba encontrada.")

  // ── Dedup: lê APENAS metadata do doc principal (1 leitura) ───────────────
  // Não lê items/ — as chaves estão no campo dedupKeys do doc principal.
  // Isso elimina a leitura O(N) que explodia a cota.
  const { keys: existentes } = await getDedupKeys("consolidacao-entregas", year, month)
  console.log(`[consolidacao] Chaves de dedup no banco: ${existentes.size}`)

  const filialData: Record<string, any[]> = {}
  let totalRegistros = 0
  const diasProcessados = new Set<string>()

  for (const [idx, rows] of sheetsData.entries()) {
    const sheetName: string = (rows as any).__sheetName ?? abaAlvo ?? ""
    if (!abaAlvo && sheetName && !abaDoMes(sheetName, month, year)) continue
    if (sheetName) diasProcessados.add(sheetName)

    const fileIdx: number = (rows as any).__fileIndex ?? idx
    const nome = (fileNames[fileIdx] ?? "").toLowerCase()

    let filialNome = "Desconhecida"
    if      (/cambe/i.test(nome))         filialNome = "Cambe"
    else if (/cascavel/i.test(nome))      filialNome = "Cascavel"
    else if (/curitiba/i.test(nome))      filialNome = "Curitiba"
    else if (/campo.?grande/i.test(nome)) filialNome = "Campo Grande"
    else if (/dourados/i.test(nome))      filialNome = "Dourados"

    const dataEntrega = abaAlvo
      ? abaAlvo.replace(/\./g, "/")
      : sheetName
        ? sheetName.replace(/\./g, "/")
        : `${String(month).padStart(2, "0")}/${year}`

    const processados = processarRows(rows, filialNome, dataEntrega)
    if (!filialData[filialNome]) filialData[filialNome] = []
    filialData[filialNome].push(...processados)
    totalRegistros += processados.length
  }

  // Todos os registros extraídos (incluindo CHÃO — o grid mostra tudo)
  const todosRegistros: any[] = []
  for (const rows of Object.values(filialData)) todosRegistros.push(...rows)

  // ── Deduplicação ──────────────────────────────────────────────────────────
  const duplicadas: Array<{ viagens: string; data: string; motorista: string; filial: string }> = []
  const novosRegistros: any[] = []

  for (const row of todosRegistros) {
    const k = dedupKey(row)
    if (k !== "|" && existentes.has(k)) {
      duplicadas.push({
        viagens:   String(row["VIAGENS"]         ?? "—"),
        data:      String(row["DATA DE ENTREGA"] ?? "—"),
        motorista: String(row["MOTORISTA"]       ?? "—"),
        filial:    String(row["FILIAL"]          ?? "—"),
      })
    } else {
      novosRegistros.push(row)
    }
  }

  console.log(
    `[consolidacao] Total extraído: ${todosRegistros.length} | ` +
    `Novos: ${novosRegistros.length} | Duplicados: ${duplicadas.length}`
  )

  // ── ExtraSheet Acumulado = sem CHÃO (para download Excel) ────────────────
  const acumuladoSemChao = novosRegistros.filter(row => {
    const rota = removeAcentos(String(row["ROTA"] ?? "")).trim()
    return rota !== "CHAO"
  })

  // ExtraSheets por filial
  const duplicadasKeys = new Set(duplicadas.map(d => `${d.viagens}|${d.data}`))
  const filialDataFiltrada: Record<string, any[]> = {}
  for (const [filial, rows] of Object.entries(filialData)) {
    filialDataFiltrada[filial] = rows.filter(r => !duplicadasKeys.has(dedupKey(r)))
  }

  const filiaisOk = Object.values(filialDataFiltrada).filter(r => r.length > 0).length
  const diasLabel  = day > 0 ? `dia ${String(day).padStart(2, "0")}` : `${diasProcessados.size} dias`
  const dupInfo    = duplicadas.length > 0 ? ` · ${duplicadas.length} duplicada(s) ignorada(s)` : ""

  return {
    // ✅ data = APENAS os novos registros (nunca reescreve os antigos)
    // O saveToFirebase vai ACRESCENTAR esses itens à subcoleção existente
    data: novosRegistros,
    summary: `Consolidação ${String(month).padStart(2, "0")}/${year} (${diasLabel}): ${filiaisOk} filiais · ${novosRegistros.length} novos · ${existentes.size + novosRegistros.length} total no banco${dupInfo}`,
    duplicadas,
    // ✅ dedupKeys das novas linhas → saveToFirebase merge com as existentes no metadata
    dedupKeys: novosRegistros.map(r => dedupKey(r)).filter(k => k !== "|"),
    extraSheets: [
      ...Object.entries(filialDataFiltrada).map(([filial, rows]) => ({
        name: filial.slice(0, 31),
        data: rows,
      })),
      { name: "Acumulado", data: acumuladoSemChao },
    ],
  }
}

export async function executeConsolidacaoEntregasPipeline(formData: FormData): Promise<PipelineResponse> {
  return await processAndSave("consolidacao-entregas", formData, consolidacaoEntregasProcessor)
}

import { collection, writeBatch, doc, getDocs, query, where } from "firebase/firestore";
import { db } from "@/lib/firebase";
import * as XLSX from 'xlsx';
import { trackRead, trackWrite } from "../../lib/firebaseUsageTracker";

export async function importFaturamentoAction(file: File): Promise<{ success: boolean; message: string; }> {
  try {
    const reader = new FileReader();

    const data = await new Promise<any[]>((resolve, reject) => {
      reader.onload = (e) => {
        try {
          const data = e.target?.result;
          const workbook = XLSX.read(data, { type: "array" });
          const sheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[sheetName];

          const rows: any[][] = XLSX.utils.sheet_to_json(worksheet, { header: 1, defval: null });

          let headerRowIndex = -1;
          for (let i = 0; i < rows.length; i++) {
            if (rows[i] && rows[i].some(cell => cell !== null && String(cell).trim() !== '')) {
              headerRowIndex = i;
              break;
            }
          }

          if (headerRowIndex === -1 || headerRowIndex >= rows.length) {
            return resolve([]);
          }

          const headers = rows[headerRowIndex].map(header => String(header || '').toUpperCase().trim());
          const dataRows = rows.slice(headerRowIndex + 1);

          const json = dataRows
            .filter(row => row && row.some(cell => cell !== null && String(cell).trim() !== ''))
            .map(row => {
              const obj: { [key: string]: any } = {};
              headers.forEach((header, index) => {
                if (header) {
                  obj[header] = row[index];
                }
              });
              return obj;
            });

          resolve(json);

        } catch (error) {
          reject(error);
        }
      };

      reader.onerror = (error) => {
        reject(error);
      };

      reader.readAsArrayBuffer(file);
    });

    const batch = writeBatch(db);
    const faturamentoCollection = collection(db, "docs_faturamento");
    let writeCount = 0;

    for (const item of data) {
      const viagem = item.VIAGEM ? String(item.VIAGEM).trim() : null;

      if (!viagem) {
        console.warn("Skipping row due to missing VIAGEM. Row content:", JSON.stringify(item, null, 2));
        continue;
      }

      const q = query(faturamentoCollection, where("VIAGEM", "==", viagem));
      const querySnapshot = await getDocs(q);
      trackRead(querySnapshot.size); // RASTREAMENTO LEITURA

      const faturamentoData = {
        DM_FILIAL: item.DM_FILIAL ?? null,
        DT_FATURAMENTO: item.DT_FATURAMENTO ?? null,
        DT_RETORNO: item.DT_RETORNO ?? null,
        DT_FECHAMENTO: item.DT_FECHAMENTO ?? null,
        DIAS_ABERTO: item.DIAS_ABERTO ?? null,
        VIAGEM: viagem,
        ENTREGAS: item.ENTREGAS ?? null,
        FATURAMENTO: item.FATURAMENTO ?? null,
        FATURAMENTO_DEV: item.FATURAMENTO_DEV ?? null,
        PESO: item.PESO ?? null,
        PESO_DEV: item.PESO_DEV ?? null,
        MOTIVO_DEV: item.MOTIVO_DEV ?? null
      };

      if (!querySnapshot.empty) {
        const faturamentoDoc = querySnapshot.docs[0];
        batch.update(faturamentoDoc.ref, faturamentoData);
      } else {
        batch.set(doc(faturamentoCollection), faturamentoData);
      }
      writeCount++;
    }

    if (writeCount > 0) {
        trackWrite(writeCount); // RASTREAMENTO ESCRITA
        await batch.commit();
    }

    return { success: true, message: "Importação de faturamento concluída com sucesso!" };
  } catch (error) {
    console.error("Erro ao importar faturamento:", error);
    return { success: false, message: `Erro ao importar faturamento: ${error instanceof Error ? error.message : "Ocorreu um erro desconhecido."}` };
  }
}

"use server"

import { PipelineArgs, PipelineResponse, ProcessorOutput, processAndSave } from "./actions-utils"

// ─── Constantes ───────────────────────────────────────────────────────────────

const SHEET_FATURAMENTO    = "Faturamento"
const PROCESSO_CINTAS      = "ENTREGA DE CINTAS PARA SEPARAÇÃO"
const PROCESSO_LIBERACAO   = "LIBERAÇÃO PARA ROTEIRIZAÇÃO"   // trailing space ignorado via trim

// Limites de horário em minutos desde meia-noite
//   Cintas:    ≤22h=100% | 22–23h=85% | 23–00h=75% | >00h=0%
//   Liberação: ≤20h30=100% | –21h=85% | –22h=75% | >22h=0%
const CINTAS_LIM_100 = hhmm(22, 0)
const CINTAS_LIM_85  = hhmm(23, 0)
const CINTAS_LIM_75  = hhmm(24, 0)   // meia-noite do dia seguinte

const LIB_LIM_100 = hhmm(20, 30)
const LIB_LIM_85  = hhmm(21, 0)
const LIB_LIM_75  = hhmm(22, 0)

function hhmm(h: number, m: number): number { return h * 60 + m }

// ─── Helpers ──────────────────────────────────────────────────────────────────

function cleanCol(col: any): string {
  return String(col).trim().toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[\s.\-/]+/g, "_")
}

function findCol(row: Record<string, any>, opcoes: string[]): string | null {
  const normMap = new Map(Object.keys(row).map(k => [cleanCol(k), k]))
  for (const op of opcoes) {
    const n = cleanCol(op)
    if (normMap.has(n)) return normMap.get(n)!
  }
  for (const op of opcoes) {
    const n = cleanCol(op)
    for (const [k, orig] of normMap) if (k.includes(n)) return orig
  }
  return null
}

/**
 * Converte string de horário ("17:00", "0:30", "23:45:00") para minutos desde meia-noite.
 * Retorna null se não conseguir converter.
 */
function parseTimeToMinutes(value: any): number | null {
  if (value == null) return null

  // Já é número (Excel serial fraction of day)
  if (typeof value === "number") {
    if (value >= 0 && value < 1) return Math.round(value * 24 * 60)
    return null
  }

  const str = String(value).trim()
  if (!str || str === "-") return null

  const match = str.match(/^(\d{1,2}):(\d{2})(?::(\d{2}))?$/)
  if (match) {
    return parseInt(match[1]) * 60 + parseInt(match[2])
  }

  // Tenta parse como Date
  const d = new Date(`1970-01-01T${str}`)
  if (!isNaN(d.getTime())) return d.getHours() * 60 + d.getMinutes()

  return null
}

function parseDate(value: any): Date | null {
  if (!value) return null
  if (value instanceof Date) return isNaN(value.getTime()) ? null : value

  const str = String(value).trim()

  const br = str.match(/^(\d{2})\/(\d{2})\/(\d{4})/)
  if (br) return new Date(+br[3], +br[2] - 1, +br[1])

  const iso = str.match(/^(\d{4})-(\d{2})-(\d{2})/)
  if (iso) return new Date(+iso[1], +iso[2] - 1, +iso[3])

  // Excel serial
  const num = parseFloat(str)
  if (!isNaN(num) && num > 40000) {
    const d = new Date(Math.round((num - 25569) * 86400 * 1000))
    return isNaN(d.getTime()) ? null : d
  }

  const d = new Date(str)
  return isNaN(d.getTime()) ? null : d
}

function formatDateISO(d: Date | null): string {
  if (!d) return ""
  return d.toISOString().slice(0, 10)
}

function minutesToHHMM(min: number): string {
  const h = Math.floor(min / 60)
  const m = min % 60
  return `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`
}

/**
 * Conta dias úteis (seg–sex) em um mês.
 * Equivalente a numpy.busday_count sem feriados customizados.
 */
function contarDiasUteis(ano: number, mes: number): number {
  const fim = new Date(ano, mes, 1)   // primeiro dia do próximo mês
  const ini = new Date(ano, mes - 1, 1)
  let count = 0
  const cur = new Date(ini)
  while (cur < fim) {
    const dow = cur.getDay()
    if (dow !== 0 && dow !== 6) count++
    cur.setDate(cur.getDate() + 1)
  }
  return count
}

function norm(s: any): string {
  if (s == null) return ""
  return String(s)
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
}

function pickSheet(
  sheetsMap: Map<string, any[]>,
  candidates: string[]
): any[] | null {
  for (const candidate of candidates) {
    for (const [sheetName, data] of sheetsMap) {
      if (norm(sheetName) === norm(candidate) || norm(sheetName).includes(norm(candidate))) {
        return data
      }
    }
  }
  return null
}

// ─── Aplicação de percentual por faixa de horário ────────────────────────────

interface PercentResult {
  perc: number       // 0, 0.75, 0.85 ou 1.0
  metaOk: boolean
}

function calcPercCintas(terminoAjMin: number): PercentResult {
  if (terminoAjMin <= CINTAS_LIM_100) return { perc: 1.00, metaOk: true  }
  if (terminoAjMin <= CINTAS_LIM_85)  return { perc: 0.85, metaOk: false }
  if (terminoAjMin <= CINTAS_LIM_75)  return { perc: 0.75, metaOk: false }
  return                                     { perc: 0.00, metaOk: false }
}

function calcPercLib(terminoAjMin: number): PercentResult {
  if (terminoAjMin <= LIB_LIM_100) return { perc: 1.00, metaOk: true  }
  if (terminoAjMin <= LIB_LIM_85)  return { perc: 0.85, metaOk: false }
  if (terminoAjMin <= LIB_LIM_75)  return { perc: 0.75, metaOk: false }
  return                                   { perc: 0.00, metaOk: false }
}

// ─── Processor principal ──────────────────────────────────────────────────────

async function faturistaProcessor(args: PipelineArgs): Promise<ProcessorOutput> {
  // Parâmetros extras do FormData
  const metaCintas    = parseFloat(args.formData?.get("metaCintas")    as string ?? "200") || 200
  const metaLiberacao = parseFloat(args.formData?.get("metaLiberacao") as string ?? "200") || 200
  const empresasRaw   = String(args.formData?.get("empresas") ?? "RK01,BV01")
  const empresasFiltro = empresasRaw.split(",").map(e => e.trim().toUpperCase()).filter(Boolean)

  // ── Leitura da aba Faturamento ────────────────────────────────────────────
  let rows: any[] = []
  try {
    const sheets = await args.files.readSheets("fileTempos")
    rows = pickSheet(sheets, [SHEET_FATURAMENTO]) ?? []
  } catch {
    // fallback: primeira aba
    const all = await args.files.readAll("fileTempos")
    rows = all.flat()
  }

  if (!rows.length) throw new Error("Arquivo vazio ou aba 'Faturamento' não encontrada.")
  const totalRegistros = rows.length
  console.log(`[Faturista] ${totalRegistros} registros carregados`)

  // ── Detecta colunas ───────────────────────────────────────────────────────
  const firstRow = rows[0]
  const COL_DATA      = findCol(firstRow, ["DATA", "Data", "DT"])
  const COL_EMPRESA   = findCol(firstRow, ["EMPRESA", "Empresa", "empresa"])
  const COL_CIDADE    = findCol(firstRow, ["CIDADE", "Cidade", "cidade"])
  const COL_PROCESSOS = findCol(firstRow, ["PROCESSOS", "Processos", "processo", "PROCESSO"])
  const COL_INICIO    = findCol(firstRow, ["INICIO", "Início", "inicio", "INÍCIO"])
  const COL_TERMINO   = findCol(firstRow, ["TERMINO", "Término", "termino", "TÉRMINO"])
  const COL_PEDIDOS   = findCol(firstRow, ["PEDIDOS", "Pedidos", "pedidos"])

  const missing = Object.entries({ DATA: COL_DATA, EMPRESA: COL_EMPRESA, PROCESSOS: COL_PROCESSOS, INICIO: COL_INICIO, TERMINO: COL_TERMINO })
    .filter(([, v]) => v == null).map(([k]) => k)
  if (missing.length) throw new Error(`Colunas não encontradas: ${missing.join(", ")}`)

  // ── Dias úteis e metas diárias ────────────────────────────────────────────
  const diasUteis    = contarDiasUteis(args.year, args.month)
  if (diasUteis === 0) throw new Error("Nenhum dia útil encontrado no período.")
  const metaDiaCintas    = metaCintas    / diasUteis
  const metaDiaLiberacao = metaLiberacao / diasUteis

  console.log(`[Faturista] ${diasUteis} dias úteis | Meta/dia: Cintas R$ ${metaDiaCintas.toFixed(2)} | Lib R$ ${metaDiaLiberacao.toFixed(2)}`)

  // ── Normaliza e filtra ────────────────────────────────────────────────────
  let viradas          = 0
  let registrosFiltrados = 0

  const dadosCintas:    any[] = []
  const dadosLiberacao: any[] = []

  for (const row of rows) {
    // Filtro data
    const data = parseDate(row[COL_DATA!])
    if (!data) continue
    if (data.getFullYear() !== args.year || data.getMonth() + 1 !== args.month) continue

    // Filtro empresa
    const empresa = String(row[COL_EMPRESA!] ?? "").trim().toUpperCase()
    if (empresasFiltro.length && !empresasFiltro.includes(empresa)) continue

    // Horários
    const inicioMin  = parseTimeToMinutes(row[COL_INICIO!])
    const terminoMin = parseTimeToMinutes(row[COL_TERMINO!])
    if (inicioMin == null || terminoMin == null) continue

    registrosFiltrados++

    // Ajuste de virada de dia
    let terminoAjMin = terminoMin
    if (terminoMin < inicioMin) {
      terminoAjMin = terminoMin + 24 * 60   // adiciona 24h
      viradas++
    }

    const processo = String(row[COL_PROCESSOS!] ?? "").trim().toUpperCase()
    const cidade   = COL_CIDADE  ? String(row[COL_CIDADE]  ?? "").trim() : ""
    const pedidos  = COL_PEDIDOS ? row[COL_PEDIDOS] : null

    const baseRow = {
      DATA:              formatDateISO(data),
      EMPRESA:           empresa,
      CIDADE:            cidade,
      PROCESSOS:         row[COL_PROCESSOS!],
      INICIO:            minutesToHHMM(inicioMin),
      TERMINO:           minutesToHHMM(terminoMin),
      PEDIDOS:           pedidos,
      TERMINO_AJUSTADO:  minutesToHHMM(terminoAjMin),
    }

    // Processo Cintas
    if (processo.includes("CINTAS")) {
      const { perc, metaOk } = calcPercCintas(terminoAjMin)
      dadosCintas.push({
        ...baseRow,
        Perc_Meta_Cintas:  perc,
        Meta_OK_Cintas:    metaOk,
        Valor_Cintas_Dia:  +(perc * metaDiaCintas).toFixed(2),
      })
    }

    // Processo Liberação
    if (processo.includes("LIBERAÇÃO") || processo.includes("LIBERACAO") || processo.includes("ROTEIRI")) {
      const { perc, metaOk } = calcPercLib(terminoAjMin)
      dadosLiberacao.push({
        ...baseRow,
        Perc_Meta_Liberacao:  perc,
        Meta_OK_Liberacao:    metaOk,
        Valor_Liberacao_Dia:  +(perc * metaDiaLiberacao).toFixed(2),
      })
    }
  }

  // ── Totais ────────────────────────────────────────────────────────────────
  const totalCintas    = dadosCintas.reduce((a, r) => a + r.Valor_Cintas_Dia, 0)
  const totalLiberacao = dadosLiberacao.reduce((a, r) => a + r.Valor_Liberacao_Dia, 0)
  const totalGeral     = totalCintas + totalLiberacao

  console.log(`[Faturista] Cintas: ${dadosCintas.length} reg · R$ ${totalCintas.toFixed(2)}`)
  console.log(`[Faturista] Liberação: ${dadosLiberacao.length} reg · R$ ${totalLiberacao.toFixed(2)}`)
  console.log(`[Faturista] ${viradas} viradas de dia`)

  // ── Resumo mensal por empresa ─────────────────────────────────────────────
  const empresasUnicas = new Set([
    ...dadosCintas.map(r => r.EMPRESA),
    ...dadosLiberacao.map(r => r.EMPRESA),
  ])

  const resumoMensal = Array.from(empresasUnicas).sort().map(emp => {
    const bonifCintas    = dadosCintas.filter(r => r.EMPRESA === emp).reduce((a, r) => a + r.Valor_Cintas_Dia, 0)
    const bonifLiberacao = dadosLiberacao.filter(r => r.EMPRESA === emp).reduce((a, r) => a + r.Valor_Liberacao_Dia, 0)
    return {
      empresa:              emp,
      bonificacaoCintas:    +bonifCintas.toFixed(2),
      bonificacaoLiberacao: +bonifLiberacao.toFixed(2),
      bonificacaoTotal:     +(bonifCintas + bonifLiberacao).toFixed(2),
    }
  })

  return {
    data:                dadosCintas,         // compatibilidade DataViewer
    dadosCintas,
    dadosLiberacao,
    resumoMensal,
    totalRegistros,
    registrosFiltrados,
    viradas,
    diasUteis,
    totalCintas:    +totalCintas.toFixed(2),
    totalLiberacao: +totalLiberacao.toFixed(2),
    summary:
      `Faturista ${String(args.month).padStart(2, "0")}/${args.year}: ` +
      `Cintas R$ ${totalCintas.toFixed(2)} · ` +
      `Liberação R$ ${totalLiberacao.toFixed(2)} · ` +
      `Total R$ ${totalGeral.toFixed(2)} · ` +
      `${viradas} viradas de dia`,
    extraSheets: [
      { name: "Prazo_Cintas",    data: dadosCintas    },
      { name: "Prazo_Liberacao", data: dadosLiberacao },
      { name: "Resumo_Mensal",   data: resumoMensal   },
    ],
  }
}

