import { collection, writeBatch, doc, getDocs, query, where } from "firebase/firestore";
import { db } from "@/lib/firebase";
import * as XLSX from 'xlsx';

export async function importMotivosDevAction(file: File): Promise<{ success: boolean; message: string; }> {
  try {
    const reader = new FileReader();

    const data = await new Promise<any[]>((resolve, reject) => {
      reader.onload = (e) => {
        try {
          const data = e.target?.result;
          const workbook = XLSX.read(data, { type: "array" });
          const sheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[sheetName];
          const json = XLSX.utils.sheet_to_json(worksheet);
          resolve(json);
        } catch (error) {
          reject(error);
        }
      };

      reader.onerror = (error) => {
        reject(error);
      };

      reader.readAsArrayBuffer(file);
    });

    const batch = writeBatch(db);
    const motivosCollection = collection(db, "motivos_devolucao");

    for (const item of data) {
      const motivoDev = item.MOTIVO_DEV?.toString().trim();
      if (!motivoDev) {
        console.warn("Skipping row due to missing MOTIVO_DEV:", item);
        continue; // Pula a linha se o motivo estiver faltando
      }

      const q = query(motivosCollection, where("MOTIVO_DEV", "==", motivoDev));
      const querySnapshot = await getDocs(q);

      const motivoData = {
        MOTIVO_DEV: motivoDev,
        CONSIDERA: item.CONSIDERA ?? null
      };

      if (!querySnapshot.empty) {
        // Atualiza o motivo existente
        const motivoDoc = querySnapshot.docs[0];
        batch.update(motivoDoc.ref, motivoData);
      } else {
        // Adiciona um novo motivo
        batch.set(doc(motivosCollection), motivoData);
      }
    }

    await batch.commit();

    return { success: true, message: "Importação de motivos de devolução concluída com sucesso!" };
  } catch (error) {
    console.error("Erro ao importar motivos de devolução:", error);
    return { success: false, message: `Erro ao importar motivos de devolução: ${error instanceof Error ? error.message : "Ocorreu um erro desconhecido."}` };
  }
}

"use server"

import { PipelineArgs, PipelineResponse, ProcessorOutput, processAndSave } from "./actions-utils"

// ─── Constantes ───────────────────────────────────────────────────────────────
const VALOR_PERFORMANCE_MOTORISTA = 8.00
const VALOR_PERFORMANCE_AJUDANTE  = 7.20
const CRITERIOS_PERFORMANCE       = 4

const PERCENTUAL_MINIMO_RAIO  = 70.0
const PERCENTUAL_MINIMO_SLA   = 80.0
const PERCENTUAL_MINIMO_TEMPO = 100.0
const PERCENTUAL_MINIMO_SEQ   = 0.0

// ─── Helpers ──────────────────────────────────────────────────────────────────

function normalize(text: any): string {
  if (!text) return ""
  return String(text)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9_\s]/g, " ")
    .replace(/\s+/g, "_")
    .trim()
}

function findCol(candidates: string[], columns: string[]): string | null {
  const normMap: Record<string, string> = {}
  for (const col of columns) normMap[normalize(col)] = col

  for (const cand of candidates) {
    const nc = normalize(cand)
    if (normMap[nc]) return normMap[nc]
    const partial = Object.keys(normMap).find(k => k.startsWith(nc))
    if (partial) return normMap[partial]
  }
  return null
}

function toFloat(x: any): number {
  if (x == null || x === "") return NaN
  const s = String(x).trim().replace(/[^0-9.,]/g, "")
  if (!s) return NaN
  if (s.includes(".") && s.includes(",")) {
    return parseFloat(s.lastIndexOf(",") > s.lastIndexOf(".")
      ? s.replace(/\./g, "").replace(",", ".")
      : s.replace(/,/g, ""))
  }
  return parseFloat(s.replace(",", "."))
}

function parseDate(value: any): string | null {
  if (!value) return null
  const str = String(value).trim()
  const br = str.match(/^(\d{2})\/(\d{2})\/(\d{4})/)
  if (br) return `${br[3]}-${br[2]}-${br[1]}`
  const iso = str.match(/^(\d{4})-(\d{2})-(\d{2})/)
  if (iso) return str.slice(0, 10)
  // Excel serial
  const num = Number(str)
  if (!isNaN(num) && num > 40000) {
    const d = new Date((num - 25569) * 86400 * 1000)
    return d.toISOString().slice(0, 10)
  }
  return null
}

function calcularTempoAtendimento(inicio: any, fim: any): number {
  if (!inicio || !fim) return NaN
  const i = new Date(String(inicio)).getTime()
  const f = new Date(String(fim)).getTime()
  if (isNaN(i) || isNaN(f)) return NaN
  return (f - i) / 60000
}

function normalizarNome(nome: any): string {
  if (!nome) return ""
  return String(nome)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s]/g, "")
    .replace(/\s+/g, " ")
    .trim()
}

// ─── Etapa 1: Processar rotas ─────────────────────────────────────────────────

function processarRotas(rows: any[]): {
  baseOriginal: any[]
  baseDados: any[]
  resumo: any[]
} {
  const cols = Object.keys(rows[0] ?? {})

  const colStatus  = findCol(["status_rota", "status_da_rota", "status"], cols)
  const colData    = findCol(["data_rota", "data_da_rota", "data"], cols)
  const colEmpresa = findCol(["empresa", "nome_deposito", "deposito"], cols)
  const colPeso    = findCol(["peso_pedido", "peso_do_pedido", "peso"], cols)
  const colOcorr   = findCol(["descricao_ocorrencia", "desc_ocorrencia", "ocorrencia"], cols)

  const processed = rows.map(row => {
    const peso = toFloat(row[colPeso ?? ""])
    const temOcorr = colOcorr
      ? String(row[colOcorr] ?? "").trim() !== "" && String(row[colOcorr] ?? "").toLowerCase() !== "nan"
      : false
    return {
      ...row,
      _data_key: parseDate(row[colData ?? ""]),
      _empresa: String(row[colEmpresa ?? ""] ?? "").trim(),
      _status: String(row[colStatus ?? ""] ?? "").trim().toLowerCase(),
      _peso_total: isNaN(peso) ? 0 : peso,
      _peso_devolvido: temOcorr ? (isNaN(peso) ? 0 : peso) : 0,
      _peso_entregue: temOcorr ? 0 : (isNaN(peso) ? 0 : peso),
    }
  })

  const baseOriginal = rows
  const baseDados = processed.filter(r => r._status !== "standby")

  // Resumo por empresa + data
  const grupos: Record<string, any> = {}
  for (const row of baseDados) {
    const key = `${row._empresa}||${row._data_key}`
    if (!grupos[key]) {
      grupos[key] = {
        nome_deposito: row._empresa,
        data_rota: row._data_key,
        peso_total: 0, peso_entregue: 0, peso_devolvido: 0, qtde_rotas: 0
      }
    }
    grupos[key].peso_total     += row._peso_total
    grupos[key].peso_entregue  += row._peso_entregue
    grupos[key].peso_devolvido += row._peso_devolvido
    grupos[key].qtde_rotas++
  }

  const resumo = Object.values(grupos).map((g: any) => ({
    ...g,
    perc_devolvido: g.peso_total > 0 ? +(g.peso_devolvido / g.peso_total * 100).toFixed(2) : 0
  }))

  return { baseOriginal, baseDados, resumo }
}

// ─── Padronizar nomes com cadastro de funcionários ────────────────────────────

function padronizarNome(nome: any, funcionarios: any[]): { nomePadronizado: string; empresa: string } {
  const n = normalizarNome(nome)
  if (!n || !funcionarios.length) return { nomePadronizado: String(nome ?? ""), empresa: "N/A" }

  const colNome    = findCol(["Nome", "nome"], Object.keys(funcionarios[0]))
  const colEmpresa = findCol(["EMPRESA", "empresa"], Object.keys(funcionarios[0]))

  if (!colNome || !colEmpresa) return { nomePadronizado: String(nome ?? ""), empresa: "N/A" }

  const exato = funcionarios.find(f => normalizarNome(f[colNome]) === n)
  if (exato) return { nomePadronizado: String(exato[colNome]), empresa: String(exato[colEmpresa]) }

  const partes = n.split(" ").filter(Boolean)
  const contem = funcionarios.find(f => {
    const fn = normalizarNome(f[colNome])
    return partes.every(p => fn.includes(p))
  })
  if (contem) return { nomePadronizado: String(contem[colNome]), empresa: String(contem[colEmpresa]) }

  return { nomePadronizado: String(nome ?? ""), empresa: "N/A" }
}

// ─── Etapa 2/3: Análise de performance (motorista ou ajudante) ────────────────

function analisarPerformance(
  baseDados: any[],
  funcionarios: any[],
  colNomeColaborador: string,
  valorPerformance: number,
  tipo: "Motorista" | "Ajudante"
): { detalhe: any[]; consolidado: any[] } {

  const cols = Object.keys(baseDados[0] ?? {})

  const colDist   = findCol(["distancia_cliente_metros", "distancia_metros", "distancia"], cols)
  const colSLA    = findCol(["sla_janela_atendimento", "sla"], cols)
  const colCheg   = findCol(["chegada_cliente_realizado", "chegada_realizado", "chegada"], cols)
  const colFim    = findCol(["fim_atendimento_cliente_realizado", "fim_atendimento_realizado", "fim_atendimento"], cols)
  const colSeqP   = findCol(["sequencia_entrega_planejado", "seq_planejado"], cols)
  const colSeqR   = findCol(["sequencia_entrega_realizado", "seq_realizado"], cols)
  const colPeso   = findCol(["peso_pedido", "peso"], cols)
  const colOcorr  = findCol(["descricao_ocorrencia", "ocorrencia"], cols)
  const colData   = findCol(["data_rota", "data"], cols)
  const colEmpresa = findCol(["nome_deposito", "empresa", "deposito"], cols)
  const colCodCli = findCol(["codigo_cliente", "cod_cliente", "cliente"], cols)

  // Filtra registros válidos com colaborador e data
  const validos = baseDados.filter(row => {
    const nome = String(row[colNomeColaborador] ?? "").trim()
    const data = row[colData ?? ""]
    return nome && nome !== "N.R." && data
  })

  if (!validos.length) return { detalhe: [], consolidado: [] }

  // Processa cada pedido
  const pedidos = validos.map(row => {
    const nome = String(row[colNomeColaborador] ?? "").trim()
    const { nomePadronizado, empresa } = padronizarNome(nome, funcionarios)
    const data = parseDate(row[colData ?? ""])
    const codCli = colCodCli ? String(row[colCodCli] ?? row["_idx"] ?? "") : ""
    const dist = colDist ? toFloat(row[colDist]) : NaN
    const peso = colPeso ? (toFloat(row[colPeso]) || 0) : 0
    const temOcorr = colOcorr
      ? String(row[colOcorr] ?? "").trim() !== "" && String(row[colOcorr] ?? "").toLowerCase() !== "nan"
      : false
    const sla = colSLA ? /sim|ok/i.test(String(row[colSLA] ?? "")) : false
    const tempo = (colCheg && colFim) ? calcularTempoAtendimento(row[colCheg], row[colFim]) : NaN
    const seqP = colSeqP ? Number(row[colSeqP]) : NaN
    const seqR = colSeqR ? Number(row[colSeqR]) : NaN

    return {
      colaborador: nomePadronizado,
      empresa,
      data,
      codCli,
      raio_ok: !isNaN(dist) ? dist <= 100 : false,
      sla_ok: sla,
      tempo_ok: !isNaN(tempo) ? tempo >= 1.0 : false,
      seq_ok: !isNaN(seqP) && !isNaN(seqR) ? seqP === seqR : false,
      peso,
      peso_devolvido: temOcorr ? peso : 0,
    }
  })

  // Agrupa por colaborador + data + cliente (deduplicação de pedido)
  const porPedido: Record<string, any> = {}
  for (const p of pedidos) {
    const key = `${p.colaborador}||${p.empresa}||${p.data}||${p.codCli}`
    if (!porPedido[key]) {
      porPedido[key] = { ...p, _count: 0 }
    } else {
      // max: se qualquer linha do pedido passou no critério, conta como OK
      porPedido[key].raio_ok  = porPedido[key].raio_ok  || p.raio_ok
      porPedido[key].sla_ok   = porPedido[key].sla_ok   || p.sla_ok
      porPedido[key].tempo_ok = porPedido[key].tempo_ok || p.tempo_ok
      porPedido[key].seq_ok   = porPedido[key].seq_ok   || p.seq_ok
      porPedido[key].peso          += p.peso
      porPedido[key].peso_devolvido += p.peso_devolvido
    }
    porPedido[key]._count++
  }

  // Agrupa por colaborador + data (diário)
  const porDia: Record<string, any> = {}
  for (const p of Object.values(porPedido)) {
    const key = `${p.colaborador}||${p.empresa}||${p.data}`
    if (!porDia[key]) {
      porDia[key] = {
        colaborador: p.colaborador, empresa: p.empresa, data: p.data,
        total: 0, raio: 0, sla: 0, tempo: 0, seq: 0,
        peso: 0, peso_dev: 0,
      }
    }
    const d = porDia[key]
    d.total++
    if (p.raio_ok)  d.raio++
    if (p.sla_ok)   d.sla++
    if (p.tempo_ok) d.tempo++
    if (p.seq_ok)   d.seq++
    d.peso     += p.peso
    d.peso_dev += p.peso_devolvido
  }

  const valorPorCriterio = valorPerformance / CRITERIOS_PERFORMANCE

  // Monta detalhe diário
  const detalhe = Object.values(porDia).map((d: any) => {
    const pRaio  = d.total > 0 ? +(d.raio  / d.total * 100).toFixed(2) : 0
    const pSLA   = d.total > 0 ? +(d.sla   / d.total * 100).toFixed(2) : 0
    const pTempo = d.total > 0 ? +(d.tempo / d.total * 100).toFixed(2) : 0
    const pSeq   = d.total > 0 ? +(d.seq   / d.total * 100).toFixed(2) : 0

    const cRaio  = pRaio  >= PERCENTUAL_MINIMO_RAIO
    const cSLA   = pSLA   >= PERCENTUAL_MINIMO_SLA
    const cTempo = pTempo >= PERCENTUAL_MINIMO_TEMPO
    const cSeq   = pSeq   >= PERCENTUAL_MINIMO_SEQ

    const cumpridos = (cRaio ? 1 : 0) + (cSLA ? 1 : 0) + (cTempo ? 1 : 0) + (cSeq ? 1 : 0)
    const bonif = +(cumpridos * valorPorCriterio).toFixed(2)
    const pBonif = +(cumpridos / CRITERIOS_PERFORMANCE * 100).toFixed(2)

    return {
      "Empresa": d.empresa,
      [tipo]: d.colaborador,
      "Dia": d.data,
      "Total de Pedidos": d.total,
      "Peso Pedido Dia (Kg)": +d.peso.toFixed(2),
      "Peso Devolvido Dia (Kg)": +d.peso_dev.toFixed(2),
      "% Devolvido Dia": d.peso > 0 ? +(d.peso_dev / d.peso * 100).toFixed(2) : 0,
      "% Raio": pRaio,   [`✓ Raio ≥${PERCENTUAL_MINIMO_RAIO}%`]:  cRaio,
      "% SLA": pSLA,     [`✓ SLA ≥${PERCENTUAL_MINIMO_SLA}%`]:    cSLA,
      "% Tempo": pTempo, [`✓ Tempo ≥${PERCENTUAL_MINIMO_TEMPO}%`]: cTempo,
      "% Sequência": pSeq, [`✓ Sequência ≥${PERCENTUAL_MINIMO_SEQ}%`]: cSeq,
      [`Critérios Cumpridos (de ${CRITERIOS_PERFORMANCE})`]: cumpridos,
      "Critérios Falhados": CRITERIOS_PERFORMANCE - cumpridos,
      "Dia Bonificação Máxima (4/4)": cumpridos === CRITERIOS_PERFORMANCE,
      "% Bonificação": pBonif,
      [`Bonificação ${tipo} (R$)`]: bonif,
    }
  })

  // Consolidado por colaborador
  const porColab: Record<string, any> = {}
  for (const row of detalhe) {
    const nome = row[tipo]
    if (!porColab[nome]) {
      porColab[nome] = {
        [tipo]: nome,
        Empresa: row["Empresa"],
        dias: 0, diasMax: 0, bonif: 0, cumpridos: 0,
        fRaio: 0, fSLA: 0, fTempo: 0, fSeq: 0,
      }
    }
    const c = porColab[nome]
    c.dias++
    if (row["Dia Bonificação Máxima (4/4)"]) c.diasMax++
    c.bonif     += row[`Bonificação ${tipo} (R$)`]
    c.cumpridos += row[`Critérios Cumpridos (de ${CRITERIOS_PERFORMANCE})`]
    if (!row[`✓ Raio ≥${PERCENTUAL_MINIMO_RAIO}%`])   c.fRaio++
    if (!row[`✓ SLA ≥${PERCENTUAL_MINIMO_SLA}%`])     c.fSLA++
    if (!row[`✓ Tempo ≥${PERCENTUAL_MINIMO_TEMPO}%`]) c.fTempo++
    if (!row[`✓ Sequência ≥${PERCENTUAL_MINIMO_SEQ}%`]) c.fSeq++
  }

  const consolidado = Object.values(porColab).map((c: any) => {
    const possiveis = c.dias * CRITERIOS_PERFORMANCE
    return {
      "Empresa": c.Empresa,
      [tipo]: c[tipo],
      "Dias com Atividade": c.dias,
      "Dias Bonif. Máxima (4/4)": c.diasMax,
      "Percentual de Desempenho (%)": possiveis > 0 ? +(c.cumpridos / possiveis * 100).toFixed(2) : 0,
      "Total Bonificação (R$)": +c.bonif.toFixed(2),
      "Total Critérios Cumpridos": c.cumpridos,
      "Falhas Raio": c.fRaio,
      "Falhas SLA": c.fSLA,
      "Falhas Tempo": c.fTempo,
      "Falhas Sequência": c.fSeq,
    }
  }).sort((a, b) => b["Percentual de Desempenho (%)"] - a["Percentual de Desempenho (%)"])

  return { detalhe, consolidado }
}

// ─── Processor principal ──────────────────────────────────────────────────────

async function performaxxiProcessor(args: PipelineArgs): Promise<ProcessorOutput> {
  const sheetsData  = await args.files.readAll("files")
  const fileNames: string[] = (args.formData?.getAll("fileNames") as string[]) ?? []

  // Separa relatório de rotas vs cadastro de funcionários pelo nome
  let rotaRows:  any[] = []
  let funcRows:  any[] = []

  sheetsData.forEach((sheet, idx) => {
    const nome = (fileNames[idx] ?? "").toLowerCase()
    if (nome.includes("funcionari")) funcRows = [...funcRows, ...sheet]
    else rotaRows = [...rotaRows, ...sheet]
  })

  if (!rotaRows.length) throw new Error("Nenhum relatório de rotas encontrado.")

  // Normaliza colunas snake_case
  const normalize_cols = (rows: any[]) =>
    rows.map(row => {
      const out: any = {}
      for (const [k, v] of Object.entries(row)) out[normalize(k)] = v
      return out
    })

  const rotas = normalize_cols(rotaRows)
  const funcs = funcRows.length ? funcRows : []

  // ── Etapa 1 ──────────────────────────────────────────────────────────────
  const { baseOriginal, baseDados, resumo } = processarRotas(rotas)

  const cols = Object.keys(baseDados[0] ?? {})

  // ── Etapa 2: Motoristas ───────────────────────────────────────────────────
  const colMot = findCol(["nome_motorista", "motorista"], cols) ?? "nome_motorista"
  const { detalhe: detMot, consolidado: consMot } =
    analisarPerformance(baseDados, funcs, colMot, VALOR_PERFORMANCE_MOTORISTA, "Motorista")

  // ── Etapa 3: Ajudantes ────────────────────────────────────────────────────
  const colAjud = findCol(
    ["nome_primeiro_ajudante", "nome_segundo_ajudante", "ajudante"], cols
  )
  const { detalhe: detAjud, consolidado: consAjud } = colAjud
    ? analisarPerformance(baseDados, funcs, colAjud, VALOR_PERFORMANCE_AJUDANTE, "Ajudante")
    : { detalhe: [], consolidado: [] }

  const totalMot  = consMot.length
  const totalAjud = consAjud.length
  const bonifMot  = consMot.reduce((s, m) => s + m["Total Bonificação (R$)"], 0)
  const bonifAjud = consAjud.reduce((s, m) => s + m["Total Bonificação (R$)"], 0)

  return {
    data: consMot,
    summary: `Performaxxi ${args.month}/${args.year}: ${totalMot} motoristas · ${totalAjud} ajudantes · R$ ${(bonifMot + bonifAjud).toFixed(2)} em bonificações`,
    extraSheets: [
      { name: "01_Base_Original",         data: baseOriginal },
      { name: "02_Base_Dados",            data: baseDados    },
      { name: "03_Resumo_Rotas",          data: resumo       },
      { name: "04_Detalhe_Motorista",     data: detMot       },
      { name: "05_Consolidado_Motorista", data: consMot      },
      { name: "06_Detalhe_Ajudante",      data: detAjud      },
      { name: "07_Consolidado_Ajudante",  data: consAjud     },
    ],
  }
}

export async function executePerformaxxiPipeline(formData: FormData): Promise<PipelineResponse> {
  return processAndSave("performaxxi", formData, performaxxiProcessor)
}

"use server"

import { processAndSave, PipelineArgs, ProcessorOutput, PipelineResponse } from "./actions-utils"

// ─── Constantes ───────────────────────────────────────────────────────────────
const MOT_BONIFICACAO_DIARIA_TOTAL = 16.00
const MOT_PERCENTUAL_PONTO         = 0.20
const MOT_VALOR_PONTO              = +(MOT_BONIFICACAO_DIARIA_TOTAL * MOT_PERCENTUAL_PONTO).toFixed(2) // 3.20
const MOT_VALOR_MARCACOES          = +(MOT_VALOR_PONTO / 2).toFixed(2) // 1.60
const MOT_VALOR_CRITERIOS          = +(MOT_VALOR_PONTO / 2).toFixed(2) // 1.60

const AJU_BONIFICACAO_DIARIA_TOTAL = 12.00
const AJU_PERCENTUAL_PONTO         = 0.40
const AJU_VALOR_PONTO              = +(AJU_BONIFICACAO_DIARIA_TOTAL * AJU_PERCENTUAL_PONTO).toFixed(2) // 4.80
const AJU_VALOR_MARCACOES          = +(AJU_VALOR_PONTO / 2).toFixed(2) // 2.40
const AJU_VALOR_CRITERIOS          = +(AJU_VALOR_PONTO / 2).toFixed(2) // 2.40

const CARGA_HORARIA_PADRAO_MIN = 440  // 07:20
const INTERJORNADA_MIN_MIN     = 11 * 60 // 11h

const SITUACOES_CONTAM_PRESENCA = [
  "ATESTADO","AUXILIO DOENCA","AUXÍLIO DOENÇA","FERIAS","FÉRIAS",
  "LICENCA MATERNIDADE","LICENÇA MATERNIDADE","LICENCA PATERNIDADE",
  "LICENÇA PATERNIDADE","FALTA ABONADA","ABONADA",
]

// ─── Helpers de tempo ─────────────────────────────────────────────────────────

function horarioParaMinutos(horario: any): number | null {
  if (!horario || String(horario).trim() === "") return null
  try {
    const clean = String(horario).replace("*", "").trim()
    const [h, m] = clean.split(":").map(Number)
    return h * 60 + m
  } catch { return null }
}

function minutosParaHorario(min: number | null): string {
  if (min == null) return ""
  return `${String(Math.floor(min / 60)).padStart(2,"0")}:${String(min % 60).padStart(2,"0")}`
}

function calcularTempoTrabalhado(
  entrada: string, saidaAlmoco: string, retornoAlmoco: string, saida: string
): { trab: number | null; alm: number | null } {
  const e  = horarioParaMinutos(entrada)
  const sa = horarioParaMinutos(saidaAlmoco)
  const ra = horarioParaMinutos(retornoAlmoco)
  const s  = horarioParaMinutos(saida)

  if (e == null || s == null) return { trab: null, alm: null }

  let total = s - e
  if (total < 0) total += 24 * 60

  let alm = 0
  if (sa != null && ra != null) {
    alm = ra - sa
    if (alm < 0) alm += 24 * 60
  }

  return { trab: total - alm, alm }
}

// ─── Etapa 1: Parser de CSV de ponto ─────────────────────────────────────────

function parsearCSVPonto(rows: any[], mes: number): any[] {
  // Os dados já chegam parseados pelo pipeline-utils
  // Tentamos identificar a estrutura do CSV de ponto
  const resultado: any[] = []

  let idAtual: string | null = null
  let nomeAtual: string | null = null
  let horarioPrevisto: string | null = null

  for (const row of rows) {
    const valores = Object.values(row).map(v => String(v ?? "").trim())
    const col0 = valores[0] ?? ""
    const col1 = valores[1] ?? ""
    const col2 = valores[2] ?? ""

    // Ignora cabeçalhos
    if (/PONTO_ORIGINAL|APURAÇÃO|TRANSMENDES|PAG:|PERÍODO/i.test(col0)) continue
    if (/Total Colaborador|Total Geral/i.test(col1)) continue
    if (!col0 && !col1) continue

    // Linha de identificação do colaborador (ID numérico + nome)
    if (/^\d{2,}$/.test(col0) && !col0.includes("/") && col1) {
      idAtual = col0
      nomeAtual = col1
      horarioPrevisto = null
      continue
    }

    // Linha de escala/horário previsto (col0 vazia, tem horários)
    if (idAtual && !col0 && valores.some(v => /^\d{2}:\d{2}/.test(v))) {
      const horarios = valores.filter(v => /^\d{2}:\d{2}/.test(v))
      if (horarios.length >= 2) horarioPrevisto = horarios.join(" ")
      continue
    }

    // Linha de data + marcações
    if (/\d{2}\/\d{2}/.test(col0) && col0.length >= 5 && col0.length <= 10) {
      const data = col0.length === 10 ? col0 : `${col0}/${new Date().getFullYear()}`

      // Extrai marcações da col2 (separadas por espaço)
      const marcacoes = col2.split(/\s+/).filter(v => /^\d{2}:\d{2}/.test(v))
      const entrada        = marcacoes[0] ?? ""
      const saidaAlmoco   = marcacoes[1] ?? ""
      const retornoAlmoco = marcacoes[2] ?? ""
      const saida         = marcacoes[3] ?? ""

      // Tempo total empresa (primeira → última marcação)
      let tempoTotalEmpresa = ""
      if (marcacoes.length >= 2) {
        const ini = horarioParaMinutos(marcacoes[0])
        const fim = horarioParaMinutos(marcacoes[marcacoes.length - 1])
        if (ini != null && fim != null) {
          let diff = fim - ini
          if (diff < 0) diff += 24 * 60
          tempoTotalEmpresa = minutosParaHorario(diff)
        }
      }

      // Situação (código + descrição)
      let codSit = "", descSit = "", tempoSit = ""
      for (let i = 3; i < valores.length; i++) {
        const v = valores[i]
        if (/^\d{3}$/.test(v) && !codSit) { codSit = v; continue }
        if (v && !/^\d+$/.test(v) && !descSit) { descSit = v; continue }
        if (/^\d{2}:\d{2}/.test(v) && !tempoSit) { tempoSit = v }
      }

      resultado.push({
        ID_Colaborador: idAtual ?? "",
        Nome_Colaborador: nomeAtual ?? "",
        Data: data,
        Dia_Semana: col1,
        Entrada: entrada,
        Saida_Almoco: saidaAlmoco,
        Retorno_Almoco: retornoAlmoco,
        Saida: saida,
        Tempo_Total_Empresa: tempoTotalEmpresa,
        Horario_Previsto: horarioPrevisto ?? "",
        Cod_Situacao: codSit,
        Desc_Situacao: descSit,
        Tempo_Situacao: tempoSit,
      })
    }
  }

  // Filtra por mês
  return resultado.filter(row => {
    const parts = row.Data.split("/")
    if (parts.length < 2) return false
    return parseInt(parts[1]) === mes
  })
}

// ─── Remove duplicatas priorizando registro mais completo ─────────────────────

function removerDuplicatas(rows: any[]): any[] {
  const mapa = new Map<string, any>()
  for (const row of rows) {
    const chave = `${row.ID_Colaborador}|${row.Data}`
    const score = [row.Entrada, row.Saida_Almoco, row.Retorno_Almoco, row.Saida]
      .filter(v => v && v !== "").length
    const existing = mapa.get(chave)
    if (!existing) {
      mapa.set(chave, { ...row, _score: score })
    } else if (score > existing._score) {
      mapa.set(chave, { ...row, _score: score })
    }
  }
  return Array.from(mapa.values()).map(({ _score, ...rest }) => rest)
}

// ─── Análise de conformidade ──────────────────────────────────────────────────

function analisarConformidade(
  rows: any[],
  valorMarcacoes: number,
  valorCriterios: number,
  colNome: string
): { detalhe: any[]; consolidado: any[] } {

  const sorted = [...rows].sort((a, b) => {
    if (a.ID_Colaborador !== b.ID_Colaborador) return a.ID_Colaborador.localeCompare(b.ID_Colaborador)
    return a.Data.localeCompare(b.Data)
  })

  const ultimoRegistro: Record<string, { data: string; saidaMin: number | null }> = {}
  const detalhe: any[] = []

  for (const row of sorted) {
    const { trab, alm } = calcularTempoTrabalhado(
      row.Entrada, row.Saida_Almoco, row.Retorno_Almoco, row.Saida
    )

    const marc = [row.Entrada, row.Saida_Almoco, row.Retorno_Almoco, row.Saida]
    const marcOk = marc.filter(m => m && m !== "").length
    const cumpriuMarcacoes = marcOk === 4
    const bonusMarcacoes   = cumpriuMarcacoes ? valorMarcacoes : 0

    // Jornada
    const limiteJornada = CARGA_HORARIA_PADRAO_MIN + 120 // +2h
    const excessoJornada = trab != null ? Math.max(0, trab - limiteJornada) : null
    const cumpriuJornada = trab != null ? trab <= limiteJornada : false

    // HE
    const he            = trab != null ? Math.max(0, trab - CARGA_HORARIA_PADRAO_MIN) : 0
    const excessoHE     = Math.max(0, he - 120)
    const cumpriuHE     = he <= 120

    // Almoço
    const cumpriuAlmoco = alm != null ? alm >= 60 : false
    const deficitAlmoco = alm != null ? Math.max(0, 60 - alm) : 60

    // Intrajornada
    const e  = horarioParaMinutos(row.Entrada)
    const sa = horarioParaMinutos(row.Saida_Almoco)
    const ra = horarioParaMinutos(row.Retorno_Almoco)
    const s  = horarioParaMinutos(row.Saida)

    let periodoManha = 0, periodoTarde = 0
    if (e != null && sa != null) { periodoManha = sa - e; if (periodoManha < 0) periodoManha += 1440 }
    if (ra != null && s  != null) { periodoTarde = s - ra;  if (periodoTarde < 0) periodoTarde += 1440 }
    const excessoManha = Math.max(0, periodoManha - 360)
    const excessoTarde = Math.max(0, periodoTarde - 360)
    const cumpriuIntrajornada = excessoManha === 0 && excessoTarde === 0

    // Interjornada
    let descansoMin: number | null = null
    let cumpriuInterjornada = true
    const prev = ultimoRegistro[row.ID_Colaborador]
    if (prev && prev.saidaMin != null && e != null) {
      const prevDateOrd = dateToOrdinal(prev.data)
      const currDateOrd = dateToOrdinal(row.Data)
      if (currDateOrd >= prevDateOrd) {
        descansoMin = (currDateOrd - prevDateOrd) * 1440 + e - prev.saidaMin
        cumpriuInterjornada = descansoMin >= INTERJORNADA_MIN_MIN
      }
    }
    ultimoRegistro[row.ID_Colaborador] = { data: row.Data, saidaMin: s }

    const todos5OK = cumpriuJornada && cumpriuHE && cumpriuAlmoco && cumpriuIntrajornada && cumpriuInterjornada
    const bonusCriterios  = todos5OK ? valorCriterios : 0
    const bonificacaoTotal = +(bonusMarcacoes + bonusCriterios).toFixed(2)

    const temAjuste = marc.some(m => m && m.includes("*"))

    detalhe.push({
      "ID": row.ID_Colaborador,
      [colNome]: row.Nome_Colaborador,
      "Dia": row.Data,
      "Dia_Semana": row.Dia_Semana,
      "Entrada": row.Entrada,
      "Saida_Almoco": row.Saida_Almoco,
      "Retorno_Almoco": row.Retorno_Almoco,
      "Saida": row.Saida,
      "Tem_Ajuste_Manual": temAjuste,
      "Tempo_Trabalhado": minutosParaHorario(trab),
      "Tempo_Almoco": minutosParaHorario(alm),
      "Marcacoes_Completas": marcOk,
      "Marcacoes_Faltantes": 4 - marcOk,
      "✓ Marcacoes_100%": cumpriuMarcacoes,
      "💰 Bonus_Marcacoes": +bonusMarcacoes.toFixed(2),
      "Excesso_Jornada": minutosParaHorario(excessoJornada),
      "✓ Jornada_OK": cumpriuJornada,
      "HE_Realizada": minutosParaHorario(he),
      "Excesso_HE": minutosParaHorario(excessoHE),
      "✓ HE_OK": cumpriuHE,
      "Almoco_Realizado": minutosParaHorario(alm),
      "Deficit_Almoco": minutosParaHorario(deficitAlmoco),
      "✓ Almoco_OK": cumpriuAlmoco,
      "Periodo_Manha": minutosParaHorario(periodoManha),
      "Periodo_Tarde": minutosParaHorario(periodoTarde),
      "✓ Intrajornada_OK": cumpriuIntrajornada,
      "Interjornada_Descanso": minutosParaHorario(descansoMin),
      "✓ Interjornada_OK": cumpriuInterjornada,
      "Todos_5_Criterios_OK": todos5OK,
      "💰 Bonus_Criterios": +bonusCriterios.toFixed(2),
      "💵 Bonificacao_Total_Dia": bonificacaoTotal,
      "Desc_Situacao": row.Desc_Situacao,
    })
  }

  // Consolidado por colaborador
  const porColab: Record<string, any> = {}
  for (const row of detalhe) {
    const id = row["ID"]
    if (!porColab[id]) {
      porColab[id] = {
        "ID": id, [colNome]: row[colNome],
        dias: 0, bonusMarcacoes: 0, bonusCriterios: 0, bonifTotal: 0,
        diasCriteriosOk: 0, dias4Marc: 0, ajustes: 0,
      }
    }
    const c = porColab[id]
    c.dias++
    c.bonusMarcacoes += row["💰 Bonus_Marcacoes"]
    c.bonusCriterios += row["💰 Bonus_Criterios"]
    c.bonifTotal     += row["💵 Bonificacao_Total_Dia"]
    if (row["Todos_5_Criterios_OK"]) c.diasCriteriosOk++
    if (row["Marcacoes_Completas"] === 4) c.dias4Marc++
    if (row["Tem_Ajuste_Manual"]) c.ajustes++
  }

  const consolidado = Object.values(porColab).map((c: any) => ({
    "ID": c["ID"],
    [colNome]: c[colNome],
    "Dias_Trabalhados": c.dias,
    "💰 Total_Bonus_Marcacoes": +c.bonusMarcacoes.toFixed(2),
    "💰 Total_Bonus_Criterios": +c.bonusCriterios.toFixed(2),
    "💵 BONIFICACAO_TOTAL": +c.bonifTotal.toFixed(2),
    "Dias_Todos_Criterios_OK": c.diasCriteriosOk,
    "Dias_4_Marcacoes_Completas": c.dias4Marc,
    "Total_Ajustes_Manuais": c.ajustes,
  })).sort((a, b) => b["💵 BONIFICACAO_TOTAL"] - a["💵 BONIFICACAO_TOTAL"])

  return { detalhe, consolidado }
}

// ─── Etapa 4: Absenteísmo ─────────────────────────────────────────────────────

function analisarAbsenteismo(
  rowsMot: any[], rowsAju: any[], mes: number,
  datasExcluir: string[], considerarDomingos: boolean,
  absValor100: number, absValor90: number, absValor75: number,
): { resumo: any[]; detalhe: any[] } {

  const todos: any[] = [
    ...rowsMot.map(r => ({ ...r, Grupo: "Motorista" })),
    ...rowsAju.map(r => ({ ...r, Grupo: "Ajudante" })),
  ]

  // Remove domingos
  const filtrado = todos.filter(row => {
    const parts = row.Data?.split("/")
    if (!parts || parts.length < 3) return true
    const d = new Date(+parts[2], +parts[1] - 1, +parts[0])
    if (!considerarDomingos && d.getDay() === 0) return false
    const iso = d.toISOString().slice(0, 10)
    const brFmt = `${parts[0]}/${parts[1]}/${parts[2]}`
    if (datasExcluir.includes(brFmt)) return false
    return true
  })

  const regexPresenca = new RegExp(SITUACOES_CONTAM_PRESENCA.join("|"), "i")

  const porColab: Record<string, any> = {}

  for (const row of filtrado) {
    const id   = row.ID_Colaborador
    const nome = row.Nome_Colaborador
    if (!id || !nome) continue

    if (!porColab[id]) {
      porColab[id] = {
        ID: id, Nome: nome, Grupo: row.Grupo,
        totalDias: 0, presencasFisicas: 0, presencasJustificadas: 0, totalPresencas: 0,
      }
    }

    const c = porColab[id]
    c.totalDias++

    const presencaFisica = !!(
      (row.Entrada && row.Entrada !== "") ||
      (row.Saida && row.Saida !== "") ||
      (row.Tempo_Total_Empresa && row.Tempo_Total_Empresa !== "")
    )
    const presencaJustificada = !!(row.Desc_Situacao && regexPresenca.test(row.Desc_Situacao))
    const presente = presencaFisica || presencaJustificada

    if (presencaFisica)     c.presencasFisicas++
    if (presencaJustificada) c.presencasJustificadas++
    if (presente)            c.totalPresencas++
  }

  const resumo = Object.values(porColab).map((c: any) => {
    const faltas   = Math.max(0, c.totalDias - c.totalPresencas)
    const perc     = c.totalDias > 0 ? +(c.totalPresencas / c.totalDias * 100).toFixed(2) : 0
    const incentivo = perc >= 100 ? absValor100 : perc >= 90 ? absValor90 : perc >= 75 ? absValor75 : 0
    return {
      "ID": c.ID, "Nome": c.Nome, "Grupo": c.Grupo,
      "Total_Dias": c.totalDias,
      "Presenças Físicas": c.presencasFisicas,
      "Atestados/Férias": c.presencasJustificadas,
      "Total Presenças": c.totalPresencas,
      "Faltas": faltas,
      "Percentual (%)": perc,
      "Valor_Incentivo": incentivo,
    }
  }).sort((a, b) => a.Grupo.localeCompare(b.Grupo) || a.Nome.localeCompare(b.Nome))

  return { resumo, detalhe: filtrado }
}

// ─── Helper: converte DD/MM/YYYY para ordinal de dias ────────────────────────

function dateToOrdinal(dataStr: string): number {
  const parts = dataStr.split("/")
  if (parts.length < 3) return 0
  return Math.floor(new Date(+parts[2], +parts[1] - 1, +parts[0]).getTime() / 86400000)
}

// ─── Processor principal ──────────────────────────────────────────────────────

async function pontoProcessor(args: PipelineArgs): Promise<ProcessorOutput> {
  const sheetsData = await args.files.readAll("files")
  const fileNames: string[] = (args.formData?.getAll("fileNames") as string[]) ?? []

  const excludedDatesRaw = args.formData?.get("excludedDates") as string ?? "[]"
  const datasExcluir: string[] = JSON.parse(excludedDatesRaw)
  const considerarDomingos = args.formData?.get("includeSundays") === "true"

  const absValor100 = 50.0
  const absValor90  = 40.0
  const absValor75  = 25.0

  if (!sheetsData.length) throw new Error("Nenhum arquivo encontrado.")

  // Separa arquivos de motoristas vs ajudantes pelo nome
  const rowsMot: any[] = []
  const rowsAju: any[] = []

  sheetsData.forEach((rows, idx) => {
    const nome = (fileNames[idx] ?? "").toLowerCase()
    const parsed = parsearCSVPonto(rows, args.month ?? new Date().getMonth() + 1)
    if (/ajudante/i.test(nome)) rowsAju.push(...parsed)
    else rowsMot.push(...parsed)
  })

  const cleanMot = removerDuplicatas(rowsMot)
  const cleanAju = removerDuplicatas(rowsAju)

  // Sem marcação
  const semMarcMot = cleanMot.filter(r =>
    !r.Entrada && !r.Saida_Almoco && !r.Retorno_Almoco && !r.Saida
  )
  const semMarcAju = cleanAju.filter(r =>
    !r.Entrada && !r.Saida_Almoco && !r.Retorno_Almoco && !r.Saida
  )

  // Etapas 2 e 3
  const { detalhe: detMot, consolidado: consMot } =
    analisarConformidade(cleanMot, MOT_VALOR_MARCACOES, MOT_VALOR_CRITERIOS, "Motorista")
  const { detalhe: detAju, consolidado: consAju } =
    analisarConformidade(cleanAju, AJU_VALOR_MARCACOES, AJU_VALOR_CRITERIOS, "Ajudante")

  // Etapa 4
  const { resumo: absResumo, detalhe: absDetalhe } = analisarAbsenteismo(
    cleanMot, cleanAju, args.month ?? 1,
    datasExcluir, considerarDomingos, absValor100, absValor90, absValor75,
  )

  // Resumo de bonificações
  const resumoBonif = [
    ...["MOTORISTA", "AJUDANTE"].flatMap((grupo, gi) => {
      const det = gi === 0 ? detMot : detAju
      const vMar = gi === 0 ? MOT_VALOR_MARCACOES : AJU_VALOR_MARCACOES
      const vCri = gi === 0 ? MOT_VALOR_CRITERIOS : AJU_VALOR_CRITERIOS
      const vPon = gi === 0 ? MOT_VALOR_PONTO : AJU_VALOR_PONTO
      const tMar = det.reduce((s, r) => s + r["💰 Bonus_Marcacoes"], 0)
      const tCri = det.reduce((s, r) => s + r["💰 Bonus_Criterios"], 0)
      const tTot = det.reduce((s, r) => s + r["💵 Bonificacao_Total_Dia"], 0)
      return [
        { Grupo: grupo, Tipo: "1ª - Marcações (4/4) — GARANTIDO", Valor_Diario: `R$ ${vMar.toFixed(2)}`, Total_Pago: `R$ ${tMar.toFixed(2)}`, Regra: "Garantido se 4 batidas" },
        { Grupo: grupo, Tipo: "2ª - 5 Critérios OK — TUDO OU NADA", Valor_Diario: `R$ ${vCri.toFixed(2)}`, Total_Pago: `R$ ${tCri.toFixed(2)}`, Regra: "Jornada + HE + Almoço + Intrajornada + Interjornada" },
        { Grupo: grupo, Tipo: "TOTAL PONTO", Valor_Diario: `R$ ${vPon.toFixed(2)}`, Total_Pago: `R$ ${tTot.toFixed(2)}`, Regra: "" },
      ]
    })
