const ResumoBox: FC<{ title: string; items: { label: string; count: number }[]; total: number }> = ({
  title, items, total,
}) => (
  <Card className="overflow-hidden">
    <button className="w-full flex items-center justify-between px-4 py-3 border-b border-border bg-muted/30">
      <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">{title}</span>
    </button>
    <div className="max-h-60 overflow-y-auto scrollbar-thin">
      <Table>
        <TableHeader>
          <TableRow className="hover:bg-transparent">
            {["Valor","Qtd","%"].map((h) => (
              <TableHead key={h} className={cn("text-[10px] uppercase tracking-wide h-8", h !== "Valor" && "text-right")}>{h}</TableHead>
            ))}
          </TableRow>
        </TableHeader>
        <TableBody>
          {items.map((item) => {
            const pct = total > 0 ? (item.count / total) * 100 : 0;
            return (
              <TableRow key={item.label} className="hover:bg-accent/30">
                <TableCell className="text-xs py-1.5 max-w-[160px] truncate" title={item.label}>{item.label}</TableCell>
                <TableCell className="text-xs py-1.5 font-mono font-bold text-right">{item.count}</TableCell>
                <TableCell className="py-1.5 w-24">
                  <div className="flex items-center gap-1.5">
                    <ProgressBar pct={pct} />
                    <span className="text-[10px] text-muted-foreground font-mono min-w-[28px] text-right">{pct.toFixed(0)}%</span>
                  </div>
                </TableCell>
              </TableRow>
            );
          })}
          <TableRow className="bg-primary/5 border-t-2 border-primary/20 hover:bg-primary/10">
            <TableCell className="text-xs py-1.5 font-bold text-primary">Total</TableCell>
            <TableCell className="text-xs py-1.5 font-mono font-bold text-primary text-right">{total}</TableCell>
            <TableCell className="text-xs py-1.5 text-primary">100%</TableCell>
          </TableRow>
        </TableBody>
      </Table>
    </div>
  </Card>
);

// ─────────────────────────────────────────────────────────────────────────────
// PROPS
// ─────────────────────────────────────────────────────────────────────────────

interface FechamentoDiarioProps {
  rows:        AnyRow[];
  filterDay:   number;
  filterMonth: number;
  filterYear:  number;
  filial?:     string;
}

// ─────────────────────────────────────────────────────────────────────────────
// COMPONENTE PRINCIPAL
// ─────────────────────────────────────────────────────────────────────────────

export const FechamentoDiario: FC<FechamentoDiarioProps> = ({
  rows, filterDay, filterMonth, filterYear,
}) => {
  const anteriorInputRef = useRef<HTMLInputElement>(null);

  // ── estado ────────────────────────────────────────────────────────────────
  const [arquivosAnteriores, setArquivosAnteriores] = useState<ArquivoAnterior[]>([]);
  const [loadingAnt, setLoadingAnt] = useState(false);
  const [erroAnt,    setErroAnt]    = useState<string | null>(null);
  const [tab,        setTab]        = useState<TabView>("visao");
  const [editingCell, setEditingCell] = useState<{ row: number; col: keyof FechRow } | null>(null);
  const [editValue,   setEditValue]   = useState("");
  const [localRows,   setLocalRows]   = useState<FechRow[]>([]);
  const [filtroStatus, setFiltroStatus] = useState<string>("");

  const anteriorRows = useMemo(
    () => arquivosAnteriores.flatMap((a) => a.linhas),
    [arquivosAnteriores]
  );

  const fechRowsBase = useMemo(
    () => rows.map((r, i) => rowToFechRow(r, i)),
    [rows]
  );

  const fechRowsMesclados = useMemo(
    () => mesclarComAnterior(fechRowsBase, anteriorRows),
    [fechRowsBase, anteriorRows]
  );

  useEffect(() => {
    setLocalRows(fechRowsMesclados);
  }, [fechRowsMesclados]); // eslint-disable-line react-hooks/exhaustive-deps

  const rowsExibidos = localRows.length > 0 ? localRows : fechRowsMesclados;

  // rows da aba detalhes (filtro de status aplicado)
  const rowsFiltradosDetalhes = useMemo(
    () => filtroStatus ? rowsExibidos.filter((r) => r.STATUS === filtroStatus) : rowsExibidos,
    [rowsExibidos, filtroStatus]
  );

  // statuses únicos para o select
  const statusUnicos = useMemo(
    () => [...new Set(rowsExibidos.map((r) => r.STATUS || "S/ Status").filter(Boolean))].sort(),
    [rowsExibidos]
  );

  // ── estatísticas ──────────────────────────────────────────────────────────
  const totalRows  = rowsExibidos.length;
  const fechados   = rowsExibidos.filter((r) => r.STATUS === "FECHADO").length;
  const pendentes  = rowsExibidos.filter((r) => r.STATUS === "PENDENTE").length;
  const outros     = totalRows - fechados - pendentes;
  const complAnt   = rowsExibidos.filter((r) => r._preenchidoAnterior).length;
  const vindoAnt   = rowsExibidos.filter((r) => r._vindoAnterior).length;
  const totalEnt   = rowsExibidos.reduce((s, r) => s + r.ENTREGAS, 0);
  const totalPeso  = rowsExibidos.reduce((s, r) => s + r.PESO, 0);
  const totalKm    = rowsExibidos.reduce((s, r) => s + r.KM, 0);
  const pctFech    = totalRows > 0 ? Math.round((fechados / totalRows) * 100) : 0;

  const filiais = useMemo(
    () => [...new Set(rowsExibidos.map((r) => r.FILIAL).filter(Boolean))].sort(),
    [rowsExibidos]
  );

  const porStatus = useMemo(() => {
    const m: Record<string, number> = {};
    rowsExibidos.forEach((r) => { const k = r.STATUS || "S/ Status"; m[k] = (m[k] ?? 0) + 1; });
    return Object.entries(m).map(([label, count]) => ({ label, count })).sort((a, b) => b.count - a.count);
  }, [rowsExibidos]);

  const porCarga = useMemo(() => {
    const m: Record<string, number> = {};
    rowsExibidos.forEach((r) => { const k = r.Tipo_Carga || "Carga A"; m[k] = (m[k] ?? 0) + 1; });
    return Object.entries(m).map(([label, count]) => ({ label, count })).sort((a, b) => b.count - a.count);
  }, [rowsExibidos]);

  const porFilialStatus = useMemo(() => {
    const m: Record<string, number> = {};
    rowsExibidos.forEach((r) => {
      const k = r.FILIAL || "Sem filial";
      m[k] = (m[k] ?? 0) + (r.STATUS === "FECHADO" ? 1 : 0);
    });
    return Object.entries(m).map(([label, count]) => ({ label, count })).sort((a, b) => b.count - a.count);
  }, [rowsExibidos]);

  const diaLabel = filterDay > 0
    ? `${String(filterDay).padStart(2,"0")}/${String(filterMonth).padStart(2,"0")}/${filterYear}`
    : `${String(filterMonth).padStart(2,"0")}/${filterYear}`;

  // ── UPLOAD DE EXCELS ANTERIORES ───────────────────────────────────────────
  // Lê TODAS as abas do arquivo (uma por região) e mescla todas as linhas.
  // Remapeia label → key em cada linha para compatibilidade com FechRow.
  // ─────────────────────────────────────────────────────────────────────────

  async function handleAnteriorUpload(e: ChangeEvent<HTMLInputElement>): Promise<void> {
    const files = Array.from(e.target.files ?? []);
    if (!files.length) return;
    if (arquivosAnteriores.length + files.length > 5) {
      setErroAnt(`Máximo 5 arquivos. Já tem ${arquivosAnteriores.length}.`);
      if (anteriorInputRef.current) anteriorInputRef.current.value = "";
      return;
    }
    setLoadingAnt(true); setErroAnt(null);
    const novos: ArquivoAnterior[] = [];

    try {
      for (const file of files) {
        const buffer = await file.arrayBuffer();
        const wb     = XLSX.read(buffer, { type: "array" });

        // ── Lê TODAS as abas e mescla as linhas ──────────────────────────
        // Filtra a aba "Todos" para evitar duplicatas (ela contém tudo já).
        // Se não houver aba "Todos", lê todas mesmo.
        const abasParaLer = wb.SheetNames.includes("Todos")
          ? ["Todos"]                           // basta ler a aba consolidada
          : wb.SheetNames;                      // sem aba Todos → lê todas

        const todasLinhas: AnyRow[] = [];

        for (const nomAba of abasParaLer) {
          const sheet = wb.Sheets[nomAba];
          if (!sheet) continue;

          const linhasAba = XLSX.utils.sheet_to_json<AnyRow>(sheet, {
            defval: "",
            cellDates: false,
          } as any);

          // Remapeia label (coluna do Excel) → key interno (FechRow)
          for (const row of linhasAba) {
            const novo: AnyRow = {};
            for (const [col, val] of Object.entries(row)) {
              const key = LABEL_TO_KEY[col] ?? col;
              novo[key] = val;
            }
            if (novo["STATUS"]) {
              novo["STATUS"] = normalizarStatus(String(novo["STATUS"]));
            }
            todasLinhas.push(novo);
          }
        }

        novos.push({ nome: file.name, linhas: todasLinhas });
      }

      setArquivosAnteriores((prev) => {
        const nomesNovos = new Set(novos.map((n) => n.nome));
        return [...prev.filter((a) => !nomesNovos.has(a.nome)), ...novos];
      });

    } catch (err) {
      setErroAnt(err instanceof Error ? err.message : "Erro ao ler arquivo.");
    } finally {
      setLoadingAnt(false);
      if (anteriorInputRef.current) anteriorInputRef.current.value = "";
    }
  }

  function removerArquivoAnterior(nome: string): void {
    setArquivosAnteriores((prev) => prev.filter((a) => a.nome !== nome));
  }

  // ── EDIÇÃO INLINE ─────────────────────────────────────────────────────────

  function startEdit(ri: number, col: keyof FechRow): void {
    setEditingCell({ row: ri, col });
    setEditValue(String((rowsExibidos[ri] as any)[col] ?? ""));
  }
  function commitEdit(): void {
    if (!editingCell) return;
    const { row: ri, col } = editingCell;
    const final = col === "STATUS" ? normalizarStatus(editValue) : editValue;
    setLocalRows((prev) => prev.map((r, i) => i === ri ? { ...r, [col]: final } : r));
    setEditingCell(null);
  }

  // ── EXPORTAÇÕES ───────────────────────────────────────────────────────────
  // exportarExcel: gera aba por REGIÃO + aba "Todos"
  // ─────────────────────────────────────────────────────────────────────────

  function exportarExcel(): void {
    if (!rowsExibidos.length) return;
    const wb = buildExcelWorkbook(rowsExibidos, TABLE_COLS);
    XLSX.writeFile(wb, `RFK_Fechamento_${diaLabel.replace(/\//g, "-")}.xlsx`);
  }

  function exportarHtml(): void {
    const html = gerarHtml(rowsExibidos, diaLabel);
    const blob = new Blob([html], { type: "text/html;charset=utf-8" });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement("a");
    a.href = url;
    a.download = `RFK_Fechamento_${diaLabel.replace(/\//g, "-")}.html`;
    a.click();
    URL.revokeObjectURL(url);
  }

  // Exportação filtrada (aba Detalhes) — também usa abas por região
  function exportarExcelFiltrado(): void {
    if (!rowsFiltradosDetalhes.length) return;
    const wb = buildExcelWorkbook(rowsFiltradosDetalhes, TABLE_COLS);
    const sufixo = filtroStatus ? `_${filtroStatus}` : "";
    XLSX.writeFile(wb, `RFK_Fechamento_${diaLabel.replace(/\//g, "-")}${sufixo}.xlsx`);
  }

  // ─────────────────────────────────────────────────────────────────────────
  // RENDER — empty state
  // ─────────────────────────────────────────────────────────────────────────

  if (rows.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-16 gap-3 text-muted-foreground">
        <ClipboardList className="h-10 w-10 opacity-30" />
        <p className="text-sm font-medium">Nenhum dado para o dia selecionado.</p>
        <p className="text-xs">Ajuste o filtro <strong>Dia</strong> para um valor específico.</p>
      </div>
    );
  }

  // ─────────────────────────────────────────────────────────────────────────
  // RENDER PRINCIPAL
  // ─────────────────────────────────────────────────────────────────────────

  return (
    <div className="space-y-4 animate-in">

      {/* ── HEADER DO COMPONENTE ─────────────────────────────────────────── */}
      <div className="flex flex-wrap items-start gap-3">

        {/* Título + dia + badges de progresso */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <h2 className="text-base font-bold flex items-center gap-2">
              <ClipboardList className="h-4 w-4 text-primary" />
              Fechamento Diário
            </h2>
            <Badge variant="outline" className="font-mono text-sm px-3">{diaLabel}</Badge>
            {vindoAnt > 0 && (
              <Badge className="text-[10px] bg-orange-500/10 text-orange-500 border-orange-400/30">
                +{vindoAnt} Anterior
              </Badge>
            )}
            {complAnt > 0 && (
              <Badge className="text-[10px] bg-blue-500/10 text-blue-400 border-blue-400/30">
                {complAnt} Complementados
              </Badge>
            )}
          </div>
          {/* KPIs em linha no header */}
          <div className="flex flex-wrap gap-2 mt-2">
            {[
              { label: "Total",    v: totalRows, cn: "text-primary"       },
              { label: "✅ Fech.", v: fechados,  cn: "text-emerald-500"   },
              { label: "⏳ Pend.", v: pendentes, cn: "text-yellow-500"    },
              { label: "⚠ Outros",v: outros,    cn: "text-destructive"   },
            ].map((k) => (
              <span key={k.label} className={cn("text-xs font-mono font-bold", k.cn)}>
                {k.label}: {k.v}
              </span>
            ))}
            <span className="text-muted-foreground text-xs">·</span>
            <span className="text-xs text-muted-foreground font-mono">{pctFech}% fechado</span>
          </div>
        </div>

        {/* Upload anteriores */}
        <div className="flex flex-col gap-1.5 items-end">
          <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
            Complementar
            {arquivosAnteriores.length > 0 && (
              <span className="ml-1 font-normal normal-case text-muted-foreground/60">
                ({arquivosAnteriores.length}/5 · {anteriorRows.length} linhas)
              </span>
            )}
          </span>

          {/* Info do que será incluído */}
          {arquivosAnteriores.length === 0 && (
            <p className="text-[10px] text-muted-foreground/60 text-right max-w-[260px] leading-tight">
              Linhas Pendentes <strong>Adicionadas</strong> e <strong>Fechadas</strong> Ignoradas.
            </p>
          )}

          {arquivosAnteriores.length > 0 && (
            <div className="flex flex-wrap gap-1 justify-end">
              {arquivosAnteriores.map((a) => (
                <div key={a.nome} className="flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-lg border border-border bg-muted/30 font-mono max-w-[180px]">
                  <CheckCircle2 className="h-3 w-3 text-emerald-500 shrink-0" />
                  <span className="truncate">{a.nome}</span>
                  <span className="text-muted-foreground/50 shrink-0">·{a.linhas.length}</span>
                  <button onClick={() => removerArquivoAnterior(a.nome)} className="hover:text-destructive transition-colors shrink-0">
                    <XCircle className="h-3 w-3" />
                  </button>
                </div>
              ))}
            </div>
          )}
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm" className="h-7 text-xs gap-1.5"
              disabled={loadingAnt || arquivosAnteriores.length >= 5}
              onClick={() => anteriorInputRef.current?.click()}>
              <Upload className="h-3 w-3" />
              {loadingAnt ? "Lendo..." : arquivosAnteriores.length >= 5 ? "Máx. 5" : arquivosAnteriores.length > 0 ? "Adicionar mais" : "Excels Anteriores"}
            </Button>
            {arquivosAnteriores.length > 0 && (
              <button onClick={() => setArquivosAnteriores([])} className="text-[10px] text-muted-foreground hover:text-destructive transition-colors">Limpar</button>
            )}
          </div>
          {erroAnt && (
            <p className="text-[10px] text-destructive flex items-center gap-1">
              <AlertCircle className="h-3 w-3" />{erroAnt}
            </p>
          )}
          <input ref={anteriorInputRef} type="file" accept=".xlsx,.xls" multiple onChange={handleAnteriorUpload} className="hidden" />
        </div>

        {/* Exportações */}
        <div className="flex gap-2 self-start">
          <Button variant="outline" size="sm" className="h-7 text-xs gap-1.5" onClick={exportarExcel}>
            <FileSpreadsheet className="h-3.5 w-3.5" /> Excel
          </Button>
          <Button size="sm" className="h-7 text-xs gap-1.5" onClick={exportarHtml}>
            <Download className="h-3.5 w-3.5" /> HTML
          </Button>
        </div>
      </div>

      {/* ── TABS ─────────────────────────────────────────────────────────── */}
      <div className="flex border-b border-border">
        {[
          { id: "visao" as TabView,    label: "Visão Geral",   icon: <LayoutDashboard className="h-3.5 w-3.5" /> },
          { id: "detalhes" as TabView, label: "Detalhes",      icon: <Table2          className="h-3.5 w-3.5" /> },
        ].map(({ id, label, icon }) => (
          <button key={id} onClick={() => setTab(id)}
            className={cn(
              "flex items-center gap-1.5 px-4 py-2.5 text-sm font-medium transition-colors border-b-2 -mb-px",
              tab === id
                ? "border-primary text-foreground"
                : "border-transparent text-muted-foreground hover:text-foreground"
            )}>
            {icon}{label}
          </button>
        ))}
      </div>

      {/* ══════════════════════════════════════════════════════════════════
          ABA: VISÃO GERAL
      ══════════════════════════════════════════════════════════════════ */}
      {tab === "visao" && (
        <div className="space-y-5">

          {/* KPI strip */}
          <div className="flex gap-2 flex-wrap">
            {[
              { label: "Total",       v: totalRows,        sub: "registros",           cn: "border-primary/30 bg-primary/5 text-primary"                    },
              { label: "✅ Fechados", v: fechados,         sub: `${pctFech}% do total`,cn: "border-emerald-500/30 bg-emerald-500/10 text-emerald-500"        },
              { label: "⏳ Pendentes",v: pendentes,        sub: `${totalRows > 0 ? Math.round(pendentes/totalRows*100) : 0}% do total`, cn: "border-yellow-500/30 bg-yellow-500/10 text-yellow-500" },
              { label: "⚠ Outros",   v: outros,           sub: "sem status / outro",  cn: "border-destructive/30 bg-destructive/10 text-destructive"        },
              { label: "📦 Entregas", v: totalEnt,         sub: "total do dia",        cn: "border-blue-400/30 bg-blue-500/10 text-blue-400"                 },
              { label: "⚖️ Peso",    v: fmtNum(totalPeso),sub: "kg total",            cn: "border-border bg-card text-foreground"                          },
              { label: "🛣️ KM",      v: fmtNum(totalKm),  sub: "km total",            cn: "border-border bg-card text-foreground"                          },
            ].map((k) => (
              <div key={k.label} className={cn("flex-1 min-w-[110px] rounded-xl border p-4", k.cn)}>
                <p className="text-[10px] font-semibold uppercase tracking-wide opacity-75 mb-1">{k.label}</p>
                <p className="text-2xl font-bold font-mono tracking-tight">{typeof k.v === "number" ? k.v.toLocaleString("pt-BR") : k.v}</p>
                <p className="text-[10px] text-muted-foreground mt-1">{k.sub}</p>
              </div>
            ))}
          </div>

          {/* Barra de progresso de fechamento */}
          <div className="rounded-xl border border-border bg-card p-4">
            <div className="flex items-center justify-between mb-2">
              <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wide">Progresso de Fechamento</span>
              <span className="text-sm font-bold font-mono text-primary">{pctFech}%</span>
            </div>
            <div className="h-3 rounded-full bg-border overflow-hidden">
              <div
                className="h-full rounded-full bg-gradient-to-r from-primary to-emerald-400 transition-all duration-700"
                style={{ width: `${pctFech}%` }}
              />
            </div>
            <div className="flex justify-between mt-1.5 text-[10px] text-muted-foreground font-mono">
              <span>{fechados} fechados</span>
              <span>{totalRows - fechados} restantes</span>
            </div>
          </div>

          {/* Cards por filial */}
          {filiais.length > 0 && (
            <div className="space-y-2">
              <div className="flex items-center gap-2">
                <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">📍 Por Filial</p>
                <div className="flex-1 h-px bg-border" />
              </div>
              <div className="grid grid-cols-[repeat(auto-fill,minmax(210px,1fr))] gap-3">
                {filiais.map((f) => (
                  <FilialCard key={f} filial={f} rows={rowsExibidos.filter((r) => r.FILIAL === f)} />
                ))}
              </div>
            </div>
          )}

          {/* Resumos */}
          <div className="space-y-2">
            <div className="flex items-center gap-2">
              <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">📊 Análise Detalhada</p>
              <div className="flex-1 h-px bg-border" />
            </div>
            <div className="grid grid-cols-[repeat(auto-fill,minmax(320px,1fr))] gap-3">
              <ResumoBox title="Por Status"         items={porStatus}       total={totalRows} />
              <ResumoBox title="Por Tipo de Carga"  items={porCarga}        total={totalRows} />
              <ResumoBox title="Fechados por Filial" items={porFilialStatus} total={fechados}  />
            </div>
          </div>
        </div>
      )}

      {/* ══════════════════════════════════════════════════════════════════
          ABA: DETALHES
      ══════════════════════════════════════════════════════════════════ */}
      {tab === "detalhes" && (
        <div className="space-y-3">

          {/* Toolbar detalhes */}
          <div className="flex flex-wrap items-center gap-3 p-3 rounded-xl border border-border bg-card">

            {/* Filtro de status */}
            <div className="flex flex-col gap-1">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Filtrar por Status</span>
              <div className="flex gap-1.5 flex-wrap">
                {(["", ...statusUnicos] as string[]).map((st) => {
                  const isActive = filtroStatus === st;
                  const style =
                    st === ""         ? "border-border text-muted-foreground"                          :
                    st === "FECHADO"  ? "border-emerald-500/40 text-emerald-500 bg-emerald-500/10"     :
                    st === "PENDENTE" ? "border-yellow-500/40 text-yellow-500 bg-yellow-500/10"        :
                                        "border-destructive/40 text-destructive bg-destructive/10";
                  return (
                    <button key={st || "__all__"}
                      onClick={() => setFiltroStatus(st)}
                      className={cn(
                        "text-[10px] font-bold px-2.5 py-1 rounded-full border font-mono transition-all",
                        style,
                        isActive ? "ring-2 ring-offset-1 ring-current" : "opacity-60 hover:opacity-100"
                      )}>
                      {st === "" ? "Todos" : st || "S/ Status"}
                      {st !== "" && (
                        <span className="ml-1 opacity-70">
                          ({rowsExibidos.filter((r) => (r.STATUS || "S/ Status") === st).length})
                        </span>
                      )}
                    </button>
                  );
                })}
              </div>
            </div>

            <div className="flex-1" />

            {/* Info + ações */}
            <div className="flex items-center gap-3 flex-wrap">
              {vindoAnt > 0 && (
                <div className="flex items-center gap-1.5 text-[10px] text-muted-foreground">
                  <div className="w-3 h-3 rounded-sm bg-orange-400/40 border border-orange-400/60 shrink-0" />
                  {vindoAnt} do dia anterior
                </div>
              )}
              {complAnt > 0 && (
                <div className="flex items-center gap-1.5 text-[10px] text-muted-foreground">
                  <div className="w-3 h-3 rounded-sm bg-blue-400/40 border border-blue-400/60 shrink-0" />
                  {complAnt} compl. do anterior
                </div>
              )}
              <span className="text-[10px] text-muted-foreground font-mono">
                <span className="text-foreground font-bold">{rowsFiltradosDetalhes.length}</span>
                {filtroStatus && <span className="text-primary"> filtrados</span>} / {rowsExibidos.length} total
              </span>
              <Button variant="ghost" size="sm" className="h-7 text-xs gap-1.5"
                onClick={() => setLocalRows(fechRowsMesclados)}>
                <RefreshCw className="h-3 w-3" /> Resetar
              </Button>

              {/* ── Exportar Excel filtrado (abas por região) ── */}
              <Button variant="outline" size="sm" className="h-7 text-xs gap-1.5"
                onClick={exportarExcelFiltrado}>
                <FileSpreadsheet className="h-3.5 w-3.5" />
                Exportar{filtroStatus ? ` (${filtroStatus})` : ""} Excel
              </Button>
            </div>
          </div>

          {/* Tabela editável */}
          <div className="rounded-xl border border-border overflow-hidden shadow-sm">
            <div className="overflow-auto max-h-[520px] scrollbar-thin">
              <Table className="min-w-max w-full">
                <TableHeader>
                  <TableRow className="hover:bg-transparent">
                    {TABLE_COLS.map((c) => (
                      <TableHead key={c.key}
                        className={cn("text-[10px] uppercase tracking-wide h-9 whitespace-nowrap sticky top-0 bg-card z-10", c.editavel && "bg-primary/5 text-primary")}>
                        {c.label}{c.editavel && <span className="ml-1 text-[8px] opacity-60">✎</span>}
                      </TableHead>
                    ))}
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {rowsFiltradosDetalhes.length === 0 ? (
                    <TableRow>
                      <TableCell colSpan={TABLE_COLS.length} className="text-center py-10 text-muted-foreground text-sm">
                        Nenhum registro para o status selecionado.
                      </TableCell>
                    </TableRow>
                  ) : rowsFiltradosDetalhes.map((row) => {
                    const riOriginal = rowsExibidos.findIndex((r) => r._idx === row._idx);
                    return (
                      <TableRow
                        key={row._idx}
                        className={cn(
                          "hover:bg-accent/30",
                          // Laranja = vindo do dia anterior | Azul = campo complementado
                          row._vindoAnterior
                            ? "border-l-2 border-l-orange-400/70"
                            : row._preenchidoAnterior
                              ? "border-l-2 border-l-blue-400/60"
                              : ""
                        )}
                      >
                        {TABLE_COLS.map(({ key, editavel, mono }) => {
                          const v    = String((row as any)[key] ?? "").trim();
                          const isEd = editingCell?.row === riOriginal && editingCell?.col === key;
                          if (editavel) {
                            return (
                              <TableCell key={key} className="py-1.5 px-2 bg-primary/[0.02] cursor-pointer"
                                onClick={() => !isEd && startEdit(riOriginal, key)}>
                                {isEd ? (
                                  <Input autoFocus value={editValue}
                                    onChange={(e) => setEditValue(e.target.value)}
                                    onBlur={commitEdit}
                                    onKeyDown={(e) => { if (e.key === "Enter") commitEdit(); if (e.key === "Escape") setEditingCell(null); }}
                                    className="h-6 text-xs px-1.5 py-0 min-w-[100px]" />
                                ) : key === "STATUS"           ? <StatusBadge v={v} />
                                  : key === "VOLTOU_LOGISTICA" ? <VlBadge v={v} />
                                  : <span className={cn("text-xs", !v && "text-muted-foreground/30")}>{v || "—"}</span>}
                              </TableCell>
                            );
                          }
                          return (
                            <TableCell key={key} title={v}
                              className="py-1.5 px-3 max-w-[180px] overflow-hidden text-ellipsis whitespace-nowrap align-middle">
                              {key === "STATUS"             ? <StatusBadge v={v} />
                               : key === "VOLTOU_LOGISTICA" ? <VlBadge v={v} />
                               : key === "Tipo_Carga"       ? <TipoBadge v={v || "Carga A"} />
                               : key === "PLACA" || key === "PLACA SISTEMA"
                                 ? <span className="font-mono font-bold text-primary text-xs">{v || "—"}</span>
                               : key === "MOTORISTA"
                                 ? <span className="font-medium text-xs">{v || "—"}</span>
                               : (key === "ENTREGAS" || key === "PESO" || key === "KM" || key === "CAPACIDADE")
                                 ? <span className="font-mono text-xs tabular-nums">{fmtNum(v)}</span>
                               : <span className={cn("text-xs", mono && "font-mono", !v && "text-muted-foreground/40")}>{v || "—"}</span>}
                            </TableCell>
                          );
                        })}
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            </div>
          </div>

          <p className="text-[10px] text-muted-foreground px-1">
            💡 Clique nas células marcadas com <span className="text-primary font-bold">✎</span> para editar.
            <kbd className="ml-1 text-[9px] px-1 border border-border rounded">Enter</kbd> confirma ·
            <kbd className="ml-1 text-[9px] px-1 border border-border rounded">Esc</kbd> cancela.
            <span className="ml-3 inline-flex items-center gap-1.5">
              <span className="inline-block w-2.5 h-2.5 rounded-sm bg-orange-400/40 border border-orange-400/60" />
              Do dia anterior
            </span>
            <span className="ml-2 inline-flex items-center gap-1.5">
              <span className="inline-block w-2.5 h-2.5 rounded-sm bg-blue-400/40 border border-blue-400/60" />
              Campo complementado
            </span>
          </p>
        </div>
      )}
    </div>
  );
};

export default FechamentoDiario;

"use client"

import * as React from "react"
import {
  Play,
  Trash2,
  FileCode,
  Loader2,
  BarChart3,
  Download,
  Info,
  HelpCircle,
  CheckCircle2,
  Circle,
  XCircle,
  AlertTriangle,
  ChevronRight,
  Terminal,
  Building2,
  TrendingUp,
  CalendarDays,
  DollarSign,
  FileSpreadsheet,
  BarChart2,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { AIParamAssistant } from "../../pages/AI-Param-Assistant"
import { ScrollArea } from "@/components/ui/scroll-area"
import { executeCcoPipeline } from "@/app/actions/import-cco-actions"
import { useToast } from "@/hooks/use-toast"
import { PipelineResult } from "@/lib/firebase"
import { Progress } from "@/components/ui/progress"
import { downloadMultipleSheets } from "@/lib/excel-utils"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { cn } from "@/lib/utils"

// ─── Tipos ────────────────────────────────────────────────────────────────────

type StageStatus = "idle" | "running" | "done" | "error" | "warn"

interface Stage {
  id: string
  label: string
  description: string
  status: StageStatus
}

interface LogEntry {
  time: string
  message: string
  type: "info" | "success" | "error" | "warn" | "step"
}

// ─── Constantes ───────────────────────────────────────────────────────────────

const BONIFICACAO_ROTAS = 16.0

const INITIAL_STAGES: Stage[] = [
  { id: "load",    label: "Carregar arquivos",              description: "Motoristas Ajustado + Ajudantes Ajustado",       status: "idle" },
  { id: "media",   label: "Etapa 1 — Médias diárias",       description: "Percentual por empresa/dia (Mot + Ajud)",        status: "idle" },
  { id: "dom",     label: "Etapa 2 — Remover domingos",     description: "Exclui registros de domingo da análise",         status: "idle" },
  { id: "bonus",   label: "Etapa 3 — Calcular bonificação", description: `R$ ${BONIFICACAO_ROTAS.toFixed(2)}/dia × % desempenho`,    status: "idle" },
  { id: "resumo",  label: "Etapa 4 — Resumos",              description: "Mensal por empresa + consolidado simples",        status: "idle" },
  { id: "export",  label: "Exportar / Salvar Firebase",     description: "4 abas: Diária · Formatada · Mensal · Simples",  status: "idle" },
]

const REGRAS_CCO = [
  {
    condition: "Bonificação base por dia",
    result: `R$ ${BONIFICACAO_ROTAS.toFixed(2)} × % desempenho médio`,
    variant: "info" as const,
  },
  {
    condition: "Desempenho = média Motoristas + Ajudantes",
    result: "Outer join por Empresa + Dia, skipna=true",
    variant: "success" as const,
  },
  {
    condition: "Domingos",
    result: "Removidos automaticamente da análise",
    variant: "warn" as const,
  },
]

// ─── Helpers visuais ──────────────────────────────────────────────────────────

function StageIcon({ status }: { status: StageStatus }) {
  if (status === "running") return <Loader2 className="size-4 animate-spin text-primary shrink-0" />
  if (status === "done")    return <CheckCircle2 className="size-4 text-emerald-500 shrink-0" />
  if (status === "error")   return <XCircle className="size-4 text-destructive shrink-0" />
  if (status === "warn")    return <AlertTriangle className="size-4 text-amber-500 shrink-0" />
  return <Circle className="size-4 text-muted-foreground/30 shrink-0" />
}

const stageBg: Record<StageStatus, string> = {
  idle:    "bg-muted/20 border-border/40",
  running: "bg-primary/5 border-primary/30",
  done:    "bg-emerald-50 border-emerald-200",
  error:   "bg-red-50 border-red-200",
  warn:    "bg-amber-50 border-amber-200",
}

const stageLabel: Record<StageStatus, string> = {
  idle:    "text-muted-foreground",
  running: "text-primary font-semibold",
  done:    "text-emerald-700 font-medium",
  error:   "text-red-700 font-semibold",
  warn:    "text-amber-700 font-medium",
}

const ruleColor = {
  success: "border-emerald-200 bg-emerald-50 text-emerald-700",
  danger:  "border-red-200 bg-red-50 text-red-700",
  warn:    "border-amber-200 bg-amber-50 text-amber-700",
  info:    "border-blue-200 bg-blue-50 text-blue-700",
}

const logColor: Record<LogEntry["type"], string> = {
  info:    "text-slate-400",
  success: "text-emerald-500",
  error:   "text-red-400 font-semibold",
  warn:    "text-amber-400",
  step:    "text-primary font-semibold",
}

const logPrefix: Record<LogEntry["type"], string> = {
  info:    "   ",
  success: "✅ ",
  error:   "❌ ",
  warn:    "⚠️  ",
  step:    "▶  ",
}

// ─── FileInputRow ─────────────────────────────────────────────────────────────

interface FileInputRowProps {
  id: string
  label: string
  tag: string
  tagColor: string
  file: File | null
  setFile: (f: File | null) => void
}

function FileInputRow({ id, label, tag, tagColor, file, setFile }: FileInputRowProps) {
  return (
    <div className="flex items-center gap-2 bg-background px-3 py-2.5 rounded-lg border text-xs">
      <FileSpreadsheet className="size-3.5 text-muted-foreground shrink-0" />
      <span className={cn("text-[10px] font-bold px-1.5 py-0.5 rounded shrink-0", tagColor)}>{tag}</span>
      <span className="truncate flex-1 font-medium text-muted-foreground">
        {file ? file.name : <span className="italic">{label}</span>}
      </span>
      {file && (
        <Button variant="ghost" size="icon" className="size-6 shrink-0" onClick={() => setFile(null)}>
          <Trash2 className="size-3 text-destructive/70" />
        </Button>
      )}
      <Button asChild variant="outline" size="sm" className="h-6 text-[10px] px-2 cursor-pointer shrink-0">
        <Label htmlFor={id}>{file ? "Trocar" : "Selecionar"}</Label>
      </Button>
      <Input
        id={id}
        type="file"
        className="hidden"
        accept=".xlsx,.xls"
        onChange={e => {
          if (e.target.files?.[0]) setFile(e.target.files[0])
          e.target.value = ""
        }}
      />
    </div>
  )
}

// ─── ResultViewer ─────────────────────────────────────────────────────────────

function CcoResultViewer({ result }: { result: PipelineResult }) {
  const [activeTab, setActiveTab] = React.useState<"mensal" | "simples" | "diaria">("mensal")

  const analiseDiaria:  any[] = result.analiseDiaria  ?? []
  const resumoMensal:   any[] = result.resumoMensal   ?? []
  const resumoSimples:  any[] = result.resumoSimples  ?? []

  if (!analiseDiaria.length && !resumoMensal.length) return null

  const totalBonificacao = resumoMensal.reduce((a: number, r: any) => a + (r["Total_Bonif_Mes"] ?? 0), 0)
  const totalEmpresas    = resumoMensal.length
  const totalDias        = resumoMensal.reduce((a: number, r: any) => a + (r["Dias_Analisados"] ?? 0), 0)
  const percMedio        = resumoMensal.length > 0
    ? resumoMensal.reduce((a: number, r: any) => a + (r["Perc_Medio_Desempenho"] ?? 0), 0) / resumoMensal.length
    : 0

  const TABS = [
    { id: "mensal",  label: "Resumo Mensal",  count: resumoMensal.length  },
    { id: "simples", label: "Resumo Simples", count: resumoSimples.length },
    { id: "diaria",  label: "Análise Diária", count: analiseDiaria.length },
  ] as const

  // Colunas para cada aba
  const colsMensal  = ["Empresa", "Dias_Analisados", "Perc_Medio_Motorista", "Perc_Medio_Ajudante", "Perc_Medio_Desempenho", "Total_Bonif_Mes"]
  const colsSimples = ["Empresa", "MES", "Bonificacao_Total", "Bonificacao_Atingida"]
  const colsDiaria  = ["Empresa", "Data", "Percentual_Atingido_Motorista", "Percentual_Atingido_Ajudante", "Percentual_Desempenho", "Valor_Bonificacao"]

  const LABEL_MAP: Record<string, string> = {
    Dias_Analisados:               "Dias",
    Perc_Medio_Motorista:          "% Mot",
    Perc_Medio_Ajudante:           "% Ajud",
    Perc_Medio_Desempenho:         "% Desemp",
    Total_Bonif_Mes:               "Bonif Total",
    Bonificacao_Total:             "Bonif Max",
    Bonificacao_Atingida:          "Bonif Atingida",
    Percentual_Atingido_Motorista: "% Mot",
    Percentual_Atingido_Ajudante:  "% Ajud",
    Percentual_Desempenho:         "% Desemp",
    Valor_Bonificacao:             "Bonif (R$)",
    MES:                           "Mês",
  }

  function label(col: string) { return LABEL_MAP[col] ?? col }

  function fmtVal(col: string, val: any) {
    if (val == null || val === "") return <span className="text-muted-foreground/40">—</span>
    if (typeof val === "number") {
      if (col.includes("Perc") || col.includes("perc")) return `${val.toFixed(2)}%`
      if (col.includes("Bonif") || col.includes("Valor")) return `R$ ${val.toFixed(2)}`
      return val.toLocaleString("pt-BR")
    }
    return String(val)
  }

  function rowClass(col: string, val: any): string {
    if (col.includes("Perc") || col.includes("perc")) {
      const n = typeof val === "number" ? val : 0
      if (n >= 90) return "text-emerald-600 font-semibold"
      if (n >= 70) return "text-amber-600"
      if (n < 70 && n > 0) return "text-red-500"
    }
    return ""
  }

  const activeData = activeTab === "mensal"
    ? { rows: resumoMensal, cols: colsMensal.filter(c => resumoMensal[0] && c in resumoMensal[0]) }
    : activeTab === "simples"
    ? { rows: resumoSimples, cols: colsSimples.filter(c => resumoSimples[0] && c in resumoSimples[0]) }
    : { rows: analiseDiaria, cols: colsDiaria.filter(c => analiseDiaria[0] && c in analiseDiaria[0]) }

  return (
    <div className="space-y-4 animate-in fade-in duration-500">
      {/* Stats rápidos */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {[
          { label: "Empresas",          value: totalEmpresas,                       icon: Building2,   highlight: true  },
          { label: "Dias analisados",   value: totalDias,                            icon: CalendarDays,highlight: false },
          { label: "Desempenho médio",  value: `${percMedio.toFixed(2)}%`,           icon: TrendingUp,  highlight: false },
          { label: "Total bonificação", value: `R$ ${totalBonificacao.toFixed(2)}`,  icon: DollarSign,  highlight: true  },
        ].map(stat => {
          const Icon = stat.icon
          return (
            <div key={stat.label} className={cn(
              "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
              stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
            )}>
              <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
              </div>
              <div className="min-w-0">
                <p className={cn("text-sm font-bold leading-tight truncate",
                  stat.highlight ? "text-primary" : "text-foreground")}>
                  {typeof stat.value === "number" ? stat.value.toLocaleString("pt-BR") : stat.value}
                </p>
                <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
              </div>
            </div>
          )
        })}
      </div>

      {/* Tabs */}
      <div className="flex gap-2 flex-wrap">
        {TABS.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={cn(
              "flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold border transition-all",
              activeTab === tab.id
                ? "bg-primary text-primary-foreground border-primary shadow-sm"
                : "bg-card border-border/60 text-muted-foreground hover:bg-muted/30"
            )}
          >
            <BarChart2 className="size-3.5" />
            {tab.label}
            <span className={cn(
              "text-[10px] font-bold px-1.5 py-0.5 rounded-full",
              activeTab === tab.id ? "bg-white/20" : "bg-muted"
            )}>
              {tab.count}
            </span>
          </button>
        ))}
      </div>

      {/* Tabela */}
      {activeData.rows.length > 0 && (
        <div className="rounded-xl border border-border/60 bg-card shadow-sm overflow-hidden">
          <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
            <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
              {TABS.find(t => t.id === activeTab)?.label}
            </span>
            <span className="text-[10px] text-muted-foreground">{activeData.rows.length} registros</span>
          </div>
          <ScrollArea className="h-[460px]">
            <div className="overflow-x-auto">
              <Table>
                <TableHeader className="sticky top-0 bg-muted/80 backdrop-blur-sm z-10">
                  <TableRow>
                    {activeData.cols.map(col => (
                      <TableHead key={col} className="text-[10px] font-bold uppercase whitespace-nowrap px-2 py-2">
                        {label(col)}
                      </TableHead>
                    ))}
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {activeData.rows.map((row, i) => (
                    <TableRow key={i} className="text-xs">
                      {activeData.cols.map(col => (
                        <TableCell
                          key={col}
                          className={cn("px-2 py-1.5 whitespace-nowrap", rowClass(col, row[col]))}
                        >
                          {fmtVal(col, row[col])}
                        </TableCell>
                      ))}
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          </ScrollArea>
        </div>
      )}
    </div>
  )
}

// ─── Componente principal ─────────────────────────────────────────────────────

export function CcoPipelineView() {
  const [year, setYear]   = React.useState(new Date().getFullYear())
  const [month, setMonth] = React.useState(new Date().getMonth() + 1)
  const [fileMotoristas, setFileMotoristas] = React.useState<File | null>(null)
  const [fileAjudantes,  setFileAjudantes]  = React.useState<File | null>(null)
  const [isExecuting, setIsExecuting]       = React.useState(false)
  const [progress, setProgress]             = React.useState(0)
  const [stages, setStages]                 = React.useState<Stage[]>(INITIAL_STAGES)
  const [logs, setLogs]                     = React.useState<LogEntry[]>([])
  const [lastResult, setLastResult]         = React.useState<PipelineResult | null>(null)
  const [stats, setStats]                   = React.useState<{
    empresas: number; dias: number; bonificacao: number; domingoRemovidos: number
  } | null>(null)
  const logEndRef = React.useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  React.useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") => {
    const time = new Date().toLocaleTimeString("pt-BR")
    setLogs(prev => [...prev, { time, message, type }])
  }

  const setStage = (id: string, status: StageStatus) =>
    setStages(prev => prev.map(s => s.id === id ? { ...s, status } : s))

  const resetStages = () => setStages(INITIAL_STAGES.map(s => ({ ...s, status: "idle" })))

  const canRun = !!(fileMotoristas && fileAjudantes)

  const runPipeline = async (downloadOnly = false) => {
    if (!canRun) return
    setIsExecuting(true)
    setProgress(0)
    setLogs([])
    setStats(null)
    resetStages()

    try {
      addLog(`Consolidador CCO iniciado — ${String(month).padStart(2, "0")}/${year}`, "step")
      addLog(`Motoristas: ${fileMotoristas!.name}`)
      addLog(`Ajudantes:  ${fileAjudantes!.name}`)

      // ── Load ──────────────────────────────────────────────────────────
      setStage("load", "running")
      setProgress(10)
      await new Promise(r => setTimeout(r, 200))

      const formData = new FormData()
      formData.append("year",           year.toString())
      formData.append("month",          month.toString())
      formData.append("fileMotoristas", fileMotoristas!)
      formData.append("fileAjudantes",  fileAjudantes!)

      const response = await executeCcoPipeline(formData)
      if (!response?.success) throw new Error(response?.error || "Erro desconhecido no servidor.")

      setStage("load", "done")
      addLog("Arquivos carregados e abas identificadas.", "success")
      setProgress(25)

      // ── Médias diárias ────────────────────────────────────────────────
      addLog("Etapa 1 — Calculando médias diárias por Empresa...", "step")
      setStage("media", "running")
      setProgress(42)
      await new Promise(r => setTimeout(r, 120))
      setStage("media", "done")
      addLog("Médias de Motoristas + Ajudantes calculadas.", "success")
      setProgress(55)

      // ── Domingos ──────────────────────────────────────────────────────
      addLog("Etapa 2 — Removendo domingos da análise...", "step")
      setStage("dom", "running")
      setProgress(63)
      await new Promise(r => setTimeout(r, 100))

      const domingoRemovidos: number = response.result.domingoRemovidos ?? 0
      if (domingoRemovidos > 0) {
        addLog(`${domingoRemovidos} registros de domingo removidos.`, "warn")
        setStage("dom", "warn")
      } else {
        setStage("dom", "done")
        addLog("Nenhum domingo encontrado no período.", "success")
      }
      setProgress(72)

      // ── Bonificação ───────────────────────────────────────────────────
      addLog(`Etapa 3 — Calculando bonificação (R$ ${BONIFICACAO_ROTAS.toFixed(2)}/dia × %)...`, "step")
      setStage("bonus", "running")
      setProgress(80)
      await new Promise(r => setTimeout(r, 100))
      setStage("bonus", "done")
      setProgress(87)

      // ── Resumos ───────────────────────────────────────────────────────
      addLog("Etapa 4 — Gerando resumo mensal e consolidado simples...", "step")
      setStage("resumo", "running")
      setProgress(93)
      await new Promise(r => setTimeout(r, 100))
      setStage("resumo", "done")
      setProgress(96)

      const result = response.result
      setLastResult(result)

      const resumoMensal: any[] = result.resumoMensal ?? []
      const analiseDiaria: any[] = result.analiseDiaria ?? []

      const empresas    = resumoMensal.length
      const diasTotal   = resumoMensal.reduce((a: number, r: any) => a + (r["Dias_Analisados"] ?? 0), 0)
      const bonificacao = resumoMensal.reduce((a: number, r: any) => a + (r["Total_Bonif_Mes"] ?? 0), 0)

      setStats({ empresas, dias: diasTotal, bonificacao, domingoRemovidos })

      addLog(`${empresas} empresas · ${diasTotal} dias · R$ ${bonificacao.toFixed(2)} em bonificações`, "success")

      // ── Export ────────────────────────────────────────────────────────
      setStage("export", "running")
      setProgress(98)

      if (downloadOnly) {
        addLog("Gerando Excel com 4 abas...", "step")
        downloadMultipleSheets(
          [
            { data: analiseDiaria,                       name: "01_Analise_Diaria"            },
            { data: result.analiseDiariaFormatada ?? [], name: "02_Analise_Diaria_Formatada"   },
            { data: resumoMensal,                        name: "03_Resumo_Mensal"              },
            { data: result.resumoSimples ?? [],          name: "04_Resumo_Simples"             },
          ],
          `CCO_Consolidado_${month}_${year}`
        )
        addLog("Arquivo Excel baixado com sucesso.", "success")
      } else {
        addLog("Dados sincronizados com Firebase.", "success")
      }

      setStage("export", "done")
      setProgress(100)
      addLog(`Pipeline concluído em ${new Date().toLocaleTimeString("pt-BR")}.`, "success")

      toast({
        title: downloadOnly ? "Excel pronto" : "Pipeline concluído",
        description: result.summary ?? "",
      })

    } catch (error: any) {
      const msg = error?.message || String(error)
      addLog(`FALHA: ${msg}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro no pipeline CCO", description: msg })
    } finally {
      setIsExecuting(false)
    }
  }

  const doneCount = stages.filter(s => s.status === "done" || s.status === "warn").length
  const hasError  = stages.some(s => s.status === "error")

  return (
    <div className="space-y-6">

      {/* ── Alert informativo ── */}
      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Info className="size-4 text-primary" />
          <AlertTitle className="mb-0">Consolidador CCO — Análise por Empresa</AlertTitle>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="size-4 text-muted-foreground cursor-help" />
              </TooltipTrigger>
              <TooltipContent className="max-w-xs">
                <p>Processa os relatórios ajustados (Motoristas + Ajudantes) e gera a visão de desempenho e bonificação por empresa/dia, removendo domingos.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <AlertDescription className="text-sm mt-2">
          Média de <strong>Motoristas + Ajudantes</strong> por empresa/dia.
          Bonificação de <strong>R$ {BONIFICACAO_ROTAS.toFixed(2)}/dia</strong> × % desempenho. Domingos removidos.
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <BarChart3 className="size-5 text-primary" />
                Configuração do Consolidador CCO
              </CardTitle>
              <CardDescription>Relatórios ajustados gerados pelo pipeline Coordenadores</CardDescription>
            </CardHeader>

            <CardContent className="space-y-6">
              {/* Período */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Ano</Label>
                  <Input type="number" value={year} onChange={e => setYear(parseInt(e.target.value))} />
                </div>
                <div className="space-y-2">
                  <Label>Mês</Label>
                  <Input type="number" min={1} max={12} value={month} onChange={e => setMonth(parseInt(e.target.value))} />
                </div>
              </div>

              <AIParamAssistant onParamsUpdate={(m, y) => { setMonth(m); setYear(y) }} currentMonth={month} currentYear={year} />

              {/* Arquivos */}
              <div className="space-y-3">
                <Label className="text-sm font-semibold text-primary">Arquivos de Entrada</Label>
                <FileInputRow
                  id="cco-motoristas"
                  label="relatorio_consolidado_Motoristas_Ajustado.xlsx"
                  tag="Motoristas"
                  tagColor="bg-primary/10 text-primary"
                  file={fileMotoristas}
                  setFile={setFileMotoristas}
                />
                <FileInputRow
                  id="cco-ajudantes"
                  label="relatorio_consolidado_Ajudantes_Ajustado.xlsx"
                  tag="Ajudantes"
                  tagColor="bg-emerald-100 text-emerald-700"
                  file={fileAjudantes}
                  setFile={setFileAjudantes}
                />
              </div>

              {/* Progresso */}
              {(isExecuting || progress > 0) && (
                <div className="space-y-2 pt-1">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-primary">
                      {hasError ? "Erro na execução" : progress === 100 ? "Concluído" : "Processando..."}
                    </span>
                    <span className="text-[10px] font-mono font-bold text-muted-foreground">{progress}%</span>
                  </div>
                  <Progress
                    value={progress}
                    className={cn("h-2 transition-all", hasError && "[&>div]:bg-destructive")}
                  />
                  <div className="flex justify-between text-[9px] text-muted-foreground">
                    <span>{doneCount}/{stages.length} etapas</span>
                    <span>
                      {isExecuting
                        ? stages.find(s => s.status === "running")?.label ?? "..."
                        : progress === 100 ? "Pipeline finalizado" : ""}
                    </span>
                  </div>
                </div>
              )}
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button
                variant="outline"
                size="sm"
                className="flex-1 h-9 text-xs font-semibold border-slate-300 text-slate-600 hover:bg-slate-50 hover:text-slate-800 hover:border-slate-400 transition-all"
                onClick={() => runPipeline(true)}
                disabled={isExecuting || !canRun}
              >
                <Download className="mr-1.5 size-3.5" /> Exportar Excel
              </Button>
              <Button
                size="sm"
                className="flex-1 h-9 text-xs font-semibold bg-primary hover:bg-primary/90 shadow-sm transition-all"
                onClick={() => runPipeline(false)}
                disabled={isExecuting || !canRun}
              >
                {isExecuting
                  ? <><Loader2 className="mr-1.5 size-3.5 animate-spin" /> Processando...</>
                  : <><Play className="mr-1.5 size-3.5 fill-current" /> Executar Pipeline</>}
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">

          {/* Etapas */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Etapas de Execução
              </span>
            </div>
            <div className="p-3 space-y-2">
              {stages.map((stage, idx) => (
                <div key={stage.id} className="flex items-start gap-2">
                  <div className="flex flex-col items-center pt-0.5">
                    <StageIcon status={stage.status} />
                    {idx < stages.length - 1 && (
                      <div className={cn(
                        "w-px mt-1 min-h-[14px]",
                        stage.status === "done" ? "bg-emerald-300" : "bg-border/60"
                      )} />
                    )}
                  </div>
                  <div className={cn("flex-1 px-2.5 py-1.5 rounded-lg border text-xs transition-all", stageBg[stage.status])}>
                    <p className={cn("leading-tight", stageLabel[stage.status])}>{stage.label}</p>
                    <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{stage.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Stats pós-execução */}
          {stats && (
            <div className="grid grid-cols-2 gap-2">
              {[
                { label: "Empresas",          value: stats.empresas,                           icon: Building2,    highlight: true  },
                { label: "Dias analisados",   value: stats.dias,                               icon: CalendarDays, highlight: false },
                { label: "Domingos removidos",value: stats.domingoRemovidos,                   icon: AlertTriangle,highlight: false },
                { label: "Total bonificação", value: `R$ ${stats.bonificacao.toFixed(2)}`,     icon: TrendingUp,   highlight: true  },
              ].map(stat => {
                const Icon = stat.icon
                return (
                  <div key={stat.label} className={cn(
                    "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                    stat.label === "Total bonificação" && "col-span-2",
                    stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                  )}>
                    <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                      stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                      <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                    </div>
                    <div className="min-w-0">
                      <p className={cn("text-sm font-bold leading-tight truncate",
                        stat.highlight ? "text-primary" : "text-foreground")}>
                        {typeof stat.value === "number" ? stat.value.toLocaleString("pt-BR") : stat.value}
                      </p>
                      <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          {/* Regras */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Regras de Cálculo
              </span>
            </div>
            <div className="p-3 space-y-1.5">
              {REGRAS_CCO.map((rule, idx) => (
                <div key={idx} className={cn(
                  "flex items-start gap-2 rounded-lg border px-2.5 py-2 text-[11px]",
                  ruleColor[rule.variant]
                )}>
                  <ChevronRight className="size-3 mt-0.5 shrink-0 opacity-60" />
                  <div>
                    <span className="font-semibold">{rule.condition}</span>
                    <span className="mx-1 opacity-50">→</span>
                    <span>{rule.result}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[200px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0
                  ? <span className="text-slate-500 italic">Aguardando execução...</span>
                  : logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))
                }
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>

        </div>
      </div>

      {lastResult && !isExecuting && <CcoResultViewer result={lastResult} />}
    </div>
  )
}

"use client";

import {
  useState,
  useMemo,
  useCallback,
  useRef,
  ChangeEvent,
  FC,
  JSX,
} from "react";
import * as XLSX from "xlsx";
import {
