// ─── Tipos ────────────────────────────────────────────────────────────────────

type StageStatus = "idle" | "running" | "done" | "error" | "warn"

interface Stage {
  id: string
  label: string
  description: string
  status: StageStatus
}

interface LogEntry {
  time: string
  message: string
  type: "info" | "success" | "error" | "warn" | "step"
}

// ─── Constantes de negócio ────────────────────────────────────────────────────

const PERCENTUAL_MAXIMO_DEVOLUCAO = 15.0
const BONIFICACAO_MAXIMA_MOTORISTA = 16.0
const BONIFICACAO_MAXIMA_AJUDANTE  = 12.0

const REGRAS_NEGOCIO = [
  {
    condition: "% Devolvido ≥ 15% no dia",
    result: "R$ 0,00 — ZERA todas as bonificações do dia",
    variant: "danger" as const,
  },
  {
    condition: "Motorista (máx/dia)",
    result: "R$ 8,00 (Perf) + R$ 3,20 (Ponto) + R$ 4,80 (Condução) = R$ 16,00",
    variant: "info" as const,
  },
  {
    condition: "Ajudante (máx/dia)",
    result: "R$ 7,20 (Perf) + R$ 4,80 (Ponto) = R$ 12,00",
    variant: "success" as const,
  },
]

// ─── Etapas ───────────────────────────────────────────────────────────────────

const INITIAL_STAGES: Stage[] = [
  { id: "load",     label: "Carregar arquivos",            description: "Motoristas Ajustado + Ajudantes Ajustado", status: "idle" },
  { id: "merge",    label: "Etapa 1 — Merge das fontes",   description: "Performance + Ponto + Condução por colaborador/dia", status: "idle" },
  { id: "penalty",  label: "Etapa 2 — Regra de devolução", description: "≥ 15% devolvido → zera bonificação do dia", status: "idle" },
  { id: "totals",   label: "Etapa 3 — Cálculo de totais",  description: "Bonificação diária + acumulada + % atingido", status: "idle" },
  { id: "enrich",   label: "Etapa 4 — Enriquecimento",     description: "Empresa · Cargo · filtro por função",       status: "idle" },
  { id: "export",   label: "Exportar / Salvar Firebase",   description: "Motoristas Ajustado + Ajudantes Ajustado", status: "idle" },
]

// ─── Helpers visuais ──────────────────────────────────────────────────────────

function StageIcon({ status }: { status: StageStatus }) {
  if (status === "running") return <Loader2 className="size-4 animate-spin text-primary shrink-0" />
  if (status === "done")    return <CheckCircle2 className="size-4 text-emerald-500 shrink-0" />
  if (status === "error")   return <XCircle className="size-4 text-destructive shrink-0" />
  if (status === "warn")    return <AlertTriangle className="size-4 text-amber-500 shrink-0" />
  return <Circle className="size-4 text-muted-foreground/30 shrink-0" />
}

const stageBg: Record<StageStatus, string> = {
  idle:    "bg-muted/20 border-border/40",
  running: "bg-primary/5 border-primary/30",
  done:    "bg-emerald-50 border-emerald-200",
  error:   "bg-red-50 border-red-200",
  warn:    "bg-amber-50 border-amber-200",
}

const stageLabel: Record<StageStatus, string> = {
  idle:    "text-muted-foreground",
  running: "text-primary font-semibold",
  done:    "text-emerald-700 font-medium",
  error:   "text-red-700 font-semibold",
  warn:    "text-amber-700 font-medium",
}

const ruleColor = {
  success: "border-emerald-200 bg-emerald-50 text-emerald-700",
  danger:  "border-red-200 bg-red-50 text-red-700",
  warn:    "border-amber-200 bg-amber-50 text-amber-700",
  info:    "border-blue-200 bg-blue-50 text-blue-700",
}

const logColor: Record<LogEntry["type"], string> = {
  info:    "text-slate-400",
  success: "text-emerald-500",
  error:   "text-red-400 font-semibold",
  warn:    "text-amber-400",
  step:    "text-primary font-semibold",
}

const logPrefix: Record<LogEntry["type"], string> = {
  info:    "   ",
  success: "✅ ",
  error:   "❌ ",
  warn:    "⚠️  ",
  step:    "▶  ",
}

// ─── FileInputRow ─────────────────────────────────────────────────────────────

interface FileInputRowProps {
  id: string
  label: string
  tag: string
  tagColor: string
  file: File | null
  setFile: (f: File | null) => void
}

function FileInputRow({ id, label, tag, tagColor, file, setFile }: FileInputRowProps) {
  return (
    <div className="flex items-center gap-2 bg-background px-3 py-2.5 rounded-lg border text-xs">
      <FileSpreadsheet className="size-3.5 text-muted-foreground shrink-0" />
      <span className={cn("text-[10px] font-bold px-1.5 py-0.5 rounded shrink-0", tagColor)}>{tag}</span>
      <span className="truncate flex-1 font-medium text-muted-foreground">
        {file ? file.name : <span className="italic">{label}</span>}
      </span>
      {file && (
        <Button variant="ghost" size="icon" className="size-6 shrink-0" onClick={() => setFile(null)}>
          <Trash2 className="size-3 text-destructive/70" />
        </Button>
      )}
      <Button asChild variant="outline" size="sm" className="h-6 text-[10px] px-2 cursor-pointer shrink-0">
        <Label htmlFor={id}>{file ? "Trocar" : "Selecionar"}</Label>
      </Button>
      <Input
        id={id}
        type="file"
        className="hidden"
        accept=".xlsx,.xls"
        onChange={e => {
          if (e.target.files?.[0]) setFile(e.target.files[0])
          e.target.value = ""
        }}
      />
    </div>
  )
}

// ─── ResultViewer ─────────────────────────────────────────────────────────────

function CoordenadorResultViewer({ result }: { result: PipelineResult }) {
  const [activeTab, setActiveTab] = React.useState<"motoristas" | "ajudantes">("motoristas")

  const motoristas: any[] = result.motoristas ?? []
  const ajudantes:  any[] = result.ajudantes  ?? []
  const erros:      any[] = result.erros       ?? []

  const statsMotoristas = React.useMemo(() => {
    if (!motoristas.length) return null
    const penalizados = motoristas.filter(r => r["PESO_Penalizado"]).length
    const bonTotal    = motoristas.reduce((a, r) => a + (r["Bonificacao_Diaria_Total"] ?? 0), 0)
    const unicos      = new Set(motoristas.map(r => r["Motorista"])).size
    return { penalizados, bonTotal, unicos, dias: motoristas.length }
  }, [motoristas])

  const statsAjudantes = React.useMemo(() => {
    if (!ajudantes.length) return null
    const penalizados = ajudantes.filter(r => r["PESO_Penalizado"]).length
    const bonTotal    = ajudantes.reduce((a, r) => a + (r["Bonificacao_Diaria_Total"] ?? 0), 0)
    const unicos      = new Set(ajudantes.map(r => r["Ajudante"])).size
    return { penalizados, bonTotal, unicos, dias: ajudantes.length }
  }, [ajudantes])

  const activeData  = activeTab === "motoristas" ? motoristas : ajudantes
  const activeStats = activeTab === "motoristas" ? statsMotoristas : statsAjudantes
  const colName     = activeTab === "motoristas" ? "Motorista" : "Ajudante"
  const maxBonus    = activeTab === "motoristas" ? BONIFICACAO_MAXIMA_MOTORISTA : BONIFICACAO_MAXIMA_AJUDANTE

  if (!motoristas.length && !ajudantes.length) return null

  // Colunas da tabela: fixas + dinâmicas
  const COLS_ALWAYS = [colName, "Dia", "Empresa", "Cargo"]
  const COLS_BONUS  = ["PERF_Bonificacao", "TOTAL_Ponto_Bonificacao", "COND_Bonificacao",
                       "Bonificacao_Diaria_Total", "Percentual_Atingido"]
  const COLS_PESO   = ["PESO_Percentual_Devolvido", "PESO_Penalizado"]
  const COLS_STATUS = ["PERF_Raio_100m", "PERF_SLA_Janela", "PERF_Tempo_Min", "PERF_Sequenciamento",
                       "PONTO_Todas_Batidas", "JORNADA_Intrajornada", "JORNADA_Interjornada", "JORNADA_DSR",
                       "COND_Curva_Brusca", "COND_Banguela", "COND_Ociosidade", "COND_Excesso_Velocidade"]

  const allKeys   = activeData.length > 0 ? Object.keys(activeData[0]) : []
  const dynCols   = [...COLS_PESO, ...COLS_STATUS, ...COLS_BONUS].filter(c => allKeys.includes(c))
  const tableCols = [...COLS_ALWAYS.filter(c => allKeys.includes(c)), ...dynCols]

  function cellClass(col: string, value: any) {
    if (col === "PESO_Penalizado") return value ? "text-red-600 font-bold" : "text-emerald-600"
    if (typeof value === "string") {
      if (value === "OK")    return "text-emerald-600 font-semibold"
      if (value === "FALHA") return "text-red-500 font-semibold"
    }
    return ""
  }

  function formatValue(col: string, value: any) {
    if (value == null || value === "") return <span className="text-muted-foreground/40">—</span>
    if (col === "PESO_Penalizado")  return value ? "⛔ SIM" : "✓ NÃO"
    if (typeof value === "number" && (col.includes("Bonif") || col.includes("Bonus") || col.includes("Total"))) {
      return `R$ ${value.toFixed(2)}`
    }
    if (col === "Dia" && value) return String(value)
    return String(value)
  }

  function labelCol(col: string) {
    const map: Record<string, string> = {
      PERF_Raio_100m: "Raio", PERF_SLA_Janela: "SLA", PERF_Tempo_Min: "Tempo Min",
      PERF_Sequenciamento: "Seq", PERF_Bonificacao: "Perf (R$)",
      PONTO_Todas_Batidas: "Batidas", JORNADA_Intrajornada: "Intrajorn",
      JORNADA_Interjornada: "Interjorn", JORNADA_DSR: "DSR",
      TOTAL_Ponto_Bonificacao: "Ponto (R$)",
      COND_Curva_Brusca: "Curva", COND_Banguela: "Banguela",
      COND_Ociosidade: "Ociosidade", COND_Excesso_Velocidade: "Velocidade",
      COND_Bonificacao: "Cond (R$)",
      PESO_Percentual_Devolvido: "% Dev", PESO_Penalizado: "Penalizado",
      Bonificacao_Diaria_Total: "Total (R$)", Percentual_Atingido: "% Atingido",
    }
    return map[col] ?? col
  }

  return (
    <div className="space-y-4 animate-in fade-in duration-500">
      {erros.length > 0 && (
        <Alert variant="destructive">
          <AlertTriangle className="size-4" />
          <AlertTitle>Erros de Processamento ({erros.length})</AlertTitle>
          <AlertDescription className="text-xs mt-1">
            {erros.slice(0, 3).map((e: any, i: number) => <div key={i}>{e.erro ?? String(e)}</div>)}
            {erros.length > 3 && <div>+{erros.length - 3} mais...</div>}
          </AlertDescription>
        </Alert>
      )}

      {/* Tabs */}
      <div className="flex gap-2">
        {(["motoristas", "ajudantes"] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={cn(
              "flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold border transition-all",
              activeTab === tab
                ? "bg-primary text-primary-foreground border-primary shadow-sm"
                : "bg-card border-border/60 text-muted-foreground hover:bg-muted/30"
            )}
          >
            <Users className="size-3.5" />
            {tab === "motoristas" ? "Motoristas" : "Ajudantes"}
            <span className={cn(
              "text-[10px] font-bold px-1.5 py-0.5 rounded-full",
              activeTab === tab ? "bg-white/20" : "bg-muted"
            )}>
              {tab === "motoristas" ? new Set(motoristas.map(r => r["Motorista"])).size : new Set(ajudantes.map(r => r["Ajudante"])).size}
            </span>
          </button>
        ))}
      </div>

      {/* Stats do grupo ativo */}
      {activeStats && (
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {[
            { label: `${colName}s únicos`,   value: activeStats.unicos,                            icon: Users,        highlight: true  },
            { label: "Dias analisados",       value: activeStats.dias,                              icon: CalendarDays, highlight: false },
            { label: "Total bonificação",     value: `R$ ${activeStats.bonTotal.toFixed(2)}`,       icon: DollarSign,   highlight: true  },
            { label: "Dias penalizados",      value: activeStats.penalizados,                       icon: AlertTriangle,highlight: false },
          ].map(stat => {
            const Icon = stat.icon
            return (
              <div key={stat.label} className={cn(
                "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
              )}>
                <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                  stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                  <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                </div>
                <div className="min-w-0">
                  <p className={cn("text-sm font-bold leading-tight truncate",
                    stat.highlight ? "text-primary" : "text-foreground")}>
                    {typeof stat.value === "number" ? stat.value.toLocaleString("pt-BR") : stat.value}
                  </p>
                  <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                </div>
              </div>
            )
          })}
        </div>
      )}

      {/* Tabela detalhada */}
      {activeData.length > 0 && (
        <div className="rounded-xl border border-border/60 bg-card shadow-sm overflow-hidden">
          <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
            <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
              Relatório Diário — {activeTab === "motoristas" ? "Motoristas" : "Ajudantes"}
            </span>
            <span className="text-[10px] text-muted-foreground">{activeData.length} registros</span>
          </div>
          <ScrollArea className="h-[480px]">
            <div className="overflow-x-auto">
              <Table>
                <TableHeader className="sticky top-0 bg-muted/80 backdrop-blur-sm z-10">
                  <TableRow>
                    {tableCols.map(col => (
                      <TableHead key={col} className="text-[10px] font-bold uppercase whitespace-nowrap px-2 py-2">
                        {labelCol(col)}
                      </TableHead>
                    ))}
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {activeData.map((row, i) => (
                    <TableRow key={i} className={cn(
                      "text-xs",
                      row["PESO_Penalizado"] && "bg-red-50/50"
                    )}>
                      {tableCols.map(col => (
                        <TableCell
                          key={col}
                          className={cn("px-2 py-1.5 whitespace-nowrap", cellClass(col, row[col]))}
                        >
                          {formatValue(col, row[col])}
                        </TableCell>
                      ))}
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          </ScrollArea>
        </div>
      )}
    </div>
  )
}

// ─── Componente principal ─────────────────────────────────────────────────────

export function CoordenadorPipelineView() {
  const [year, setYear]     = React.useState(new Date().getFullYear())
  const [month, setMonth]   = React.useState(new Date().getMonth() + 1)
  const [fileMotoristas, setFileMotoristas] = React.useState<File | null>(null)
  const [fileAjudantes,  setFileAjudantes]  = React.useState<File | null>(null)
  const [isExecuting, setIsExecuting]       = React.useState(false)
  const [progress, setProgress]             = React.useState(0)
  const [stages, setStages]                 = React.useState<Stage[]>(INITIAL_STAGES)
  const [logs, setLogs]                     = React.useState<LogEntry[]>([])
  const [lastResult, setLastResult]         = React.useState<PipelineResult | null>(null)
  const [stats, setStats]                   = React.useState<{
    motoristas: number; ajudantes: number; bonTotal: number
  } | null>(null)
  const logEndRef = React.useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  React.useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") => {
    const time = new Date().toLocaleTimeString("pt-BR")
    setLogs(prev => [...prev, { time, message, type }])
  }

  const setStage = (id: string, status: StageStatus) =>
    setStages(prev => prev.map(s => s.id === id ? { ...s, status } : s))

  const resetStages = () => setStages(INITIAL_STAGES.map(s => ({ ...s, status: "idle" })))

  const canRun = !!(fileMotoristas && fileAjudantes)

  const runPipeline = async (downloadOnly = false) => {
    if (!canRun) return
    setIsExecuting(true)
    setProgress(0)
    setLogs([])
    setStats(null)
    resetStages()

    try {
      addLog(`Pipeline Coordenadores iniciado — ${String(month).padStart(2, "0")}/${year}`, "step")
      addLog(`Motoristas: ${fileMotoristas!.name}`)
      addLog(`Ajudantes:  ${fileAjudantes!.name}`)

      // ── Etapa Load ────────────────────────────────────────────────────
      setStage("load", "running")
      setProgress(10)
      await new Promise(r => setTimeout(r, 200))
      setStage("load", "done")
      addLog("Arquivos carregados com sucesso.", "success")
      setProgress(20)

      // ── Etapa Merge ───────────────────────────────────────────────────
      addLog("Etapa 1 — Merge das fontes por Colaborador + Dia...", "step")
      setStage("merge", "running")
      setProgress(30)

      const formData = new FormData()
      formData.append("year",           year.toString())
      formData.append("month",          month.toString())
      formData.append("fileMotoristas", fileMotoristas!)
      formData.append("fileAjudantes",  fileAjudantes!)

      const response = await executeCoordenadorPipeline(formData)

      if (!response?.success) throw new Error(response?.error || "Erro desconhecido no servidor.")

      setStage("merge", "done")
      addLog("Fontes mescladas: Performance + Ponto + Condução.", "success")
      setProgress(50)

      // ── Etapa Penalização ─────────────────────────────────────────────
      addLog("Etapa 2 — Aplicando regra de devolução (≥ 15%)...", "step")
      setStage("penalty", "running")
      setProgress(62)
      await new Promise(r => setTimeout(r, 120))
      setStage("penalty", "done")
      setProgress(70)

      // ── Etapa Totais ──────────────────────────────────────────────────
      addLog("Etapa 3 — Calculando bonificação diária e acumulada...", "step")
      setStage("totals", "running")
      setProgress(78)
      await new Promise(r => setTimeout(r, 100))
      setStage("totals", "done")
      setProgress(84)

      // ── Etapa Enriquecimento ──────────────────────────────────────────
      addLog("Etapa 4 — Enriquecendo com Empresa e Cargo...", "step")
      setStage("enrich", "running")
      setProgress(90)
      await new Promise(r => setTimeout(r, 100))
      setStage("enrich", "done")
      setProgress(95)

      const result = response.result
      setLastResult(result)

      const motoristas: any[] = result.motoristas ?? []
      const ajudantes:  any[] = result.ajudantes  ?? []
      const bonMotor = motoristas.reduce((a: number, r: any) => a + (r["Bonificacao_Diaria_Total"] ?? 0), 0)
      const bonAjud  = ajudantes.reduce((a: number, r: any)  => a + (r["Bonificacao_Diaria_Total"] ?? 0), 0)

      setStats({
        motoristas: new Set(motoristas.map((r: any) => r["Motorista"])).size,
        ajudantes:  new Set(ajudantes.map((r: any)  => r["Ajudante"])).size,
        bonTotal:   bonMotor + bonAjud,
      })

      addLog(`${new Set(motoristas.map((r: any) => r["Motorista"])).size} motoristas · R$ ${bonMotor.toFixed(2)} em bonificações`, "success")
      addLog(`${new Set(ajudantes.map((r: any) => r["Ajudante"])).size} ajudantes · R$ ${bonAjud.toFixed(2)} em bonificações`, "success")

      // ── Exportar ──────────────────────────────────────────────────────
      setStage("export", "running")
      setProgress(98)

      if (downloadOnly) {
        addLog("Gerando Excel com múltiplas abas...", "step")
        downloadMultipleSheets(
          [
            { data: motoristas, name: "Motoristas_Ajustado" },
            { data: ajudantes,  name: "Ajudantes_Ajustado"  },
          ],
          `Coordenadores_Consolidado_${month}_${year}`
        )
        addLog("Arquivo Excel baixado com sucesso.", "success")
      } else {
        addLog("Dados sincronizados com Firebase.", "success")
      }

      setStage("export", "done")
      setProgress(100)
      addLog(`Pipeline concluído em ${new Date().toLocaleTimeString("pt-BR")}.`, "success")

      toast({
        title: downloadOnly ? "Excel pronto" : "Pipeline concluído",
        description: result.summary ?? "",
      })

    } catch (error: any) {
      const msg = error?.message || String(error)
      addLog(`FALHA: ${msg}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro no pipeline", description: msg })
    } finally {
      setIsExecuting(false)
    }
  }

  const doneCount = stages.filter(s => s.status === "done" || s.status === "warn").length
  const hasError  = stages.some(s => s.status === "error")

  return (
    <div className="space-y-6">

      {/* ── Alert informativo ── */}
      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Info className="size-4 text-primary" />
          <AlertTitle className="mb-0">Consolidador Final — Motoristas & Ajudantes</AlertTitle>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="size-4 text-muted-foreground cursor-help" />
              </TooltipTrigger>
              <TooltipContent className="max-w-xs">
                <p>Processa os relatórios ajustados gerados pelos pipelines anteriores e gera a visão consolidada com Empresa, Cargo e bonificação total.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <AlertDescription className="text-sm mt-2">
          Consolida <strong>Performance + Ponto + Condução</strong> por colaborador/dia.
          Penaliza dias com devolução ≥ {PERCENTUAL_MAXIMO_DEVOLUCAO}%.
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Building2 className="size-5 text-primary" />
                Configuração do Consolidador
              </CardTitle>
              <CardDescription>Relatórios gerados pelos pipelines de Performance, Ponto e Condução</CardDescription>
            </CardHeader>

            <CardContent className="space-y-6">
              {/* Período */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Ano</Label>
                  <Input type="number" value={year} onChange={e => setYear(parseInt(e.target.value))} />
                </div>
                <div className="space-y-2">
                  <Label>Mês</Label>
                  <Input type="number" min={1} max={12} value={month} onChange={e => setMonth(parseInt(e.target.value))} />
                </div>
              </div>

              <AIParamAssistant onParamsUpdate={(m, y) => { setMonth(m); setYear(y) }} currentMonth={month} currentYear={year} />

              {/* Arquivos */}
              <div className="space-y-3">
                <Label className="text-sm font-semibold text-primary">Arquivos de Entrada</Label>
                <FileInputRow
                  id="file-motoristas"
                  label="Motoristas_Ajustado.xlsx (gerado pelo pipeline anterior)"
                  tag="Motoristas"
                  tagColor="bg-primary/10 text-primary"
                  file={fileMotoristas}
                  setFile={setFileMotoristas}
                />
                <FileInputRow
                  id="file-ajudantes"
                  label="Ajudantes_Ajustado.xlsx (gerado pelo pipeline anterior)"
                  tag="Ajudantes"
                  tagColor="bg-emerald-100 text-emerald-700"
                  file={fileAjudantes}
                  setFile={setFileAjudantes}
                />
              </div>

              {/* Barra de progresso */}
              {(isExecuting || progress > 0) && (
                <div className="space-y-2 pt-1">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-primary">
                      {hasError ? "Erro na execução" : progress === 100 ? "Concluído" : "Processando..."}
                    </span>
                    <span className="text-[10px] font-mono font-bold text-muted-foreground">{progress}%</span>
                  </div>
                  <Progress
                    value={progress}
                    className={cn("h-2 transition-all", hasError && "[&>div]:bg-destructive")}
                  />
                  <div className="flex justify-between text-[9px] text-muted-foreground">
                    <span>{doneCount}/{stages.length} etapas</span>
                    <span>
                      {isExecuting
                        ? stages.find(s => s.status === "running")?.label ?? "..."
                        : progress === 100 ? "Pipeline finalizado" : ""}
                    </span>
                  </div>
                </div>
              )}
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button
                variant="outline"
                size="sm"
                className="flex-1 h-9 text-xs font-semibold border-slate-300 text-slate-600 hover:bg-slate-50 hover:text-slate-800 hover:border-slate-400 transition-all"
                onClick={() => runPipeline(true)}
                disabled={isExecuting || !canRun}
              >
                <Download className="mr-1.5 size-3.5" /> Exportar Excel
              </Button>
              <Button
                size="sm"
                className="flex-1 h-9 text-xs font-semibold bg-primary hover:bg-primary/90 shadow-sm transition-all"
                onClick={() => runPipeline(false)}
                disabled={isExecuting || !canRun}
              >
                {isExecuting
                  ? <><Loader2 className="mr-1.5 size-3.5 animate-spin" /> Processando...</>
                  : <><Play className="mr-1.5 size-3.5 fill-current" /> Executar Pipeline</>}
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">

          {/* Etapas */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Etapas de Execução
              </span>
            </div>
            <div className="p-3 space-y-2">
              {stages.map((stage, idx) => (
                <div key={stage.id} className="flex items-start gap-2">
                  <div className="flex flex-col items-center pt-0.5">
                    <StageIcon status={stage.status} />
                    {idx < stages.length - 1 && (
                      <div className={cn(
                        "w-px mt-1 min-h-[14px]",
                        stage.status === "done" ? "bg-emerald-300" : "bg-border/60"
                      )} />
                    )}
                  </div>
                  <div className={cn("flex-1 px-2.5 py-1.5 rounded-lg border text-xs transition-all", stageBg[stage.status])}>
                    <p className={cn("leading-tight", stageLabel[stage.status])}>{stage.label}</p>
                    <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{stage.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Stats (só aparecem após execução) */}
          {stats && (
            <div className="grid grid-cols-2 gap-2">
              {[
                { label: "Motoristas",        value: stats.motoristas, icon: Users,      highlight: true  },
                { label: "Ajudantes",          value: stats.ajudantes,  icon: Users,      highlight: false },
                { label: "Total bonificação",  value: `R$ ${stats.bonTotal.toFixed(2)}`, icon: TrendingUp, highlight: true  },
              ].map(stat => {
                const Icon = stat.icon
                return (
                  <div key={stat.label} className={cn(
                    "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm col-span-1",
                    stat.label === "Total bonificação" && "col-span-2",
                    stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                  )}>
                    <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                      stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                      <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                    </div>
                    <div className="min-w-0">
                      <p className={cn("text-sm font-bold leading-tight truncate",
                        stat.highlight ? "text-primary" : "text-foreground")}>
                        {typeof stat.value === "number" ? stat.value.toLocaleString("pt-BR") : stat.value}
                      </p>
                      <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          {/* Regras de negócio */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Regras de Bonificação
              </span>
            </div>
            <div className="p-3 space-y-1.5">
              {REGRAS_NEGOCIO.map((rule, idx) => (
                <div key={idx} className={cn(
                  "flex items-start gap-2 rounded-lg border px-2.5 py-2 text-[11px]",
                  ruleColor[rule.variant]
                )}>
                  <ChevronRight className="size-3 mt-0.5 shrink-0 opacity-60" />
                  <div>
                    <span className="font-semibold">{rule.condition}</span>
                    <span className="mx-1 opacity-50">→</span>
                    <span>{rule.result}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                  Console
                </span>
              </div>
              {logs.length > 0 && (
                <button
                  onClick={() => setLogs([])}
                  className="text-[9px] text-muted-foreground hover:text-foreground transition-colors"
                >
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[220px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0 ? (
                  <span className="text-slate-500 italic">Aguardando execução...</span>
                ) : (
                  logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))
                )}
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>

        </div>
      </div>

      {lastResult && !isExecuting && <CoordenadorResultViewer result={lastResult} />}
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Play, Trash2, FileCode, Loader2, HelpCircle,
  Download, CheckCircle2, Circle, XCircle, AlertTriangle,
  ChevronRight, Terminal, Info, Database,
  PackageX, FileSpreadsheet, Users,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Input } from "@/components/ui/input"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Progress } from "@/components/ui/progress"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { AIParamAssistant } from "../../pages/AI-Param-Assistant"
import { executeDevolucoesPipeline } from "@/app/actions/import-devolucoes-actions"
import { useToast } from "@/hooks/use-toast"
import { PipelineResult } from "@/lib/firebase"
import { downloadMultipleSheets } from "@/lib/excel-utils"
import { cn } from "@/lib/utils"

// ─── Tipos ────────────────────────────────────────────────────────────────────
type StageStatus = "idle" | "running" | "done" | "error" | "warn"
interface Stage { id: string; label: string; description: string; status: StageStatus }
interface LogEntry { time: string; message: string; type: "info" | "success" | "error" | "warn" | "step" }

// ─── Arquivos necessários ─────────────────────────────────────────────────────
const FILE_SLOTS = [
  { id: "controle",    label: "Controle Logístico",      hint: "Consolidado_Entregas_V2_Geral.xlsx",  required: true  },
  { id: "faturamento", label: "Faturamento",              hint: "Fat_Fechamento.xlsx",                 required: true  },
  { id: "funcionarios",label: "Cadastro de Funcionários", hint: "Funcionario.xlsx",                    required: false },
  { id: "motivos",     label: "Motivos do Sistema",       hint: "Motivos Sistema.xlsx",                required: false },
]

// ─── Etapas ───────────────────────────────────────────────────────────────────
const INITIAL_STAGES: Stage[] = [
  { id: "load",    label: "Carregar arquivos",          description: "Controle logístico · faturamento · funcionários",     status: "idle" },
  { id: "filter",  label: "Filtrar por ano/mês",        description: "Stream — somente registros do período",               status: "idle" },
  { id: "names",   label: "Normalizar nomes",           description: "Fuzzy match contra cadastro de funcionários",         status: "idle" },
  { id: "explode", label: "Explodir viagens",           description: "Colaborador × viagem (VIAGEM pode ter múltiplos IDs)", status: "idle" },
  { id: "fat",     label: "Agregar faturamento",        description: "Por viagem · excluindo motivos do sistema",           status: "idle" },
  { id: "merge",   label: "Merge + Percentuais",        description: "Colaborador × faturamento · % devolvido",             status: "idle" },
  { id: "export",  label: "Exportar / Salvar Firebase", description: "Resumo por colaborador + Detalhamento",               status: "idle" },
]

const REGRAS = [
  { condition: "FATURAMENTO_DEV > 0",   result: "Identificada como devolução",          variant: "warn"    as const },
  { condition: "Motivo do sistema",      result: "Excluída — não culpa do motorista",    variant: "info"    as const },
  { condition: "Sem Motivos Sistema.xlsx", result: "Todas dev. desconsideradas (padrão)", variant: "info"  as const },
  { condition: "Zeros à esquerda VIAGEM", result: "Normalizados antes do merge",         variant: "info"   as const },
  { condition: "Colaborador com fat. 0", result: "Incluído no detalhamento",             variant: "warn"   as const },
]

// ─── Sub-componentes ──────────────────────────────────────────────────────────
function StageIcon({ status }: { status: StageStatus }) {
  if (status === "running") return <Loader2 className="size-4 animate-spin text-primary shrink-0" />
  if (status === "done")    return <CheckCircle2 className="size-4 text-emerald-500 shrink-0" />
  if (status === "error")   return <XCircle className="size-4 text-destructive shrink-0" />
  if (status === "warn")    return <AlertTriangle className="size-4 text-amber-500 shrink-0" />
  return <Circle className="size-4 text-muted-foreground/30 shrink-0" />
}
const stageBg: Record<StageStatus, string> = {
  idle: "bg-muted/20 border-border/40", running: "bg-primary/5 border-primary/30",
  done: "bg-emerald-50 border-emerald-200", error: "bg-red-50 border-red-200", warn: "bg-amber-50 border-amber-200",
}
const stageLbl: Record<StageStatus, string> = {
  idle: "text-muted-foreground", running: "text-primary font-semibold",
  done: "text-emerald-700 font-medium", error: "text-red-700 font-semibold", warn: "text-amber-700 font-medium",
}
const ruleColor = {
  success: "border-emerald-200 bg-emerald-50 text-emerald-700",
  danger:  "border-red-200 bg-red-50 text-red-700",
  warn:    "border-amber-200 bg-amber-50 text-amber-700",
  info:    "border-blue-200 bg-blue-50 text-blue-700",
}
const logColor: Record<LogEntry["type"], string> = {
  info: "text-slate-400", success: "text-emerald-400",
  error: "text-red-400 font-semibold", warn: "text-amber-400", step: "text-primary font-semibold",
}
const logPrefix: Record<LogEntry["type"], string> = {
  info: "   ", success: "✅ ", error: "❌ ", warn: "⚠️  ", step: "▶  ",
}

// ─── Componente principal ─────────────────────────────────────────────────────
export function DevolucoesPipelineView() {
  const [year, setYear]   = React.useState(new Date().getFullYear())
  const [month, setMonth] = React.useState(new Date().getMonth() + 1)
  const [files, setFiles] = React.useState<Record<string, File | null>>({})
  const [isExecuting, setIsExecuting] = React.useState(false)
  const [progress, setProgress]       = React.useState(0)
  const [stages, setStages]           = React.useState<Stage[]>(INITIAL_STAGES)
  const [logs, setLogs]               = React.useState<LogEntry[]>([])
  const [lastResult, setLastResult]   = React.useState<PipelineResult | null>(null)
  const [stats, setStats]             = React.useState<{
    colaboradores: number; viagens: number; fatTotal: number; fatDev: number
  } | null>(null)
  const logEndRef = React.useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  React.useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") =>
    setLogs(prev => [...prev, { time: new Date().toLocaleTimeString("pt-BR"), message, type }])

  const setStage = (id: string, status: StageStatus) =>
    setStages(prev => prev.map(s => s.id === id ? { ...s, status } : s))

  const resetAll = () => {
    setStages(INITIAL_STAGES.map(s => ({ ...s, status: "idle" })))
    setProgress(0); setStats(null)
  }

  const handleFile = (id: string, file: File | null) =>
    setFiles(prev => ({ ...prev, [id]: file }))

  const canRun = !!(files["controle"] && files["faturamento"])

  const runPipeline = async (downloadOnly = false) => {
    if (!canRun) return
    setIsExecuting(true); setLogs([]); resetAll()

    try {
      addLog(`Devoluções — ${String(month).padStart(2,"0")}/${year}`, "step")

      // Etapa 1
      setStage("load", "running"); setProgress(8)
      FILE_SLOTS.forEach(slot => {
        const f = files[slot.id]
        if (f) addLog(`• [${slot.label}] ${f.name}`)
        else if (!slot.required) addLog(`• [${slot.label}] não informado — usando padrão`, "warn")
      })
      setStage("load", "done"); setProgress(15)

      // FormData
      const formData = new FormData()
      formData.append("year", String(year))
      formData.append("month", String(month))
      // Ordem de detecção: controle primeiro, depois os demais
      const ordem = ["controle", "faturamento", "funcionarios", "motivos"] as const
      for (const id of ordem) {
        const f = files[id]
        if (f) {
          formData.append("files", f)
          formData.append("fileNames", f.name)
        }
      }

      // Etapa 2
      addLog(`Filtrando controle para ${month}/${year}...`, "step")
      setStage("filter", "running"); setProgress(25)
      const response = await executeDevolucoesPipeline(formData)
      if (!response.success) throw new Error(response.error)
      setStage("filter", "done"); setProgress(38)
      addLog("Registros do período extraídos.", "success")

      // Etapa 3
      addLog("Normalizando nomes via fuzzy match...", "step")
      setStage("names", "running"); setProgress(48)
      await new Promise(r => setTimeout(r, 100))
      setStage("names", "done"); setProgress(56)
      addLog("Nomes normalizados.", "success")

      // Etapa 4
      addLog("Explodindo viagens por colaborador...", "step")
      setStage("explode", "running"); setProgress(63)
      await new Promise(r => setTimeout(r, 100))
      setStage("explode", "done"); setProgress(70)

      // Etapa 5
      addLog("Agregando faturamento por viagem (excluindo motivos sistema)...", "step")
      setStage("fat", "running"); setProgress(78)
      await new Promise(r => setTimeout(r, 100))
      setStage("fat", "done"); setProgress(85)

      // Etapa 6
      addLog("Calculando percentuais de devolução...", "step")
      setStage("merge", "running"); setProgress(92)
      await new Promise(r => setTimeout(r, 100))
      setStage("merge", "done")

      // Etapa 7
      setStage("export", "running"); setProgress(97)
      const result = response.result
      setLastResult(result)

      // Extrai stats do summary
      const m = (result.summary ?? "").match(/(\d+) colaboradores · (\d+) viagens · R\$ ([\d,.]+) fat\. · R\$ ([\d,.]+) devolvido/)
      if (m) {
        setStats({
          colaboradores: parseInt(m[1]),
          viagens:       parseInt(m[2]),
          fatTotal:      parseFloat(m[3].replace(",",".")),
          fatDev:        parseFloat(m[4].replace(",",".")),
        })
      }

      if (downloadOnly && result.extraSheets) {
        downloadMultipleSheets(
          result.extraSheets.map((s: any) => ({ data: s.data, name: s.name })),
          `Devolucoes_${String(month).padStart(2,"0")}_${year}`
        )
        addLog("Excel com 2 abas baixado.", "success")
      } else {
        addLog("Dados sincronizados com Firebase.", "success")
      }

      setStage("export", "done"); setProgress(100)
      addLog(result.summary ?? "Pipeline concluído.", "success")
      toast({ title: downloadOnly ? "Excel pronto" : "Pipeline concluído", description: result.summary })

    } catch (err: any) {
      addLog(`FALHA: ${err.message}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro no pipeline", description: err.message })
    } finally {
      setIsExecuting(false)
    }
  }

  const doneCount = stages.filter(s => s.status === "done" || s.status === "warn").length
  const hasError  = stages.some(s => s.status === "error")

  return (
    <div className="space-y-6">

      {/* Alert */}
      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <PackageX className="size-4 text-primary" />
          <AlertTitle className="mb-0">Consolidador de Controle Logístico + Devoluções</AlertTitle>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="size-4 text-muted-foreground cursor-help" />
              </TooltipTrigger>
              <TooltipContent className="max-w-xs">
                <p>Cruza o controle de entregas com o faturamento, filtra devoluções por motivo do sistema, e gera percentuais de devolução por colaborador.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <AlertDescription className="text-xs mt-2">
          Gera <strong>2 abas</strong>: Resumo por Colaborador · Detalhamento (colaborador × viagem × faturamento).
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <PackageX className="size-5 text-primary" />
                Configuração da Análise
              </CardTitle>
              <CardDescription>Período e arquivos de controle, faturamento e cadastros.</CardDescription>
            </CardHeader>

            <CardContent className="space-y-5">
              {/* Período */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Ano</Label>
                  <Input type="number" value={year} onChange={e => setYear(parseInt(e.target.value))} />
                </div>
                <div className="space-y-2">
                  <Label>Mês</Label>
                  <Input type="number" min={1} max={12} value={month} onChange={e => setMonth(parseInt(e.target.value))} />
                </div>
              </div>

              <AIParamAssistant onParamsUpdate={(m, y) => { setMonth(m); setYear(y) }} currentMonth={month} currentYear={year} />

              {/* Arquivos */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold text-primary">
                  Arquivos de Entrada ({Object.values(files).filter(Boolean).length}/{FILE_SLOTS.length})
                </Label>
                <div className="space-y-1.5 rounded-xl border border-border/60 p-2 bg-muted/5">
                  {FILE_SLOTS.map(slot => {
                    const hasFile = !!files[slot.id]
                    return (
                      <div key={slot.id} className={cn(
                        "flex items-center gap-3 px-3 py-2.5 rounded-lg border transition-colors",
                        hasFile
                          ? "bg-emerald-50 border-emerald-200"
                          : slot.required
                            ? "bg-background border-border/40 hover:bg-muted/10"
                            : "bg-muted/5 border-dashed border-border/30 hover:bg-muted/10"
                      )}>
                        <FileSpreadsheet className={cn(
                          "size-4 shrink-0",
                          hasFile ? "text-emerald-600" : slot.required ? "text-primary/50" : "text-muted-foreground/40"
                        )} />

                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-1.5">
                            <span className="text-xs font-semibold">{slot.label}</span>
                            {!slot.required && (
                              <span className="text-[9px] text-muted-foreground border border-border/40 rounded px-1 py-0 leading-tight">opcional</span>
                            )}
                          </div>
                          {hasFile
                            ? <span className="text-[11px] text-emerald-600 font-medium truncate block mt-0.5">{files[slot.id]?.name}</span>
                            : <span className="text-[11px] text-muted-foreground italic mt-0.5 block">{slot.hint}</span>}
                        </div>

                        <div className="flex items-center gap-1 shrink-0">
                          {hasFile && (
                            <Button variant="ghost" size="icon" className="size-6"
                              onClick={() => handleFile(slot.id, null)}>
                              <Trash2 className="size-3 text-destructive/70" />
                            </Button>
                          )}
                          <Button
                            variant="outline" size="sm" className="h-6 text-[10px] px-2"
                            onClick={() => document.getElementById(`devolucoes-file-${slot.id}`)?.click()}
                          >
                            {hasFile ? "Trocar" : "Selecionar"}
                          </Button>
                        </div>
                        <input
                          id={`devolucoes-file-${slot.id}`} type="file" className="hidden"
                          accept=".xlsx,.xls"
                          onChange={e => handleFile(slot.id, e.target.files?.[0] ?? null)}
                        />
                      </div>
                    )
                  })}
                </div>
                {!canRun && (
                  <p className="text-[11px] text-amber-600 font-medium flex items-center gap-1">
                    <AlertTriangle className="size-3" /> Controle Logístico e Faturamento são obrigatórios.
                  </p>
                )}
              </div>

              {/* Progresso */}
              {(isExecuting || progress > 0) && (
                <div className="space-y-2 pt-1">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-primary">
                      {hasError ? "Erro na execução" : progress === 100 ? "Concluído" : "Processando..."}
                    </span>
                    <span className="text-[10px] font-mono font-bold text-muted-foreground">{progress}%</span>
                  </div>
                  <Progress value={progress} className={cn("h-2", hasError && "[&>div]:bg-destructive")} />
                  <div className="flex justify-between text-[9px] text-muted-foreground">
                    <span>{doneCount}/{stages.length} etapas</span>
                    <span>{isExecuting ? (stages.find(s => s.status === "running")?.label ?? "...") : (progress === 100 ? "Pipeline finalizado" : "")}</span>
                  </div>
                </div>
              )}
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button
                variant="outline" size="sm"
                className="flex-1 h-9 text-xs font-semibold border-slate-300 text-slate-600 hover:bg-slate-50 hover:border-slate-400 transition-all"
                onClick={() => runPipeline(true)}
                disabled={isExecuting || !canRun}
              >
                <Download className="mr-1.5 size-3.5" /> Exportar Excel
              </Button>
              <Button
                size="sm"
                className="flex-1 h-9 text-xs font-semibold shadow-sm transition-all"
                onClick={() => runPipeline(false)}
                disabled={isExecuting || !canRun}
              >
                {isExecuting
                  ? <><Loader2 className="mr-1.5 size-3.5 animate-spin" /> Processando...</>
                  : <><Play className="mr-1.5 size-3.5 fill-current" /> Iniciar Análise</>}
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">

          {/* Etapas */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Etapas de Execução</span>
            </div>
            <div className="p-3 space-y-2">
              {stages.map((stage, idx) => (
                <div key={stage.id} className="flex items-start gap-2">
                  <div className="flex flex-col items-center pt-0.5">
                    <StageIcon status={stage.status} />
                    {idx < stages.length - 1 && (
                      <div className={cn("w-px mt-1 min-h-[12px]", stage.status === "done" ? "bg-emerald-300" : "bg-border/60")} />
                    )}
                  </div>
                  <div className={cn("flex-1 px-2.5 py-1.5 rounded-lg border text-xs transition-all", stageBg[stage.status])}>
                    <p className={cn("leading-tight", stageLbl[stage.status])}>{stage.label}</p>
                    <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{stage.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Stats */}
          {stats && (
            <div className="grid grid-cols-2 gap-2">
              {[
                { label: "Colaboradores",  value: stats.colaboradores,                    icon: Users,     highlight: false },
                { label: "Viagens",        value: stats.viagens.toLocaleString("pt-BR"),  icon: Database,  highlight: false },
                { label: "Faturamento",    value: `R$ ${stats.fatTotal.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}`, icon: Database, highlight: true },
                { label: "Devolvido",      value: `R$ ${stats.fatDev.toLocaleString("pt-BR",  { minimumFractionDigits: 2 })}`, icon: PackageX, highlight: true },
              ].map(stat => {
                const Icon = stat.icon
                return (
                  <div key={stat.label} className={cn(
                    "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                    stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                  )}>
                    <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                      stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                      <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                    </div>
                    <div className="min-w-0">
                      <p className={cn("text-sm font-bold leading-tight truncate", stat.highlight ? "text-primary" : "text-foreground")}>
                        {stat.value}
                      </p>
                      <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          {/* Regras */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Regras de Processamento</span>
            </div>
            <div className="p-3 space-y-1.5">
              {REGRAS.map((rule, idx) => (
                <div key={idx} className={cn("flex items-start gap-2 rounded-lg border px-2.5 py-2 text-[11px]", ruleColor[rule.variant])}>
                  <ChevronRight className="size-3 mt-0.5 shrink-0 opacity-60" />
                  <div>
                    <span className="font-semibold">{rule.condition}</span>
                    <span className="mx-1 opacity-50">→</span>
                    <span>{rule.result}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[220px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0
                  ? <span className="text-slate-500 italic">Aguardando arquivos...</span>
                  : logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))}
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>

        </div>
      </div>
    </div>
  )
}

"use client";

/**
 * VisaoAcumuladaCards
 * ───────────────────────────────────────────────────────────────────────────
 * View em cards para a Visão Acumulada, inspirada no dashboard Python do
 * Grupo RFK (03 - Dashboard Interativo de Entregas).
 *
 * USO — no arquivo VisaoAcumuladaPage, basta:
 *
 *   1. Importar este componente:
 *        import { VisaoAcumuladaCards } from "./VisaoAcumuladaCards"
 *
 *   2. Adicionar state de view mode:
 *        const [viewMode, setViewMode] = useState<"tabela" | "cards">("tabela")
 *
 *   3. Adicionar toggle nos botões do header:
 *        <Button variant={viewMode === "tabela" ? "default" : "outline"} size="sm"
 *          onClick={() => setViewMode("tabela")}>
 *          <Table2 className="size-3.5 mr-1" /> Tabela
 *        </Button>
 *        <Button variant={viewMode === "cards" ? "default" : "outline"} size="sm"
 *          onClick={() => setViewMode("cards")}>
 *          <LayoutGrid className="size-3.5 mr-1" /> Cards
 *        </Button>
 *
 *   4. Renderizar condicionalmente:
 *        {viewMode === "cards" && (
 *          <VisaoAcumuladaCards
 *            rows={acumulado}
 *            veiculoMap={veiculoMap}
 *          />
 *        )}
 *
 *   5. Tipar o veiculoMap exportando VeiculoInfo de VisaoAcumuladaPage:
 *        export interface VeiculoInfo { capacidade: number; modelo: string; operacao: string }
 *
 * ───────────────────────────────────────────────────────────────────────────
 */

import { FC, JSX, useState, useMemo } from "react";
import {
  Truck, Users, MapPin, Gauge, Package, TrendingUp,
  ChevronDown, ChevronUp, LayoutGrid, Activity, Route,
  Layers, Navigation, Weight, Banknote,
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";

// ─────────────────────────────────────────────────────────────────────────────
// TYPES — espelham os do VisaoAcumuladaPage (ou importe diretamente de lá)
// ─────────────────────────────────────────────────────────────────────────────

export interface VeiculoInfo {
  capacidade: number;
  modelo:     string;
  operacao:   string;
}

export interface AccumulatedRow {
  "DATA DE ENTREGA":  string;
  "FILIAL":           string;
  "REGIÃO":           string;
  "MOTORISTA":        string;
  "AJUDANTE":         string;
  "AJUDANTE 2":       string;
  "PLACA":            string;
  "PLACA SISTEMA":    string;
  "TIPO CARGA":       string;
  "ENTREGAS":         number;
  "PESO":             number;
  "KM":               number;
  "KM_MAX":           number;
  "TEMPO_MINUTOS":    number;
  "TEMPO":            string;
  "VIAGENS":          string;
  "ROTA":             string;
  "VALOR":            number;
  "FRETE":            number;
  "DESCARGA PALET":   number;
  "HOSPEDAGEM":       number;
  "DIARIA":           number;
  "EXTRA":            number;
  "CHAPA":            number;
  __cargas:           number;
  __linhasOriginais:  Record<string, unknown>[];
}

interface VisaoAcumuladaCardsProps {
  rows:       AccumulatedRow[];
  veiculoMap: Map<string, VeiculoInfo>;
}

// ─────────────────────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────────────────────

function normalizarPlaca(placa: unknown): string {
  return String(placa ?? "").trim().toUpperCase().replace(/[-\s]/g, "");
}

function fmtNum(v: number, dec = 2): string {
  if (!v) return "—";
  return v.toLocaleString("pt-BR", {
    minimumFractionDigits: dec,
    maximumFractionDigits: dec,
  });
}

function fmtBRL(v: number): string {
  if (!v) return "—";
  return v.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

function calcOcupacao(peso: number, capacidade: number): number | null {
  if (!capacidade || capacidade <= 0) return null;
  return (peso / capacidade) * 100;
}

function calcCustoKm(freteTotal: number, km: number): number | null {
  if (!km) return null;
  return freteTotal / km;
}

function calcCustoTon(freteTotal: number, pesoKg: number): number | null {
  if (!pesoKg) return null;
  return freteTotal / (pesoKg / 1000);
}

function calcCustoNfe(freteTotal: number, valor: number): number | null {
  if (!valor) return null;
  return (freteTotal / valor) * 100;
}

// ─────────────────────────────────────────────────────────────────────────────
// TIPO CARGA — badge visual
// ─────────────────────────────────────────────────────────────────────────────

const CARGA_STYLE: Record<string, { bg: string; text: string; border: string }> = {
  "Carga A": { bg: "bg-emerald-500/10", text: "text-emerald-500", border: "border-emerald-500/30" },
  "Carga B": { bg: "bg-blue-500/10",    text: "text-blue-400",    border: "border-blue-400/30"    },
  "Carga C": { bg: "bg-yellow-500/10",  text: "text-yellow-500",  border: "border-yellow-500/30"  },
  "Carga D": { bg: "bg-orange-500/10",  text: "text-orange-400",  border: "border-orange-400/30"  },
  "Carga E": { bg: "bg-red-500/10",     text: "text-red-400",     border: "border-red-400/30"     },
};

function TipoCargaBadge({ tipo }: { tipo: string }): JSX.Element {
  const style = CARGA_STYLE[tipo] ?? { bg: "bg-muted", text: "text-muted-foreground", border: "border-border" };
  return (
    <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full border", style.bg, style.text, style.border)}>
      {tipo || "—"}
    </span>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// OCUPAÇÃO — barra + badge
// ─────────────────────────────────────────────────────────────────────────────

function OcupacaoBar({ pct }: { pct: number | null }): JSX.Element {
  if (pct === null) {
    return (
      <div className="flex items-center gap-2">
        <div className="flex-1 h-2 rounded-full bg-border" />
        <span className="text-[10px] font-bold text-muted-foreground w-12 text-right">N/C</span>
      </div>
    );
  }
  const capped = Math.min(pct, 100);
  const colorBar =
    pct >= 100 ? "bg-emerald-500" :
    pct >=  85 ? "bg-yellow-400" :
                 "bg-red-400";
  const colorText =
    pct >= 100 ? "text-emerald-500" :
    pct >=  85 ? "text-yellow-500"  :
                 "text-red-400";
  return (
    <div className="flex items-center gap-2">
      <div className="flex-1 h-2 rounded-full bg-border overflow-hidden">
        <div
          className={cn("h-full rounded-full transition-all duration-700", colorBar)}
          style={{ width: `${capped}%` }}
        />
      </div>
      <span className={cn("text-[10px] font-bold w-12 text-right font-mono", colorText)}>
        {pct.toFixed(1)}%
      </span>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// MODELO BADGE
// ─────────────────────────────────────────────────────────────────────────────

function ModeloBadge({ modelo }: { modelo: string }): JSX.Element {
  const m = modelo.trim().toUpperCase();
  if (!m || m === "-") return <span className="text-muted-foreground/40 text-[10px]">—</span>;
  const cor =
    m === "TRUCK"     ? "bg-slate-100 text-slate-700 border-slate-200" :
    m === "TOCO"      ? "bg-violet-100 text-violet-700 border-violet-200" :
    m === "CARRETA"   ? "bg-amber-100 text-amber-700 border-amber-200" :
    m === "BITRUCK"   ? "bg-orange-100 text-orange-700 border-orange-200" :
    m === "TRUCKINHO" ? "bg-teal-100 text-teal-700 border-teal-200" :
    m === "VAN"       ? "bg-pink-100 text-pink-700 border-pink-200" :
                        "bg-muted text-muted-foreground border-border";
  return (
    <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full border", cor)}>{m}</span>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// OPERAÇÃO BADGE
// ─────────────────────────────────────────────────────────────────────────────

function OperacaoBadge({ operacao }: { operacao: string }): JSX.Element {
  const op = operacao.trim().toUpperCase();
  if (!op) return <span className="text-muted-foreground/40 text-[10px]">—</span>;
  const cor =
    op === "FRETE" ? "bg-blue-100 text-blue-700 border-blue-200" :
    op === "FROTA" ? "bg-primary/10 text-primary border-primary/20" :
                     "bg-muted text-muted-foreground border-border";
  return (
    <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full border", cor)}>{op}</span>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// INDICADOR LOGÍSTICO — bloco individual
// ─────────────────────────────────────────────────────────────────────────────

interface IndicadorProps {
  label: string;
  value: string | null;
  icon: JSX.Element;
}

const Indicador: FC<IndicadorProps> = ({ label, value, icon }) => (
  <div className="flex flex-col items-center gap-1 rounded-xl border border-white/20 bg-white/10 px-3 py-2.5 text-center backdrop-blur-sm hover:bg-white/20 transition-colors">
    <div className="opacity-80">{icon}</div>
    <span className="text-[9px] font-bold uppercase tracking-wider opacity-75">{label}</span>
    <span className="text-sm font-bold leading-tight">{value ?? "—"}</span>
  </div>
);

// ─────────────────────────────────────────────────────────────────────────────
// MÉTRICA BOX — grid de métricas principais no corpo do card
// ─────────────────────────────────────────────────────────────────────────────

interface MetricaBoxProps {
  label: string;
  value: string | JSX.Element;
  icon?: JSX.Element;
  highlight?: boolean;
  className?: string;
}

const MetricaBox: FC<MetricaBoxProps> = ({ label, value, icon, highlight, className }) => (
  <div className={cn(
    "flex flex-col gap-1 rounded-xl border p-3 transition-all hover:shadow-sm",
    highlight
      ? "border-primary/30 bg-primary/5"
      : "border-border bg-muted/30",
    className
  )}>
    <div className="flex items-center gap-1.5">
      {icon && <span className="text-muted-foreground">{icon}</span>}
      <span className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">{label}</span>
    </div>
    <div className="text-sm font-bold text-foreground leading-tight font-mono">{value}</div>
  </div>
);

// ─────────────────────────────────────────────────────────────────────────────
// CARD DE MOTORISTA
// ─────────────────────────────────────────────────────────────────────────────

interface MotoristaCardProps {
  row:        AccumulatedRow;
  veiculoMap: Map<string, VeiculoInfo>;
}

const MotoristaCard: FC<MotoristaCardProps> = ({ row, veiculoMap }) => {
  const [expanded, setExpanded] = useState(false);

  const placa       = normalizarPlaca(row["PLACA"] || row["PLACA SISTEMA"]);
  const veiculo     = veiculoMap.get(placa);
  const capacidade  = veiculo?.capacidade ?? 0;
  const modelo      = veiculo?.modelo     ?? "";
  const operacao    = veiculo?.operacao   ?? "";

  const freteTotal  = (row["FRETE"] || 0) + (row["CHAPA"] || 0);
  const ocupacaoPct = calcOcupacao(row["PESO"], capacidade);
  const custoKm     = calcCustoKm(freteTotal, row["KM"]);
  const custoTon    = calcCustoTon(freteTotal, row["PESO"]);
  const custoNfe    = calcCustoNfe(freteTotal, row["VALOR"]);

  // Viagens como array
  const viagens = (row["VIAGENS"] || "").split(" / ").filter(Boolean);

  // Tipos de carga (pode ter múltiplos separados por " / ")
  const tiposCarga = (row["TIPO CARGA"] || "Carga A").split(" / ").filter(Boolean);

  // Cor gradiente do header baseada no tipo de carga predominante
  const headerGrad =
    tiposCarga[0] === "Carga A" ? "from-emerald-600 to-teal-600"   :
    tiposCarga[0] === "Carga B" ? "from-blue-600 to-cyan-600"      :
    tiposCarga[0] === "Carga C" ? "from-yellow-600 to-amber-600"   :
    tiposCarga[0] === "Carga D" ? "from-orange-600 to-red-500"     :
                                  "from-red-700 to-rose-600";

  // Ocupação visual
  const ocupPct = ocupacaoPct ?? 0;
  const ocupColor =
    ocupPct >= 100 ? "text-emerald-400" :
    ocupPct >=  85 ? "text-yellow-400"  :
                     "text-red-400";

  return (
    <div className={cn(
      "rounded-2xl border border-border bg-card overflow-hidden shadow-sm",
      "transition-all duration-300 hover:shadow-lg hover:-translate-y-0.5 hover:border-primary/40"
    )}>
      {/* ── HEADER ────────────────────────────────────────────────────── */}
      <div className={cn("relative bg-gradient-to-br text-white px-5 py-4", headerGrad)}>
        {/* Badge multi-rota */}
        {row.__cargas > 1 && (
          <div className="absolute top-3 right-3">
            <span className="flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-full bg-white/20 border border-white/30 backdrop-blur-sm">
              <Layers className="h-3 w-3" />{row.__cargas} rotas
            </span>
          </div>
        )}

        {/* Nome + ajudantes */}
        <div className="flex items-start gap-3">
          <div className="h-11 w-11 rounded-xl bg-white/20 border border-white/30 flex items-center justify-center flex-shrink-0 backdrop-blur-sm">
            <Truck className="h-5 w-5 text-white" />
          </div>
          <div className="flex-1 min-w-0">
            <p className="font-bold text-base leading-tight truncate drop-shadow-sm">
              {row["MOTORISTA"] || "—"}
            </p>
            {(row["AJUDANTE"] || row["AJUDANTE 2"]) && (
              <p className="text-xs text-white/80 mt-0.5 flex items-center gap-1">
                <Users className="h-3 w-3" />
                {[row["AJUDANTE"], row["AJUDANTE 2"]].filter(Boolean).join(" · ")}
              </p>
            )}
            <div className="flex items-center gap-2 mt-2 flex-wrap">
              {(row["FILIAL"] || row["REGIÃO"]) && (
                <span className="text-[10px] bg-white/15 border border-white/25 rounded-full px-2 py-0.5 flex items-center gap-1">
                  <MapPin className="h-2.5 w-2.5" />
                  {[row["FILIAL"], row["REGIÃO"]].filter(Boolean).join(" · ")}
                </span>
              )}
              {tiposCarga.map((t) => <TipoCargaBadge key={t} tipo={t} />)}
            </div>
          </div>
        </div>

        {/* Placa + modelo + data */}
        <div className="mt-3 flex items-center gap-2 flex-wrap">
          {(row["PLACA"] || row["PLACA SISTEMA"]) && (
            <span className="text-xs bg-white/20 border border-white/30 rounded-lg px-2.5 py-1 font-mono font-bold backdrop-blur-sm">
              🚗 {row["PLACA"] || row["PLACA SISTEMA"]}
            </span>
          )}
          {modelo && <ModeloBadge modelo={modelo} />}
          {operacao && <OperacaoBadge operacao={operacao} />}
          {row["DATA DE ENTREGA"] && (
            <span className="text-[10px] text-white/70 font-mono ml-auto">{row["DATA DE ENTREGA"]}</span>
          )}
        </div>
      </div>

      {/* ── CORPO ─────────────────────────────────────────────────────── */}
      <div className="px-4 py-4 space-y-4">

        {/* MÉTRICAS PRINCIPAIS — grid 3 colunas */}
        <div className="grid grid-cols-3 gap-2">
          <MetricaBox
            label="Viagens"
            value={<span className="text-primary">{viagens.length || row["VIAGENS"] ? viagens.length || 1 : "—"}</span>}
            icon={<Navigation className="h-3 w-3" />}
            highlight
          />
          <MetricaBox
            label="Entregas"
