                {importDone ? "Dados salvos com sucesso" : "Grava no banco de dados"}
              </p>
            </div>
          </button>
        </div>

        {/* Stats pós-importação */}
        {stats && (
          <div className="grid grid-cols-3 gap-2 pt-1">
            <div className="rounded-lg border border-border/60 bg-card px-3 py-2 text-center">
              <p className="text-sm font-bold text-primary">{stats.filiaisOk}/5</p>
              <p className="text-[10px] text-muted-foreground">Filiais</p>
            </div>
            <div className="rounded-lg border border-border/60 bg-card px-3 py-2 text-center">
              <p className="text-sm font-bold text-foreground">{stats.novos.toLocaleString("pt-BR")}</p>
              <p className="text-[10px] text-muted-foreground">Novos registros</p>
            </div>
            <div className="rounded-lg border border-emerald-200 bg-emerald-50 px-3 py-2 text-center">
              <p className="text-sm font-bold text-emerald-700">{stats.total.toLocaleString("pt-BR")}</p>
              <p className="text-[10px] text-muted-foreground">Total no banco</p>
            </div>
          </div>
        )}

        {/* Banner duplicadas */}
        {duplicadas.length > 0 && (
          <button
            onClick={onVerDuplicadas}
            className="w-full flex items-center gap-2.5 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2.5 text-left hover:bg-amber-100 transition-colors"
          >
            <ShieldAlert className="size-4 text-amber-500 shrink-0" />
            <div className="flex-1 min-w-0">
              <p className="text-[11px] font-semibold text-amber-800">
                {duplicadas.length} viagem{duplicadas.length !== 1 ? "ns" : ""} não importada{duplicadas.length !== 1 ? "s" : ""}
              </p>
              <p className="text-[10px] text-amber-600">Já existem no banco. Clique para ver os detalhes.</p>
            </div>
            <ChevronRight className="size-3.5 text-amber-500 shrink-0" />
          </button>
        )}
      </div>
    </div>
  )
}

// ─── Componente principal ─────────────────────────────────────────────────────
export function ConsolidacaoEntregasPipelineView() {
  const today = new Date()

  const [year,  setYear]  = React.useState(today.getFullYear())
  const [month, setMonth] = React.useState(today.getMonth() + 1)
  const [day,   setDay]   = React.useState<number>(today.getDate())

  const [files, setFiles] = React.useState<Record<string, File | null>>({})

  // ── estado de análise local (etapa 1 — zero Firebase) ────────────────────
  const [isAnalyzing, setIsAnalyzing] = React.useState(false)
  const [analises,    setAnalises]    = React.useState<AnaliseArquivo[]>([])
  const [analiseDone, setAnaliseDone] = React.useState(false)

  // ── estado de importação Firebase (etapa 2 — só se o usuário pedir) ──────
  const [isImporting, setIsImporting] = React.useState(false)
  const [importDone,  setImportDone]  = React.useState(false)

  const [progress, setProgress] = React.useState(0)
  const [stages,   setStages]   = React.useState<Stage[]>(STAGES_DIA)
  const [logs,     setLogs]     = React.useState<LogEntry[]>([])
  const [stats,    setStats]    = React.useState<{
    filiaisOk: number; novos: number; total: number; duplicadas: number
  } | null>(null)

  const [duplicadas,     setDuplicadas]     = React.useState<DuplicadaInfo[]>([])
  const [showDuplicadas, setShowDuplicadas] = React.useState(false)

  const logEndRef = React.useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  const modoMesCompleto = day === 0

  React.useEffect(() => {
    // etapas mudam conforme análise ativa ou não
    if (isImporting || importDone) return
    const base = analiseDone
      ? (modoMesCompleto ? STAGES_MES : STAGES_DIA)
      : (modoMesCompleto ? STAGES_MES : STAGES_DIA)
    setStages(base.map(s => ({ ...s, status: "idle" })))
  }, [modoMesCompleto])

  React.useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") =>
    setLogs(prev => [...prev, { time: new Date().toLocaleTimeString("pt-BR"), message, type }])

  const setStage = (id: string, status: StageStatus) =>
    setStages(prev => prev.map(s => s.id === id ? { ...s, status } : s))

  const resetAnalise = () => {
    setStages((modoMesCompleto ? STAGES_MES : STAGES_DIA).map(s => ({ ...s, status: "idle" })))
    setProgress(0); setStats(null)
    setAnalises([]); setAnaliseDone(false)
    setImportDone(false); setDuplicadas([]); setShowDuplicadas(false)
  }

  const canAnalyze = FILIAIS.some(f => files[f.id])
  const abaPreview = day > 0 ? montarNomeAba(day, month, year) : null

  const handleFileChange = (id: string, file: File | null) => {
    setFiles(prev => ({ ...prev, [id]: file }))
    if (analiseDone) resetAnalise()
  }

  // ── ETAPA 1: Análise local no browser — zero Firebase ────────────────────
  const runAnalise = async () => {
    if (!canAnalyze) return
    setIsAnalyzing(true); setLogs([]); resetAnalise()

    try {
      const selecionados = FILIAIS.filter(f => files[f.id])
      const modoLabel = day > 0
        ? `aba ${montarNomeAba(day, month, year)}`
        : `mês ${String(month).padStart(2, "0")}/${year} completo`

      addLog(`Análise local — ${modoLabel}`, "step")
      addLog(`${selecionados.length} filial(is): ${selecionados.map(f => f.regiao).join(" · ")}`)
      if (modoMesCompleto) addLog("Modo mês completo — pode ser demorado para arquivos grandes.", "warn")

      setStage("load", "running"); setProgress(10)
      await new Promise(r => setTimeout(r, 80))
      selecionados.forEach(f => {
        const sz = files[f.id]?.size ?? 0
        addLog(`• [${f.regiao}] ${f.label} — ${fmtSize(sz)}${sz > 5 * 1024 * 1024 ? " ⚠️ arquivo grande" : ""}`)
      })
      setStage("load", "done"); setProgress(20)

      const stage2id = modoMesCompleto ? "scan" : "sheet"
      addLog(day > 0 ? `Localizando aba "${abaPreview}"...` : "Varrendo abas do mês...", "step")
      setStage(stage2id, "running"); setProgress(35)

      const novasAnalises: AnaliseArquivo[] = []

      for (const filial of selecionados) {
        const file = files[filial.id]!
        const buffer = await file.arrayBuffer()
        const filialNome = MAPA_FILIAL[filial.id] ?? "Desconhecida"

        if (day > 0) {
          const abaAlvo = montarNomeAba(day, month, year)
          const wb = XLSX.read(buffer, { type: "array", cellDates: true, sheets: abaAlvo })

          if (!wb.SheetNames.includes(abaAlvo)) {
            addLog(`[${filial.regiao}] Aba "${abaAlvo}" não encontrada — pulando.`, "warn")
            continue
          }

          const { rows, colNames } = parseSheetLocal(wb.Sheets[abaAlvo])
          const dataEntrega = abaAlvo.replace(/\./g, "/")
          const dados = processarRowsLocal(rows, filialNome, dataEntrega)

          novasAnalises.push({
            id: filial.id, cd: filial.label.replace(".xlsx", ""),
            regiao: filial.regiao, fileName: file.name,
            colunas: colNames.filter(c => !c.startsWith("__")).length,
            linhas: dados.length, abaAlvo, dados, fileSize: file.size,
          })
          addLog(`• [${filial.regiao}] ${dados.length} registros — aba ${abaAlvo}`, "success")

        } else {
          const wb = XLSX.read(buffer, { type: "array", cellDates: true })
          const abasMes = wb.SheetNames.filter(name => {
            const m = name.match(/^(\d{2})\.(\d{2})\.(\d{4})$/)
            return m && parseInt(m[2]) === month && parseInt(m[3]) === year
          })

          if (abasMes.length === 0) {
            addLog(`[${filial.regiao}] Nenhuma aba do mês encontrada — pulando.`, "warn")
            continue
          }

          let todosDados: any[] = []
          let colunasMax = 0
          for (const abaAlvo of abasMes) {
            const { rows, colNames } = parseSheetLocal(wb.Sheets[abaAlvo])
            const dados = processarRowsLocal(rows, filialNome, abaAlvo.replace(/\./g, "/"))
            todosDados = todosDados.concat(dados)
            colunasMax = Math.max(colunasMax, colNames.filter(c => !c.startsWith("__")).length)
          }

          novasAnalises.push({
            id: filial.id, cd: filial.label.replace(".xlsx", ""),
            regiao: filial.regiao, fileName: file.name,
            colunas: colunasMax, linhas: todosDados.length,
            abaAlvo: `${abasMes.length} aba(s)`, dados: todosDados, fileSize: file.size,
          })
          addLog(`• [${filial.regiao}] ${todosDados.length} registros de ${abasMes.length} aba(s)`, "success")
        }
      }

      setStage(stage2id, "done"); setProgress(70)
      setStage("parse", "running"); setProgress(85)
      await new Promise(r => setTimeout(r, 60))
      setStage("parse", "done")
      setStage("ready", "done"); setProgress(100)

      setAnalises(novasAnalises)
      setAnaliseDone(true)

      const totalLins = novasAnalises.reduce((s, a) => s + a.linhas, 0)
      addLog(`Análise concluída — ${totalLins.toLocaleString("pt-BR")} registros em memória · zero Firebase.`, "success")
      addLog("Escolha: baixar Excel ou importar para Firebase.", "step")

      toast({ title: "Análise concluída", description: `${totalLins.toLocaleString("pt-BR")} registros prontos · sem custo Firebase` })

    } catch (err: any) {
      addLog(`FALHA: ${err.message}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro na análise", description: err.message })
    } finally {
      setIsAnalyzing(false)
    }
  }

  // ── ETAPA 2a: Baixar Excel sem Firebase ──────────────────────────────────
  const handleBaixarExcel = () => {
    if (!analises.length) return
    try {
      const wb = XLSX.utils.book_new()
      for (const a of analises) {
        if (!a.dados.length) continue
        const semChao = a.dados.filter(r => removeAcentos(String(r["ROTA"] ?? "")).trim() !== "TESTE")
        XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(semChao), a.cd.slice(0, 31))
      }
      const acumulado = analises.flatMap(a =>
        a.dados.filter(r => removeAcentos(String(r["ROTA"] ?? "")).trim() !== "TESTE")
      )
      if (acumulado.length) XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(acumulado), "Acumulado")

      const nome = day > 0
        ? `Entregas_${String(day).padStart(2,"0")}-${String(month).padStart(2,"0")}-${year}.xlsx`
        : `Entregas_${String(month).padStart(2,"0")}-${year}.xlsx`

      XLSX.writeFile(wb, nome)
      addLog(`Excel gerado: ${nome}`, "success")
      toast({ title: "Excel baixado", description: nome })
    } catch (err: any) {
      addLog(`Erro ao gerar Excel: ${err.message}`, "error")
      toast({ variant: "destructive", title: "Erro ao gerar Excel", description: err.message })
    }
  }

  // ── ETAPA 2b: Importar para Firebase (só se o usuário quiser) ────────────
  const handleImportar = async () => {
    if (!analises.length || isImporting || importDone) return
    setIsImporting(true)

    // Troca as etapas laterais para o modo importação
    const importStages = modoMesCompleto ? STAGES_IMPORT_MES : STAGES_IMPORT_DIA
    setStages(importStages.map(s => ({ ...s, status: "idle" })))
    setProgress(0)

    addLog("Iniciando importação para Firebase...", "step")

    try {
      const selecionados = FILIAIS.filter(f => files[f.id])
      const modoLabel = day > 0
        ? `aba ${montarNomeAba(day, month, year)}`
        : `mês ${String(month).padStart(2, "0")}/${year} completo`

      setStage("load", "running"); setProgress(8)
      await new Promise(r => setTimeout(r, 80))
      selecionados.forEach(f => {
        const sz = files[f.id]?.size ?? 0
        addLog(`• [${f.regiao}] ${f.label} — ${fmtSize(sz)}`)
      })
      setStage("load", "done"); setProgress(15)

      const formData = new FormData()
      formData.append("year",  String(year))
      formData.append("month", String(month))
      formData.append("day",   String(day))
      if (day > 0) formData.append("sheetName", montarNomeAba(day, month, year))
      for (const filial of FILIAIS) {
        if (files[filial.id]) {
          formData.append("files",     files[filial.id]!)
          formData.append("fileNames", files[filial.id]!.name)
        }
      }

      const stage2id = modoMesCompleto ? "scan" : "sheet"
      addLog(day > 0 ? `Localizando aba "${abaPreview}"...` : "Varrendo abas do mês...", "step")
      setStage(stage2id, "running"); setProgress(25)
      setStage("dedup", "running"); setProgress(35)
      addLog("Verificando duplicatas (1 leitura de metadata)...", "info")

      const response = await executeConsolidacaoEntregasPipeline(formData)

      if (!response.success) {
        const msg = response.error ?? "Erro desconhecido"
        addLog(`FALHA: ${msg}`, "error")
        if (msg.includes("não foi encontrada")) {
          addLog(`Dica: verifique se o arquivo contém a aba "${abaPreview}".`, "warn")
          addLog(`Formato esperado: DD.MM.YYYY — ex: ${abaPreview}`, "warn")
        }
        setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
        setProgress(0)
        toast({ variant: "destructive", title: "Erro na importação", description: msg })
        return
      }

      setStage(stage2id, "done")
      setStage("dedup", "done"); setProgress(55)
      addLog("Duplicatas verificadas.", "success")

      setStage("parse", "running"); setProgress(68)
      await new Promise(r => setTimeout(r, 80))
      setStage("parse", "done"); setProgress(80)
      addLog("Registros extraídos e padronizados.", "success")

      addLog("Gerando Acumulado — removendo CHÃO...", "step")
      setStage("accum", "running"); setProgress(90)
      await new Promise(r => setTimeout(r, 60))
      setStage("accum", "done")

      setStage("save", "running"); setProgress(97)
      const result = response.result

      const dups: DuplicadaInfo[] = (result as any).duplicadas ?? []
      if (dups.length > 0) {
        setDuplicadas(dups)
        addLog(`${dups.length} viagem(ns) ignorada(s) — já existem no banco.`, "warn")
        setTimeout(() => setShowDuplicadas(true), 400)
      }

      const m = (result.summary ?? "").match(/(\d+) filiais? · (\d+) novos · (\d+) total/)
      if (m) setStats({ filiaisOk: parseInt(m[1]), novos: parseInt(m[2]), total: parseInt(m[3]), duplicadas: dups.length })

      addLog("Dados sincronizados com Firebase.", "success")
      setStage("save", "done"); setProgress(100)
      addLog(result.summary ?? "Pipeline concluído.", "success")
      setImportDone(true)

      toast({
        title: "Importação concluída",
        description: dups.length > 0 ? `${result.summary} — verifique as duplicatas.` : result.summary,
      })

    } catch (err: any) {
      addLog(`FALHA: ${err.message}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro na importação", description: err.message })
    } finally {
      setIsImporting(false)
    }
  }

  const doneCount = stages.filter(s => s.status === "done" || s.status === "warn").length
  const hasError  = stages.some(s => s.status === "error")

  return (
    <div className="space-y-6">

      {/* Alert */}
      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Building2 className="size-4 text-primary" />
          <AlertTitle className="mb-0">Consolidação de Entregas</AlertTitle>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="size-4 text-muted-foreground cursor-help" />
              </TooltipTrigger>
              <TooltipContent className="max-w-xs">
                <p>Analisa localmente primeiro (zero Firebase). Depois escolha: baixar Excel ou importar.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <AlertDescription className="text-xs mt-2">
          <strong>Novo fluxo:</strong> Analise primeiro (zero custo) → veja a tabela de resultados →
          escolha <strong>Baixar Excel</strong> ou <strong>Importar para Firebase</strong>.
          Com <strong>dia preenchido</strong> → lê apenas aquela aba.
          Com <strong>dia 0</strong> → lê o mês completo.
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Building2 className="size-5 text-primary" />
                Configuração da Consolidação
              </CardTitle>
              <CardDescription>Selecione o período e os arquivos de cada filial.</CardDescription>
            </CardHeader>

            <CardContent className="space-y-5">
              {/* Período */}
              <div className="grid grid-cols-3 gap-3">
                <div className="space-y-2">
                  <Label className="flex items-center gap-1.5">
                    Ano
                    <TooltipProvider><Tooltip>
                      <TooltipTrigger asChild><HelpCircle className="size-3 text-muted-foreground cursor-help" /></TooltipTrigger>
                      <TooltipContent><p>Ano de referência. Ex: <strong>2026</strong>.</p></TooltipContent>
                    </Tooltip></TooltipProvider>
                  </Label>
                  <Input type="number" value={year} onChange={e => setYear(parseInt(e.target.value))} />
                </div>
                <div className="space-y-2">
                  <Label className="flex items-center gap-1.5">
                    Mês
                    <TooltipProvider><Tooltip>
                      <TooltipTrigger asChild><HelpCircle className="size-3 text-muted-foreground cursor-help" /></TooltipTrigger>
                      <TooltipContent><p>Mês (1–12). Ex: <strong>3</strong> para março.</p></TooltipContent>
                    </Tooltip></TooltipProvider>
                  </Label>
                  <Input type="number" min={1} max={12} value={month} onChange={e => setMonth(parseInt(e.target.value))} />
                </div>
                <div className="space-y-2">
                  <Label className="flex items-center gap-1.5">
                    Dia
                    <TooltipProvider><Tooltip>
                      <TooltipTrigger asChild><HelpCircle className="size-3 text-muted-foreground cursor-help" /></TooltipTrigger>
                      <TooltipContent><p>Dia específico → aba <span className="font-mono">DD.MM.YYYY</span>.<br/>Deixe <strong>0</strong> para o mês todo.</p></TooltipContent>
                    </Tooltip></TooltipProvider>
                  </Label>
                  <Input
                    type="number" min={0} max={31}
                    value={day === 0 ? "" : day}
                    placeholder="0 = mês todo"
                    onChange={e => {
                      const v = parseInt(e.target.value)
                      setDay(isNaN(v) || v < 0 ? 0 : Math.min(v, 31))
                      if (analiseDone) resetAnalise()
                    }}
                  />
                </div>
              </div>

              {/* Preview do modo */}
              {modoMesCompleto ? (
                <div className="flex items-start gap-2 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2.5">
                  <Clock className="size-3.5 text-amber-600 shrink-0 mt-0.5" />
                  <div className="text-[11px] text-amber-700">
                    <span className="font-semibold">Modo mês completo</span> — todas as abas{" "}
                    <span className="font-mono">DD.{String(month).padStart(2,"0")}.{year}</span>{" "}
                    serão analisadas localmente.
                  </div>
                </div>
              ) : (
                <div className="flex items-center gap-2 rounded-lg border border-primary/20 bg-primary/5 px-3 py-2">
                  <Calendar className="size-3.5 text-primary shrink-0" />
                  <span className="text-[11px] text-primary">
                    Aba alvo: <span className="font-mono font-bold">{abaPreview}</span>
                    <span className="text-muted-foreground ml-2">— apenas esta aba será analisada</span>
                  </span>
                </div>
              )}

              <AIParamAssistant
                onParamsUpdate={(m, y) => { setMonth(m); setYear(y) }}
                currentMonth={month} currentYear={year}
              />

              {/* Filiais */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold text-primary">
                  Arquivos de Controle ({FILIAIS.filter(f => files[f.id]).length}/{FILIAIS.length} selecionados)
                </Label>
                <div className="space-y-1.5 rounded-xl border border-border/60 p-2 bg-muted/5">
                  {FILIAIS.map(filial => {
                    const hasFile = !!files[filial.id]
                    const sz      = files[filial.id]?.size ?? 0
                    const isBig   = hasFile && sz > 5 * 1024 * 1024
                    const analise = analises.find(a => a.id === filial.id)
                    return (
                      <div key={filial.id} className={cn(
                        "flex items-center gap-3 px-3 py-2.5 rounded-lg border transition-colors",
                        hasFile ? "bg-emerald-50 border-emerald-200" : "bg-background border-border/40 hover:bg-muted/10"
                      )}>
                        <FileSpreadsheet className={cn("size-4 shrink-0", hasFile ? "text-emerald-600" : "text-primary/50")} />
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            <span className={cn(
                              "text-[10px] font-bold px-1.5 py-0.5 rounded shrink-0",
                              hasFile ? "bg-emerald-100 text-emerald-700" : "bg-muted text-muted-foreground"
                            )}>
                              {filial.regiao}
                            </span>
                            <span className="text-xs font-semibold truncate">
                              CONTROLE DE DISTRIBUIÇÃO — {filial.label}
                            </span>
                            {isBig && (
                              <Badge className="text-[9px] h-4 px-1.5 bg-amber-100 text-amber-700 border-amber-200">
                                {fmtSize(sz)} — arquivo grande
                              </Badge>
                            )}
                            {analise && (
                              <Badge className="text-[9px] h-4 px-1.5 bg-blue-100 text-blue-700 border-blue-200">
                                {analise.linhas} linhas · {analise.colunas} cols
                              </Badge>
                            )}
                          </div>
                          {hasFile
                            ? <span className="text-[11px] text-emerald-600 font-medium truncate block mt-0.5">
                                {files[filial.id]?.name}
                                {!isBig && <span className="text-muted-foreground ml-1">({fmtSize(sz)})</span>}
                              </span>
                            : <span className="text-[11px] text-muted-foreground italic mt-0.5 block">
                                Nenhum arquivo selecionado
                              </span>}
                        </div>
                        <div className="flex items-center gap-1 shrink-0">
                          {hasFile && (
                            <Button variant="ghost" size="icon" className="size-6"
                              onClick={() => handleFileChange(filial.id, null)}>
                              <Trash2 className="size-3 text-destructive/70" />
                            </Button>
                          )}
                          <Button variant="outline" size="sm" className="h-6 text-[10px] px-2"
                            onClick={() => document.getElementById(`file-ent-${filial.id}`)?.click()}>
                            {hasFile ? "Trocar" : "Selecionar"}
                          </Button>
                        </div>
                        <input
                          id={`file-ent-${filial.id}`} type="file" className="hidden" accept=".xlsx,.xls"
                          onChange={e => handleFileChange(filial.id, e.target.files?.[0] || null)}
                        />
                      </div>
                    )
                  })}
                </div>
              </div>

              {/* Progresso */}
              {(isAnalyzing || isImporting || progress > 0) && (
                <div className="space-y-2 pt-1">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-primary">
                      {hasError
                        ? "Erro na execução"
                        : isImporting
                          ? "Importando para Firebase..."
                          : progress === 100
                            ? "Análise concluída"
                            : "Analisando localmente..."}
                    </span>
                    <span className="text-[10px] font-mono font-bold text-muted-foreground">{progress}%</span>
                  </div>
                  <Progress value={progress} className={cn("h-2", hasError && "[&>div]:bg-destructive")} />
                  <div className="flex justify-between text-[9px] text-muted-foreground">
                    <span>{doneCount}/{stages.length} etapas</span>
                    <span>
                      {isAnalyzing || isImporting
                        ? (stages.find(s => s.status === "running")?.label ?? "...")
                        : progress === 100 ? "Pipeline finalizado" : ""}
                    </span>
                  </div>
                </div>
              )}
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4">
              <Button
                size="sm" className="w-full h-9 text-xs font-semibold shadow-sm"
                onClick={analiseDone ? resetAnalise : runAnalise}
                disabled={isAnalyzing || isImporting || (!canAnalyze && !analiseDone)}
                variant={analiseDone ? "outline" : "default"}
              >
                {isAnalyzing
                  ? <><Loader2 className="mr-1.5 size-3.5 animate-spin" /> Analisando...</>
                  : analiseDone
                    ? <><BarChart3 className="mr-1.5 size-3.5" /> Nova Análise</>
                    : <><Eye className="mr-1.5 size-3.5" /> Analisar Arquivos</>}
              </Button>
            </CardFooter>
          </Card>

          {/* ── Tabela de resultado (aparece após análise) ── */}
          {analiseDone && <TabelaAnalise analises={analises} />}

          {/* ── Painel de ações (aparece após análise) ── */}
          {analiseDone && (
            <PainelAcoes
              analises={analises}
              onImportar={handleImportar}
              onBaixarExcel={handleBaixarExcel}
              isImporting={isImporting}
              importDone={importDone}
              stats={stats}
              duplicadas={duplicadas}
              onVerDuplicadas={() => setShowDuplicadas(true)}
            />
          )}
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">

          {/* Etapas */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Etapas — {modoMesCompleto ? "Mês Completo" : "Dia Específico"}
              </span>
            </div>
            <div className="p-3 space-y-2">
              {stages.map((stage, idx) => (
                <div key={stage.id} className="flex items-start gap-2">
                  <div className="flex flex-col items-center pt-0.5">
                    <StageIcon status={stage.status} />
                    {idx < stages.length - 1 && (
                      <div className={cn("w-px mt-1 min-h-[14px]",
                        stage.status === "done" ? "bg-emerald-300" : "bg-border/60")} />
                    )}
                  </div>
                  <div className={cn("flex-1 px-2.5 py-1.5 rounded-lg border text-xs transition-all", stageBg[stage.status])}>
                    <p className={cn("leading-tight", stageLbl[stage.status])}>{stage.label}</p>
                    <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{stage.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Stats pós-importação */}
          {stats && (
            <div className="grid grid-cols-2 gap-2">
              {([
                { label: "Filiais",             value: `${stats.filiaisOk}/5`,              icon: Building2,    highlight: false, warn: false },
                { label: "Novos registros",     value: stats.novos.toLocaleString("pt-BR"), icon: Database,     highlight: false, warn: false },
                { label: "Total no banco",      value: stats.total.toLocaleString("pt-BR"), icon: CheckCircle2, highlight: true,  warn: false, span: true },
                ...(stats.duplicadas > 0 ? [{ label: "Duplicadas ignoradas", value: stats.duplicadas.toLocaleString("pt-BR"), icon: ShieldAlert, highlight: false, warn: true, span: true }] : []),
              ] as any[]).map((stat: any) => {
                const Icon = stat.icon
                return (
                  <div key={stat.label} className={cn(
                    "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                    stat.span ? "col-span-2" : "",
                    stat.warn ? "bg-amber-50 border-amber-200" : stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                  )}>
                    <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                      stat.warn ? "bg-amber-100" : stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                      <Icon className={cn("size-3.5",
                        stat.warn ? "text-amber-500" : stat.highlight ? "text-primary" : "text-muted-foreground")} />
                    </div>
                    <div className="min-w-0">
                      <p className={cn("text-sm font-bold leading-tight",
                        stat.warn ? "text-amber-700" : stat.highlight ? "text-primary" : "text-foreground")}>
                        {stat.value}
                      </p>
                      <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          {/* Regras */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Regras</span>
            </div>
            <div className="p-3 space-y-1.5">
              {REGRAS.map((rule, idx) => (
                <div key={idx} className={cn("flex items-start gap-2 rounded-lg border px-2.5 py-2 text-[11px]", ruleColor[rule.variant])}>
                  <ChevronRight className="size-3 mt-0.5 shrink-0 opacity-60" />
                  <div>
                    <span className="font-semibold">{rule.condition}</span>
                    <span className="mx-1 opacity-50">→</span>
                    <span>{rule.result}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[240px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0
                  ? <span className="text-slate-500 italic">Aguardando análise...</span>
                  : logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))}
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>

        </div>
      </div>

      <DuplicadasDialog
        open={showDuplicadas}
        onClose={() => setShowDuplicadas(false)}
        duplicadas={duplicadas}
      />
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Play,
  Trash2,
  FileCode,
  Loader2,
  Download,
  Info,
  HelpCircle,
  CheckCircle2,
  Circle,
  XCircle,
  AlertTriangle,
  ChevronRight,
  Terminal,
  Package,
  Truck,
  Clock,
  DollarSign,
  FileSpreadsheet,
  CalendarDays,
  BadgePercent,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { AIParamAssistant } from "../../pages/AI-Param-Assistant"
import { ScrollArea } from "@/components/ui/scroll-area"
import { executeFaturistaPipeline } from "@/app/actions/import-faturista-actions"
import { useToast } from "@/hooks/use-toast"
import { PipelineResult } from "@/lib/firebase"
import { Progress } from "@/components/ui/progress"
import { downloadMultipleSheets } from "@/lib/excel-utils"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"

// ─── Tipos ────────────────────────────────────────────────────────────────────

type StageStatus = "idle" | "running" | "done" | "error" | "warn"

interface Stage {
  id: string
  label: string
  description: string
  status: StageStatus
}

interface LogEntry {
  time: string
  message: string
  type: "info" | "success" | "error" | "warn" | "step"
}

// ─── Constantes ───────────────────────────────────────────────────────────────

const DEFAULT_META_CINTAS    = 200.0
const DEFAULT_META_LIBERACAO = 200.0
const EMPRESAS_PADRAO        = "RK01, BV01"

const INITIAL_STAGES: Stage[] = [
  { id: "load",    label: "Carregar arquivo",            description: "Tempos e Movimentos (aba Faturamento)",         status: "idle" },
  { id: "filter",  label: "Etapa 1 — Filtros",           description: "Período + Empresas + horários válidos",         status: "idle" },
  { id: "adjust",  label: "Etapa 2 — Ajuste de horários",description: "Correção de virada de dia (após meia-noite)",   status: "idle" },
  { id: "metas",   label: "Etapa 3 — Metas diárias",     description: "Dias úteis no mês → meta por dia",             status: "idle" },
  { id: "cintas",  label: "Etapa 4 — Cintas",            description: "≤22h=100% | 22–23h=85% | 23–00h=75% | >00h=0%",status: "idle" },
  { id: "lib",     label: "Etapa 5 — Liberação",         description: "≤20h30=100% | –21h=85% | –22h=75% | >22h=0%",  status: "idle" },
  { id: "export",  label: "Exportar / Salvar Firebase",  description: "Cintas + Liberação separados por processo",     status: "idle" },
]

const REGRAS = [
  { label: "Cintas — 100%",     detail: "Término ≤ 22:00",             color: "border-emerald-200 bg-emerald-50 text-emerald-700" },
  { label: "Cintas — 85%",      detail: "22:00 < término ≤ 23:00",     color: "border-blue-200 bg-blue-50 text-blue-700" },
  { label: "Cintas — 75%",      detail: "23:00 < término ≤ 00:00",     color: "border-amber-200 bg-amber-50 text-amber-700" },
  { label: "Cintas — 0%",       detail: "Término após 00:00",           color: "border-red-200 bg-red-50 text-red-700" },
  { label: "Liberação — 100%",  detail: "Término ≤ 20:30",             color: "border-emerald-200 bg-emerald-50 text-emerald-700" },
  { label: "Liberação — 85%",   detail: "20:30 < término ≤ 21:00",     color: "border-blue-200 bg-blue-50 text-blue-700" },
  { label: "Liberação — 75%",   detail: "21:00 < término ≤ 22:00",     color: "border-amber-200 bg-amber-50 text-amber-700" },
  { label: "Liberação — 0%",    detail: "Término após 22:00",           color: "border-red-200 bg-red-50 text-red-700" },
]

// ─── Helpers visuais ──────────────────────────────────────────────────────────

function StageIcon({ status }: { status: StageStatus }) {
  if (status === "running") return <Loader2 className="size-4 animate-spin text-primary shrink-0" />
  if (status === "done")    return <CheckCircle2 className="size-4 text-emerald-500 shrink-0" />
  if (status === "error")   return <XCircle className="size-4 text-destructive shrink-0" />
  if (status === "warn")    return <AlertTriangle className="size-4 text-amber-500 shrink-0" />
  return <Circle className="size-4 text-muted-foreground/30 shrink-0" />
}

const stageBg: Record<StageStatus, string> = {
  idle:    "bg-muted/20 border-border/40",
  running: "bg-primary/5 border-primary/30",
  done:    "bg-emerald-50 border-emerald-200",
  error:   "bg-red-50 border-red-200",
  warn:    "bg-amber-50 border-amber-200",
}

const stageLabel: Record<StageStatus, string> = {
  idle:    "text-muted-foreground",
  running: "text-primary font-semibold",
  done:    "text-emerald-700 font-medium",
  error:   "text-red-700 font-semibold",
  warn:    "text-amber-700 font-medium",
}

const logColor: Record<LogEntry["type"], string> = {
  info:    "text-slate-400",
  success: "text-emerald-500",
  error:   "text-red-400 font-semibold",
  warn:    "text-amber-400",
  step:    "text-primary font-semibold",
}

const logPrefix: Record<LogEntry["type"], string> = {
  info:    "   ",
  success: "✅ ",
  error:   "❌ ",
  warn:    "⚠️  ",
  step:    "▶  ",
}

function pctBadge(pct: number) {
  if (pct >= 1)    return <Badge className="bg-emerald-100 text-emerald-700 border-emerald-200 hover:bg-emerald-100">100%</Badge>
  if (pct >= 0.85) return <Badge className="bg-blue-100 text-blue-700 border-blue-200 hover:bg-blue-100">85%</Badge>
  if (pct >= 0.75) return <Badge className="bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-100">75%</Badge>
  return <Badge className="bg-red-100 text-red-700 border-red-200 hover:bg-red-100">0%</Badge>
}

// ─── ResultViewer ─────────────────────────────────────────────────────────────

function FaturistaResultViewer({ result }: { result: PipelineResult }) {
  const [activeTab, setActiveTab] = React.useState<"cintas" | "liberacao">("cintas")

  const cintas:    any[] = result.dadosCintas    ?? []
  const liberacao: any[] = result.dadosLiberacao ?? []
  const resumo:    any[] = result.resumoMensal   ?? []

  if (!cintas.length && !liberacao.length) return null

  const totalCintas    = cintas.reduce((a: number, r: any) => a + (r["Valor_Cintas_Dia"] ?? 0), 0)
  const totalLiberacao = liberacao.reduce((a: number, r: any) => a + (r["Valor_Liberacao_Dia"] ?? 0), 0)

  // Distribuição de percentuais para o processo ativo
  const activeRows = activeTab === "cintas" ? cintas : liberacao
  const percCol    = activeTab === "cintas" ? "Perc_Meta_Cintas" : "Perc_Meta_Liberacao"
  const valorCol   = activeTab === "cintas" ? "Valor_Cintas_Dia" : "Valor_Liberacao_Dia"
  const metaOkCol  = activeTab === "cintas" ? "Meta_OK_Cintas"   : "Meta_OK_Liberacao"

  const dist = {
    p100: activeRows.filter(r => r[percCol] >= 1).length,
    p85:  activeRows.filter(r => r[percCol] >= 0.85 && r[percCol] < 1).length,
    p75:  activeRows.filter(r => r[percCol] >= 0.75 && r[percCol] < 0.85).length,
    p0:   activeRows.filter(r => r[percCol] < 0.75).length,
  }

  const TABS = [
    { id: "cintas",    label: "Cintas",    icon: Package, count: cintas.length    },
    { id: "liberacao", label: "Liberação", icon: Truck,   count: liberacao.length },
  ] as const

  const TABLE_COLS = ["DATA", "EMPRESA", "CIDADE", "INICIO", "TERMINO", "TERMINO_AJUSTADO", percCol, metaOkCol, valorCol]
    .filter(c => activeRows.length && c in activeRows[0])

  function fmtVal(col: string, val: any) {
    if (val == null || val === "") return <span className="text-muted-foreground/40">—</span>
    if (col === percCol)  return pctBadge(typeof val === "number" ? val : parseFloat(val))
    if (col === metaOkCol) return val
      ? <span className="text-emerald-600 font-semibold">✓ Sim</span>
      : <span className="text-red-500">✗ Não</span>
    if (col === valorCol && typeof val === "number") return `R$ ${val.toFixed(2)}`
    if (col === "TERMINO_AJUSTADO" && val) return String(val).slice(11, 16) || String(val)
    if (col === "DATA" && val) return String(val).slice(0, 10)
    return String(val)
  }

  const labelMap: Record<string, string> = {
    DATA: "Data", EMPRESA: "Empresa", CIDADE: "Cidade",
    INICIO: "Início", TERMINO: "Término", TERMINO_AJUSTADO: "Término Aj.",
    Perc_Meta_Cintas: "% Meta", Perc_Meta_Liberacao: "% Meta",
    Meta_OK_Cintas: "Meta OK", Meta_OK_Liberacao: "Meta OK",
    Valor_Cintas_Dia: "Valor (R$)", Valor_Liberacao_Dia: "Valor (R$)",
  }

  return (
    <div className="space-y-4 animate-in fade-in duration-500">

      {/* Totais */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {[
          { label: "Total Cintas",    value: `R$ ${totalCintas.toFixed(2)}`,    icon: Package,  highlight: true  },
          { label: "Total Liberação", value: `R$ ${totalLiberacao.toFixed(2)}`, icon: Truck,    highlight: false },
          { label: "Total Geral",     value: `R$ ${(totalCintas + totalLiberacao).toFixed(2)}`, icon: DollarSign, highlight: true },
          { label: "Registros",       value: cintas.length + liberacao.length,  icon: CalendarDays, highlight: false },
        ].map(stat => {
          const Icon = stat.icon
          return (
            <div key={stat.label} className={cn(
              "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
              stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
            )}>
              <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
              </div>
              <div className="min-w-0">
                <p className={cn("text-sm font-bold leading-tight truncate",
                  stat.highlight ? "text-primary" : "text-foreground")}>
                  {typeof stat.value === "number" ? stat.value.toLocaleString("pt-BR") : stat.value}
                </p>
                <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
              </div>
            </div>
          )
        })}
      </div>

      {/* Resumo mensal por empresa */}
      {resumo.length > 0 && (
        <div className="rounded-xl border border-border/60 bg-card shadow-sm overflow-hidden">
          <div className="px-4 py-2.5 border-b bg-muted/10">
            <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Resumo Mensal por Empresa</span>
          </div>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="text-[10px] font-bold uppercase">Empresa</TableHead>
                <TableHead className="text-[10px] font-bold uppercase text-right">Cintas</TableHead>
                <TableHead className="text-[10px] font-bold uppercase text-right">Liberação</TableHead>
                <TableHead className="text-[10px] font-bold uppercase text-right">Total</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {resumo.map((r: any, i: number) => (
                <TableRow key={i} className="text-xs">
                  <TableCell className="font-semibold">{r.empresa}</TableCell>
                  <TableCell className="text-right font-mono">R$ {(r.bonificacaoCintas ?? 0).toFixed(2)}</TableCell>
                  <TableCell className="text-right font-mono">R$ {(r.bonificacaoLiberacao ?? 0).toFixed(2)}</TableCell>
                  <TableCell className="text-right font-mono font-bold text-primary">R$ {(r.bonificacaoTotal ?? 0).toFixed(2)}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
      )}

      {/* Distribuição de percentuais */}
      <div className="grid grid-cols-4 gap-2">
        {[
          { pct: "100%", count: dist.p100, color: "bg-emerald-50 border-emerald-200 text-emerald-700" },
          { pct: "85%",  count: dist.p85,  color: "bg-blue-50 border-blue-200 text-blue-700" },
          { pct: "75%",  count: dist.p75,  color: "bg-amber-50 border-amber-200 text-amber-700" },
          { pct: "0%",   count: dist.p0,   color: "bg-red-50 border-red-200 text-red-700" },
        ].map(d => (
          <div key={d.pct} className={cn("rounded-xl border px-3 py-2.5 text-center shadow-sm", d.color)}>
            <p className="text-lg font-bold leading-tight">{d.count}</p>
            <p className="text-[10px] font-semibold leading-tight">{d.pct} da meta</p>
          </div>
        ))}
      </div>

      {/* Tabs + tabela */}
      <div className="flex gap-2">
        {TABS.map(tab => {
          const Icon = tab.icon
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={cn(
                "flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold border transition-all",
                activeTab === tab.id
                  ? "bg-primary text-primary-foreground border-primary shadow-sm"
                  : "bg-card border-border/60 text-muted-foreground hover:bg-muted/30"
              )}
            >
              <Icon className="size-3.5" />
              {tab.label}
              <span className={cn(
                "text-[10px] font-bold px-1.5 py-0.5 rounded-full",
                activeTab === tab.id ? "bg-white/20" : "bg-muted"
              )}>
                {tab.count}
              </span>
            </button>
          )
        })}
      </div>

      {activeRows.length > 0 && (
        <div className="rounded-xl border border-border/60 bg-card shadow-sm overflow-hidden">
          <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
            <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
              {activeTab === "cintas" ? "Entrega de Cintas para Separação" : "Liberação para Roteirização"}
            </span>
            <span className="text-[10px] text-muted-foreground">{activeRows.length} registros</span>
          </div>
          <ScrollArea className="h-[440px]">
            <div className="overflow-x-auto">
              <Table>
                <TableHeader className="sticky top-0 bg-muted/80 backdrop-blur-sm z-10">
                  <TableRow>
                    {TABLE_COLS.map(col => (
                      <TableHead key={col} className="text-[10px] font-bold uppercase whitespace-nowrap px-2 py-2">
                        {labelMap[col] ?? col}
                      </TableHead>
                    ))}
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {activeRows.map((row, i) => (
                    <TableRow key={i} className={cn(
                      "text-xs",
                      row[percCol] === 0 && "bg-red-50/40",
                      row[percCol] >= 1  && "bg-emerald-50/30",
                    )}>
                      {TABLE_COLS.map(col => (
                        <TableCell key={col} className="px-2 py-1.5 whitespace-nowrap">
                          {fmtVal(col, row[col])}
                        </TableCell>
                      ))}
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          </ScrollArea>
        </div>
      )}
    </div>
  )
}

// ─── Componente principal ─────────────────────────────────────────────────────

export function FaturistaPipelineView() {
  const [year, setYear]       = React.useState(new Date().getFullYear())
  const [month, setMonth]     = React.useState(new Date().getMonth() + 1)
  const [fileTempos, setFileTempos] = React.useState<File | null>(null)
  const [metaCintas, setMetaCintas]       = React.useState(DEFAULT_META_CINTAS)
  const [metaLiberacao, setMetaLiberacao] = React.useState(DEFAULT_META_LIBERACAO)
  const [empresas, setEmpresas]           = React.useState(EMPRESAS_PADRAO)
  const [isExecuting, setIsExecuting]     = React.useState(false)
  const [progress, setProgress]           = React.useState(0)
  const [stages, setStages]               = React.useState<Stage[]>(INITIAL_STAGES)
  const [logs, setLogs]                   = React.useState<LogEntry[]>([])
  const [lastResult, setLastResult]       = React.useState<PipelineResult | null>(null)
  const [stats, setStats]                 = React.useState<{
    viradas: number; diasUteis: number; totalCintas: number; totalLib: number
  } | null>(null)
  const logEndRef = React.useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  React.useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") => {
    const time = new Date().toLocaleTimeString("pt-BR")
    setLogs(prev => [...prev, { time, message, type }])
  }

  const setStage = (id: string, status: StageStatus) =>
    setStages(prev => prev.map(s => s.id === id ? { ...s, status } : s))

  const resetStages = () => setStages(INITIAL_STAGES.map(s => ({ ...s, status: "idle" })))

  const canRun = !!fileTempos

  const runPipeline = async (downloadOnly = false) => {
    if (!canRun) return
    setIsExecuting(true)
    setProgress(0)
    setLogs([])
    setStats(null)
    resetStages()

    try {
      addLog(`Pipeline Faturista iniciado — ${String(month).padStart(2, "0")}/${year}`, "step")
      addLog(`Arquivo: ${fileTempos!.name}`)
      addLog(`Metas: Cintas R$ ${metaCintas.toFixed(2)} · Liberação R$ ${metaLiberacao.toFixed(2)}`)
      addLog(`Empresas: ${empresas}`)

      // ── Load ──────────────────────────────────────────────────────────
      setStage("load", "running")
      setProgress(8)

      const formData = new FormData()
      formData.append("year",          year.toString())
      formData.append("month",         month.toString())
      formData.append("fileTempos",    fileTempos!)
      formData.append("metaCintas",    metaCintas.toString())
      formData.append("metaLiberacao", metaLiberacao.toString())
      formData.append("empresas",      empresas)

      const response = await executeFaturistaPipeline(formData)
      if (!response?.success) throw new Error(response?.error || "Erro desconhecido no servidor.")

      setStage("load", "done")
      addLog(`Dados carregados: ${response.result.totalRegistros ?? "?"} registros na aba Faturamento.`, "success")
      setProgress(20)

      // ── Filtros ───────────────────────────────────────────────────────
      addLog("Etapa 1 — Aplicando filtros de período, empresa e horário...", "step")
      setStage("filter", "running")
      setProgress(32)
      await new Promise(r => setTimeout(r, 120))
      setStage("filter", "done")
      addLog(`${response.result.registrosFiltrados ?? "?"} registros após filtros.`, "success")
      setProgress(45)

      // ── Ajuste horários ───────────────────────────────────────────────
      addLog("Etapa 2 — Ajustando viradas de dia (após meia-noite)...", "step")
      setStage("adjust", "running")
      setProgress(54)
      await new Promise(r => setTimeout(r, 100))
      const viradas: number = response.result.viradas ?? 0
      if (viradas > 0) {
        addLog(`${viradas} registros com virada de dia corrigidos.`, "warn")
        setStage("adjust", "warn")
      } else {
        setStage("adjust", "done")
        addLog("Nenhuma virada de dia detectada.", "success")
      }
      setProgress(63)

      // ── Metas diárias ─────────────────────────────────────────────────
      addLog("Etapa 3 — Calculando dias úteis e metas diárias...", "step")
      setStage("metas", "running")
      setProgress(70)
      await new Promise(r => setTimeout(r, 80))
      setStage("metas", "done")
      const diasUteis: number = response.result.diasUteis ?? 0
      addLog(`${diasUteis} dias úteis → Meta/dia: Cintas R$ ${(metaCintas / diasUteis).toFixed(2)} · Lib R$ ${(metaLiberacao / diasUteis).toFixed(2)}`, "success")
      setProgress(78)

      // ── Cintas ────────────────────────────────────────────────────────
      addLog("Etapa 4 — Processando Entrega de Cintas...", "step")
      setStage("cintas", "running")
      setProgress(84)
      await new Promise(r => setTimeout(r, 80))
      setStage("cintas", "done")
      const totalCintas: number = response.result.totalCintas ?? 0
      addLog(`Cintas: ${(response.result.dadosCintas ?? []).length} registros · R$ ${totalCintas.toFixed(2)}`, "success")
      setProgress(90)

      // ── Liberação ─────────────────────────────────────────────────────
      addLog("Etapa 5 — Processando Liberação para Roteirização...", "step")
      setStage("lib", "running")
      setProgress(95)
      await new Promise(r => setTimeout(r, 80))
      setStage("lib", "done")
      const totalLib: number = response.result.totalLiberacao ?? 0
      addLog(`Liberação: ${(response.result.dadosLiberacao ?? []).length} registros · R$ ${totalLib.toFixed(2)}`, "success")
      setProgress(97)

      setStats({ viradas, diasUteis, totalCintas, totalLib })
      setLastResult(response.result)

      // ── Export ────────────────────────────────────────────────────────
      setStage("export", "running")
      setProgress(99)

      if (downloadOnly) {
        addLog("Gerando Excel com arquivos separados por processo...", "step")
        downloadMultipleSheets(
          [
            { data: response.result.dadosCintas    ?? [], name: "Prazo_Cintas"    },
            { data: response.result.dadosLiberacao ?? [], name: "Prazo_Liberacao" },
            { data: response.result.resumoMensal   ?? [], name: "Resumo_Mensal"   },
          ],
          `Faturista_${month}_${year}`
        )
        addLog("Arquivo Excel baixado.", "success")
      } else {
        addLog("Dados sincronizados com Firebase.", "success")
      }

      setStage("export", "done")
      setProgress(100)
      addLog(`Pipeline concluído em ${new Date().toLocaleTimeString("pt-BR")}.`, "success")

      toast({
        title: downloadOnly ? "Excel pronto" : "Pipeline concluído",
        description: response.result.summary ?? "",
      })

    } catch (error: any) {
      const msg = error?.message || String(error)
      addLog(`FALHA: ${msg}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro no pipeline Faturista", description: msg })
    } finally {
      setIsExecuting(false)
    }
  }

  const doneCount = stages.filter(s => s.status === "done" || s.status === "warn").length
  const hasError  = stages.some(s => s.status === "error")

  return (
    <div className="space-y-6">

      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Info className="size-4 text-primary" />
          <AlertTitle className="mb-0">Análise de Faturamento — Cintas & Liberação</AlertTitle>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="size-4 text-muted-foreground cursor-help" />
              </TooltipTrigger>
              <TooltipContent className="max-w-xs">
                <p>Processa os tempos de Entrega de Cintas e Liberação para Roteirização, calculando bonificação por faixa de horário.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <AlertDescription className="text-sm mt-2">
          Bonificação por cumprimento de horários — <strong>100% / 85% / 75% / 0%</strong> conforme faixa de término.
          Viradas de dia ajustadas automaticamente.
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <BadgePercent className="size-5 text-primary" />
                Configuração do Pipeline Faturista
              </CardTitle>
              <CardDescription>Tempos e Movimentos (aba Faturamento)</CardDescription>
            </CardHeader>

            <CardContent className="space-y-5">
              {/* Período */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Ano</Label>
                  <Input type="number" value={year} onChange={e => setYear(parseInt(e.target.value))} />
                </div>
                <div className="space-y-2">
                  <Label>Mês</Label>
                  <Input type="number" min={1} max={12} value={month} onChange={e => setMonth(parseInt(e.target.value))} />
                </div>
              </div>

              <AIParamAssistant onParamsUpdate={(m, y) => { setMonth(m); setYear(y) }} currentMonth={month} currentYear={year} />

              {/* Metas */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label className="flex items-center gap-1.5">
                    <Package className="size-3.5 text-muted-foreground" /> Meta Cintas (R$/mês)
                  </Label>
                  <Input
                    type="number"
                    step="10"
                    value={metaCintas}
                    onChange={e => setMetaCintas(parseFloat(e.target.value) || 0)}
                  />
                </div>
                <div className="space-y-2">
                  <Label className="flex items-center gap-1.5">
                    <Truck className="size-3.5 text-muted-foreground" /> Meta Liberação (R$/mês)
                  </Label>
                  <Input
                    type="number"
                    step="10"
                    value={metaLiberacao}
                    onChange={e => setMetaLiberacao(parseFloat(e.target.value) || 0)}
                  />
                </div>
              </div>

              {/* Empresas */}
              <div className="space-y-2">
                <Label className="flex items-center gap-1.5">
                  <Clock className="size-3.5 text-muted-foreground" /> Empresas (separadas por vírgula)
                </Label>
                <Input
                  value={empresas}
                  onChange={e => setEmpresas(e.target.value)}
                  placeholder="RK01, BV01"
                />
              </div>

              {/* Arquivo */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold text-primary">Arquivo de Tempos e Movimentos</Label>
                <div className="flex items-center gap-2 bg-background px-3 py-2.5 rounded-lg border text-xs">
                  <FileSpreadsheet className="size-3.5 text-muted-foreground shrink-0" />
                  <span className={cn(
                    "text-[10px] font-bold px-1.5 py-0.5 rounded shrink-0",
                    "bg-primary/10 text-primary"
                  )}>Faturamento</span>
                  <span className="truncate flex-1 font-medium text-muted-foreground">
                    {fileTempos ? fileTempos.name : <span className="italic">Tempos e Movimentos - PR, MS.xlsx</span>}
                  </span>
                  {fileTempos && (
                    <Button variant="ghost" size="icon" className="size-6 shrink-0" onClick={() => setFileTempos(null)}>
                      <Trash2 className="size-3 text-destructive/70" />
                    </Button>
                  )}
                  <Button asChild variant="outline" size="sm" className="h-6 text-[10px] px-2 cursor-pointer shrink-0">
                    <Label htmlFor="faturista-upload">{fileTempos ? "Trocar" : "Selecionar"}</Label>
                  </Button>
                  <Input
                    id="faturista-upload"
                    type="file"
                    className="hidden"
                    accept=".xlsx,.xls"
                    onChange={e => {
                      if (e.target.files?.[0]) setFileTempos(e.target.files[0])
                      e.target.value = ""
                    }}
                  />
                </div>
              </div>

              {/* Progress */}
              {(isExecuting || progress > 0) && (
                <div className="space-y-2 pt-1">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-primary">
                      {hasError ? "Erro na execução" : progress === 100 ? "Concluído" : "Processando..."}
                    </span>
                    <span className="text-[10px] font-mono font-bold text-muted-foreground">{progress}%</span>
                  </div>
                  <Progress
                    value={progress}
                    className={cn("h-2 transition-all", hasError && "[&>div]:bg-destructive")}
                  />
                  <div className="flex justify-between text-[9px] text-muted-foreground">
                    <span>{doneCount}/{stages.length} etapas</span>
                    <span>
                      {isExecuting
                        ? stages.find(s => s.status === "running")?.label ?? "..."
                        : progress === 100 ? "Pipeline finalizado" : ""}
                    </span>
                  </div>
                </div>
              )}
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button
                variant="outline"
                size="sm"
                className="flex-1 h-9 text-xs font-semibold border-slate-300 text-slate-600 hover:bg-slate-50 hover:text-slate-800 hover:border-slate-400 transition-all"
                onClick={() => runPipeline(true)}
                disabled={isExecuting || !canRun}
              >
                <Download className="mr-1.5 size-3.5" /> Exportar Excel
              </Button>
              <Button
                size="sm"
                className="flex-1 h-9 text-xs font-semibold bg-primary hover:bg-primary/90 shadow-sm transition-all"
                onClick={() => runPipeline(false)}
                disabled={isExecuting || !canRun}
              >
                {isExecuting
                  ? <><Loader2 className="mr-1.5 size-3.5 animate-spin" /> Processando...</>
                  : <><Play className="mr-1.5 size-3.5 fill-current" /> Executar Pipeline</>}
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">

          {/* Etapas */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Etapas de Execução
              </span>
            </div>
            <div className="p-3 space-y-2">
              {stages.map((stage, idx) => (
                <div key={stage.id} className="flex items-start gap-2">
                  <div className="flex flex-col items-center pt-0.5">
                    <StageIcon status={stage.status} />
                    {idx < stages.length - 1 && (
                      <div className={cn(
                        "w-px mt-1 min-h-[14px]",
                        stage.status === "done" ? "bg-emerald-300" : "bg-border/60"
                      )} />
                    )}
                  </div>
                  <div className={cn("flex-1 px-2.5 py-1.5 rounded-lg border text-xs transition-all", stageBg[stage.status])}>
                    <p className={cn("leading-tight", stageLabel[stage.status])}>{stage.label}</p>
                    <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{stage.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Stats pós-execução */}
          {stats && (
            <div className="grid grid-cols-2 gap-2">
              {[
                { label: "Dias úteis",         value: stats.diasUteis,                              icon: CalendarDays, highlight: false },
                { label: "Viradas de dia",      value: stats.viradas,                               icon: Clock,        highlight: false },
                { label: "Total Cintas",        value: `R$ ${stats.totalCintas.toFixed(2)}`,        icon: Package,      highlight: true  },
                { label: "Total Liberação",     value: `R$ ${stats.totalLib.toFixed(2)}`,           icon: Truck,        highlight: true  },
              ].map(stat => {
                const Icon = stat.icon
                return (
                  <div key={stat.label} className={cn(
                    "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                    stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                  )}>
                    <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                      stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                      <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                    </div>
                    <div className="min-w-0">
                      <p className={cn("text-sm font-bold leading-tight truncate",
                        stat.highlight ? "text-primary" : "text-foreground")}>
                        {typeof stat.value === "number" ? stat.value.toLocaleString("pt-BR") : stat.value}
                      </p>
                      <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          {/* Regras de bonificação */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Regras de Bonificação
              </span>
            </div>
            <div className="p-3 space-y-1.5">
              {REGRAS.map((rule, idx) => (
                <div key={idx} className={cn(
                  "flex items-center gap-2 rounded-lg border px-2.5 py-1.5 text-[11px]",
                  rule.color
                )}>
                  <ChevronRight className="size-3 shrink-0 opacity-60" />
                  <span className="font-semibold shrink-0">{rule.label}</span>
                  <span className="opacity-50 shrink-0">→</span>
                  <span className="text-[10px]">{rule.detail}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[180px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0
                  ? <span className="text-slate-500 italic">Aguardando execução...</span>
                  : logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))
                }
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>

        </div>
      </div>

      {lastResult && !isExecuting && <FaturistaResultViewer result={lastResult} />}
    </div>
  )
}

"use client"

import * as React from "react"
import * as XLSX from "xlsx"
import { importFuncionariosAction } from "@/app/actions/import-funcionarios-action"
import {
  PlusCircle, Edit, Trash2, MoreHorizontal, Loader2, User, Search, Upload,
  Terminal, Users, CheckCircle2, Info, BadgeCheck,
} from "lucide-react"
import {
  Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter,
} from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table"
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter, DialogClose,
} from "@/components/ui/dialog"
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import {
  DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { ScrollArea } from "@/components/ui/scroll-area"
import { useToast } from "@/hooks/use-toast"
import { collection, onSnapshot, updateDoc, deleteDoc, doc, setDoc } from "firebase/firestore"
import { db } from "@/lib/firebase"
import { cn } from "@/lib/utils"

type Funcionario = {
  id: string
  MATRICULA: string
  NOME_COMPLETO: string
  CARGO: string
  STATUS: string
  [key: string]: any
}

type LogEntry = { time: string; message: string; type: "info" | "success" | "error" | "warn" | "step" }

const searchableFields = ["NOME_COMPLETO", "MATRICULA", "CARGO", "STATUS"]

const logColor: Record<LogEntry["type"], string> = {
  info: "text-slate-400", success: "text-emerald-500",
  error: "text-red-400 font-semibold", warn: "text-amber-400", step: "text-primary font-semibold",
}
const logPrefix: Record<LogEntry["type"], string> = {
  info: "   ", success: "✅ ", error: "❌ ", warn: "⚠️  ", step: "▶  ",
}

export function FuncionariosPipelineView() {
  const { toast } = useToast()
  const [items, setItems] = React.useState<Funcionario[]>([])
  const [loading, setLoading] = React.useState(true)
  const [search, setSearch] = React.useState("")
  const [isFormOpen, setFormOpen] = React.useState(false)
  const [editingItem, setEditingItem] = React.useState<Funcionario | null>(null)
  const [formData, setFormData] = React.useState<Partial<Funcionario>>({})
  const [isAlertOpen, setAlertOpen] = React.useState(false)
  const [itemToDelete, setItemToDelete] = React.useState<Funcionario | null>(null)
  const [isProcessing, setProcessing] = React.useState(false)
  const [isImportOpen, setImportOpen] = React.useState(false)
  const [isImporting, setImporting] = React.useState(false)
  const [importFile, setImportFile] = React.useState<File | null>(null)
  const [logs, setLogs] = React.useState<LogEntry[]>([])
  const logEndRef = React.useRef<HTMLDivElement>(null)

  React.useEffect(() => { logEndRef.current?.scrollIntoView({ behavior: "smooth" }) }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") => {
    const time = new Date().toLocaleTimeString("pt-BR")
    setLogs(prev => [...prev, { time, message, type }])
  }

  React.useEffect(() => {
    addLog("Conectando à coleção docs_funcionarios...", "step")
    const unsubscribe = onSnapshot(collection(db, "docs_funcionarios"), (snapshot) => {
      const data = snapshot.docs.map(d => ({ id: d.id, ...d.data() } as Funcionario))
      setItems(data)
      setLoading(false)
      addLog(`${data.length} funcionário(s) carregado(s).`, "success")
    }, (error) => {
      addLog(`Erro ao buscar dados: ${error.message}`, "error")
      toast({ variant: "destructive", title: "Erro ao buscar dados", description: error.message })
      setLoading(false)
    })
    return () => unsubscribe()
  }, [toast])

  const openForm = (item: Funcionario | null = null) => {
    setEditingItem(item)
    setFormData(item ? { ...item } : {})
    setFormOpen(true)
  }

  const handleSave = async () => {
    setProcessing(true)
    try {
      const { id, ...dataToSave } = formData
      if (editingItem) {
        await updateDoc(doc(db, "docs_funcionarios", editingItem.id), dataToSave)
        addLog(`Funcionário ${editingItem.NOME_COMPLETO} atualizado.`, "success")
        toast({ title: "Sucesso!", description: "Funcionário atualizado." })
      } else {
        const rawName = dataToSave.NOME_COMPLETO || ""
        if (!rawName) throw new Error("O campo 'Nome Completo' é obrigatório.")
        const docId = rawName.trim().toUpperCase().replace(/\//g, ' ')
        await setDoc(doc(db, "docs_funcionarios", docId), dataToSave)
        addLog(`Funcionário ${rawName} adicionado.`, "success")
        toast({ title: "Sucesso!", description: "Funcionário adicionado." })
      }
      setFormOpen(false)
    } catch (e: any) {
      addLog(`Erro ao salvar: ${e.message}`, "error")
      toast({ variant: "destructive", title: "Erro ao salvar", description: e.message })
    } finally {
      setProcessing(false)
    }
  }

  const openDeleteAlert = (item: Funcionario) => { setItemToDelete(item); setAlertOpen(true) }

  const handleDelete = async () => {
    if (!itemToDelete) return
    setProcessing(true)
    try {
      await deleteDoc(doc(db, "docs_funcionarios", itemToDelete.id))
      addLog(`Funcionário ${itemToDelete.NOME_COMPLETO} excluído.`, "warn")
      toast({ title: "Excluído", description: "O item foi removido." })
      setAlertOpen(false)
    } catch (e: any) {
      addLog(`Erro ao excluir: ${e.message}`, "error")
      toast({ variant: "destructive", title: "Erro ao excluir", description: e.message })
    } finally {
      setProcessing(false)
    }
  }

  const handleImport = async () => {
    if (!importFile) return
    setImporting(true)
    addLog(`Lendo arquivo: ${importFile.name}...`, "step")

    const reader = new FileReader()
    reader.onload = async (e) => {
      try {
        const data = e.target?.result
        if (!data) throw new Error("Não foi possível ler o arquivo.")
        const workbook = XLSX.read(data, { type: 'array' })
        const sheetName = workbook.SheetNames[0]
        const worksheet = workbook.Sheets[sheetName]
        const jsonData = XLSX.utils.sheet_to_json(worksheet)
        addLog(`${jsonData.length} registros encontrados na planilha.`, "info")

        const result = await importFuncionariosAction(jsonData)
        if (result.success) {
          addLog(result.message, "success")
          toast({ title: "Sucesso!", description: result.message })
          setImportOpen(false)
          setImportFile(null)
        } else {
          addLog(`Erro na importação: ${result.message}`, "error")
          toast({ variant: "destructive", title: "Erro na importação", description: result.message })
        }
      } catch (err: any) {
        addLog(`Erro ao processar arquivo: ${err.message}`, "error")
        toast({ variant: "destructive", title: "Erro ao processar arquivo", description: err.message })
      } finally {
        setImporting(false)
      }
    }
    reader.onerror = () => {
      addLog("Não foi possível ler o arquivo.", "error")
      toast({ variant: "destructive", title: "Erro de leitura", description: "Não foi possível ler o arquivo." })
      setImporting(false)
    }
    reader.readAsArrayBuffer(importFile)
  }

  const handleInputChange = (name: string, value: any) => {
    setFormData(prev => ({ ...prev, [name]: value }))
  }

  const filteredItems = items.filter(item =>
    search ? searchableFields.some(field =>
      String(item[field] ?? "").toLowerCase().includes(search.toLowerCase())
    ) : true
  )

  const ativos = items.filter(i => String(i.STATUS).toUpperCase() === "ATIVO").length
  const inativos = items.length - ativos

  const fields = [
    { name: "NOME_COMPLETO", label: "Nome Completo", type: "text" },
    { name: "MATRICULA", label: "Matrícula", type: "text" },
    { name: "CPF", label: "CPF", type: "text" },
    { name: "CARGO", label: "Cargo", type: "text" },
    { name: "STATUS", label: "Status", type: "text" },
  ]

  return (
    <div className="space-y-6">
      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Info className="size-4 text-primary" />
          <AlertTitle className="mb-0">Cadastro de Funcionários</AlertTitle>
        </div>
        <AlertDescription className="text-sm mt-2">
          Gerencie os dados mestres de funcionários. O ID do documento é gerado a partir do <strong>Nome Completo</strong>.
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <User className="size-5 text-primary" />
                Funcionários
              </CardTitle>
              <CardDescription>Coleção: docs_funcionarios</CardDescription>
            </CardHeader>

            <CardContent className="space-y-4">
              <div className="relative flex-1">
                <Search className="absolute left-2.5 top-2.5 size-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar por Nome, Matrícula, Cargo..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="pl-8"
                />
              </div>

              <ScrollArea className="h-[500px] rounded-md border">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Nome Completo</TableHead>
                      <TableHead>Matrícula</TableHead>
                      <TableHead>Cargo</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead className="w-[60px]" />
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {loading ? (
                      <TableRow>
                        <TableCell colSpan={5} className="h-24 text-center">
                          <div className="flex justify-center items-center gap-2 text-muted-foreground">
                            <Loader2 className="size-4 animate-spin" /> Carregando...
                          </div>
                        </TableCell>
                      </TableRow>
                    ) : filteredItems.length > 0 ? (
                      filteredItems.map(item => (
                        <TableRow key={item.id}>
                          <TableCell className="font-medium">{item.NOME_COMPLETO}</TableCell>
                          <TableCell>{item.MATRICULA}</TableCell>
                          <TableCell>{item.CARGO}</TableCell>
                          <TableCell>
                            <span className={cn(
                              "text-[10px] font-bold px-2 py-0.5 rounded-full",
                              String(item.STATUS).toUpperCase() === "ATIVO"
                                ? "bg-emerald-100 text-emerald-700"
                                : "bg-slate-100 text-slate-600"
                            )}>
                              {item.STATUS}
                            </span>
                          </TableCell>
                          <TableCell className="text-right">
                            <DropdownMenu>
                              <DropdownMenuTrigger asChild>
                                <Button variant="ghost" className="h-8 w-8 p-0">
                                  <MoreHorizontal className="h-4 w-4" />
                                </Button>
                              </DropdownMenuTrigger>
                              <DropdownMenuContent align="end">
                                <DropdownMenuItem onClick={() => openForm(item)}>
                                  <Edit className="mr-2 h-4 w-4" /> Editar
                                </DropdownMenuItem>
                                <DropdownMenuItem onClick={() => openDeleteAlert(item)} className="text-destructive">
                                  <Trash2 className="mr-2 h-4 w-4" /> Excluir
                                </DropdownMenuItem>
                              </DropdownMenuContent>
                            </DropdownMenu>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell colSpan={5} className="h-24 text-center text-muted-foreground">
                          Nenhum funcionário encontrado.
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </ScrollArea>
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button variant="outline" size="sm" className="flex-1 h-9 text-xs font-semibold"
                onClick={() => setImportOpen(true)}>
                <Upload className="mr-1.5 size-3.5" /> Importar Excel/CSV
              </Button>
              <Button size="sm" className="flex-1 h-9 text-xs font-semibold bg-primary hover:bg-primary/90 shadow-sm"
                onClick={() => openForm()}>
                <PlusCircle className="mr-1.5 size-3.5" /> Novo Funcionário
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">
          <div className="grid grid-cols-1 gap-2">
            {[
              { label: "Total Cadastrados", value: items.length.toLocaleString("pt-BR"), icon: Users, highlight: false },
              { label: "Ativos", value: ativos.toLocaleString("pt-BR"), icon: CheckCircle2, highlight: true },
              { label: "Inativos / Outros", value: inativos.toLocaleString("pt-BR"), icon: BadgeCheck, highlight: false },
            ].map(stat => {
              const Icon = stat.icon
              return (
                <div key={stat.label} className={cn(
                  "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                  stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                )}>
                  <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                    stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                    <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                  </div>
                  <div>
                    <p className={cn("text-sm font-bold leading-tight", stat.highlight ? "text-primary" : "text-foreground")}>
                      {stat.value}
                    </p>
                    <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                  </div>
                </div>
              )
            })}
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[200px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0 ? (
                  <span className="text-slate-500 italic">Aguardando operações...</span>
                ) : (
                  logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))
                )}
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>
        </div>
      </div>

      {/* ── Dialog Form ── */}
      <Dialog open={isFormOpen} onOpenChange={setFormOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingItem ? "Editar" : "Novo"} Funcionário</DialogTitle>
            <DialogDescription>
              {editingItem ? "Altere os dados do funcionário abaixo." : "Preencha os dados do novo funcionário."}
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            {fields.map(field => (
              <div key={field.name} className="grid grid-cols-4 items-center gap-4">
                <Label htmlFor={field.name} className="text-right">{field.label}</Label>
                <Input
                  id={field.name}
                  type={field.type}
                  value={formData[field.name] ?? ""}
                  onChange={(e) => handleInputChange(field.name, e.target.value)}
                  className="col-span-3"
                  disabled={!!editingItem && field.name === "NOME_COMPLETO"}
                />
              </div>
            ))}
          </div>
          <DialogFooter>
            <DialogClose asChild><Button variant="outline">Cancelar</Button></DialogClose>
            <Button onClick={handleSave} disabled={isProcessing}>
              {isProcessing && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Salvar
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ── Dialog Import ── */}
      <Dialog open={isImportOpen} onOpenChange={setImportOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Importar Funcionários</DialogTitle>
            <DialogDescription>Selecione um arquivo Excel ou CSV para importar em lote.</DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid grid-cols-4 items-center gap-4">
              <Label htmlFor="import-file" className="text-right">Arquivo</Label>
              <Input
                id="import-file"
                type="file"
                className="col-span-3"
                accept=".xlsx,.xls,.csv"
                onChange={(e) => setImportFile(e.target.files?.[0] ?? null)}
              />
            </div>
            <p className="text-xs text-muted-foreground px-4 text-center">
              Cabeçalhos esperados: NOME_COMPLETO, MATRICULA, CPF, CARGO, STATUS.
            </p>
          </div>
          <DialogFooter>
            <DialogClose asChild><Button variant="outline">Cancelar</Button></DialogClose>
            <Button onClick={handleImport} disabled={isImporting || !importFile}>
              {isImporting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Confirmar Importação
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ── Alert Delete ── */}
      <AlertDialog open={isAlertOpen} onOpenChange={setAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Você tem certeza?</AlertDialogTitle>
            <AlertDialogDescription>Esta ação não pode ser desfeita. O item será excluído permanentemente.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-destructive hover:bg-destructive/90">
              {isProcessing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : "Excluir"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}

"use client"

import * as React from "react"
import { importMotivosDevAction } from "@/app/actions/import-motivos-dev-action"
import {
  PlusCircle, Edit, Trash2, MoreHorizontal, Loader2, Tag, Search, Upload,
  Terminal, Info, CheckCircle2, XCircle,
} from "lucide-react"
import {
  Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter,
} from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Table, TableBody, TableCell, TableHead, TableHeader, TableRow,
} from "@/components/ui/table"
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter, DialogClose,
} from "@/components/ui/dialog"
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import {
  DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { ScrollArea } from "@/components/ui/scroll-area"
import { useToast } from "@/hooks/use-toast"
import { collection, onSnapshot, addDoc, updateDoc, deleteDoc, doc } from "firebase/firestore"
import { db } from "@/lib/firebase"
import { cn } from "@/lib/utils"

type MotivoDev = {
  id: string
  MOTIVO_DEV: string
  CONSIDERA: "SIM" | "NAO"
}

type LogEntry = { time: string; message: string; type: "info" | "success" | "error" | "warn" | "step" }

const searchableFields = ["MOTIVO_DEV", "CONSIDERA"]

const logColor: Record<LogEntry["type"], string> = {
  info: "text-slate-400", success: "text-emerald-500",
  error: "text-red-400 font-semibold", warn: "text-amber-400", step: "text-primary font-semibold",
}
const logPrefix: Record<LogEntry["type"], string> = {
  info: "   ", success: "✅ ", error: "❌ ", warn: "⚠️  ", step: "▶  ",
}

export function MotivosDevPipelineView() {
  const { toast } = useToast()
  const [items, setItems] = React.useState<MotivoDev[]>([])
  const [loading, setLoading] = React.useState(true)
  const [search, setSearch] = React.useState("")
  const [isFormOpen, setFormOpen] = React.useState(false)
  const [editingItem, setEditingItem] = React.useState<MotivoDev | null>(null)
  const [formData, setFormData] = React.useState<Partial<MotivoDev>>({})
  const [isAlertOpen, setAlertOpen] = React.useState(false)
  const [itemToDelete, setItemToDelete] = React.useState<MotivoDev | null>(null)
  const [isProcessing, setProcessing] = React.useState(false)
  const [isImportOpen, setImportOpen] = React.useState(false)
  const [isImporting, setImporting] = React.useState(false)
  const [importFile, setImportFile] = React.useState<File | null>(null)
  const [logs, setLogs] = React.useState<LogEntry[]>([])
  const logEndRef = React.useRef<HTMLDivElement>(null)

  React.useEffect(() => { logEndRef.current?.scrollIntoView({ behavior: "smooth" }) }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") => {
    const time = new Date().toLocaleTimeString("pt-BR")
    setLogs(prev => [...prev, { time, message, type }])
  }

  React.useEffect(() => {
    addLog("Conectando à coleção docs_mot_devolucao...", "step")
    const unsubscribe = onSnapshot(collection(db, "docs_mot_devolucao"), (snapshot) => {
      const data = snapshot.docs.map(d => ({ id: d.id, ...d.data() } as MotivoDev))
      setItems(data)
      setLoading(false)
      addLog(`${data.length} motivo(s) carregado(s).`, "success")
    }, (error) => {
      addLog(`Erro ao buscar dados: ${error.message}`, "error")
      toast({ variant: "destructive", title: "Erro ao buscar dados", description: error.message })
      setLoading(false)
    })
    return () => unsubscribe()
  }, [toast])

  const openForm = (item: MotivoDev | null = null) => {
    setEditingItem(item)
    setFormData(item ? { ...item } : {})
    setFormOpen(true)
  }

  const handleSave = async () => {
    setProcessing(true)
    try {
      if (editingItem) {
        const { id, ...data } = formData
        await updateDoc(doc(db, "docs_mot_devolucao", editingItem.id), data)
        addLog(`Motivo "${editingItem.MOTIVO_DEV}" atualizado.`, "success")
        toast({ title: "Sucesso!", description: "Motivo de devolução atualizado." })
      } else {
        await addDoc(collection(db, "docs_mot_devolucao"), formData)
        addLog(`Novo motivo adicionado.`, "success")
        toast({ title: "Sucesso!", description: "Motivo de devolução adicionado." })
      }
      setFormOpen(false)
    } catch (e: any) {
      addLog(`Erro ao salvar: ${e.message}`, "error")
      toast({ variant: "destructive", title: "Erro ao salvar", description: e.message })
    } finally {
      setProcessing(false)
    }
  }

  const openDeleteAlert = (item: MotivoDev) => { setItemToDelete(item); setAlertOpen(true) }

  const handleDelete = async () => {
    if (!itemToDelete) return
    setProcessing(true)
    try {
      await deleteDoc(doc(db, "docs_mot_devolucao", itemToDelete.id))
      addLog(`Motivo "${itemToDelete.MOTIVO_DEV}" excluído.`, "warn")
      toast({ title: "Excluído", description: "O item foi removido." })
      setAlertOpen(false)
    } catch (e: any) {
      addLog(`Erro ao excluir: ${e.message}`, "error")
      toast({ variant: "destructive", title: "Erro ao excluir", description: e.message })
    } finally {
      setProcessing(false)
    }
  }

  const handleImport = async () => {
    if (!importFile) return
    setImporting(true)
    addLog(`Importando arquivo: ${importFile.name}...`, "step")
    try {
      const result = await importMotivosDevAction(importFile)
      if (result.success) {
        addLog(result.message, "success")
        toast({ title: "Sucesso!", description: result.message })
        setImportOpen(false)
        setImportFile(null)
      } else {
        addLog(`Erro na importação: ${result.message}`, "error")
        toast({ variant: "destructive", title: "Erro na importação", description: result.message })
      }
    } catch (e: any) {
      addLog(`Erro inesperado: ${e.message}`, "error")
      toast({ variant: "destructive", title: "Erro inesperado", description: e.message })
    } finally {
      setImporting(false)
    }
  }

  const handleInputChange = (name: string, value: any) => {
    setFormData(prev => ({ ...prev, [name]: value }))
  }

  const filteredItems = items.filter(item =>
    search ? searchableFields.some(field =>
      String(item[field as keyof MotivoDev] ?? "").toLowerCase().includes(search.toLowerCase())
    ) : true
  )

  const culpaLogistica = items.filter(i => i.CONSIDERA === "SIM").length
  const semCulpa = items.filter(i => i.CONSIDERA === "NAO").length

  const fields = [
    { name: "MOTIVO_DEV", label: "Motivo da Devolução", type: "text" },
    { name: "CONSIDERA", label: "Culpa Logística", type: "select", options: ["SIM", "NAO"] },
  ]

  return (
    <div className="space-y-6">
      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Info className="size-4 text-primary" />
          <AlertTitle className="mb-0">Motivos de Devolução</AlertTitle>
        </div>
        <AlertDescription className="text-sm mt-2">
          Gerencie os motivos de devolução e defina se cada um é considerado <strong>culpa da logística</strong>.
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Tag className="size-5 text-primary" />
                Motivos de Devolução
              </CardTitle>
              <CardDescription>Coleção: docs_mot_devolucao</CardDescription>
            </CardHeader>

            <CardContent className="space-y-4">
              <div className="relative flex-1">
                <Search className="absolute left-2.5 top-2.5 size-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar por Motivo ou Considera..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="pl-8"
                />
              </div>

              <ScrollArea className="h-[500px] rounded-md border">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Motivo da Devolução</TableHead>
                      <TableHead>Culpa da Logística?</TableHead>
                      <TableHead className="w-[60px]" />
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {loading ? (
                      <TableRow>
                        <TableCell colSpan={3} className="h-24 text-center">
                          <div className="flex justify-center items-center gap-2 text-muted-foreground">
                            <Loader2 className="size-4 animate-spin" /> Carregando...
                          </div>
                        </TableCell>
                      </TableRow>
                    ) : filteredItems.length > 0 ? (
                      filteredItems.map(item => (
                        <TableRow key={item.id}>
                          <TableCell className="font-medium">{item.MOTIVO_DEV}</TableCell>
                          <TableCell>
                            <span className={cn(
                              "text-[10px] font-bold px-2 py-0.5 rounded-full flex items-center gap-1 w-fit",
                              item.CONSIDERA === "SIM"
                                ? "bg-red-100 text-red-700"
                                : "bg-emerald-100 text-emerald-700"
                            )}>
                              {item.CONSIDERA === "SIM"
                                ? <XCircle className="size-3" />
                                : <CheckCircle2 className="size-3" />}
                              {item.CONSIDERA}
                            </span>
                          </TableCell>
                          <TableCell className="text-right">
                            <DropdownMenu>
                              <DropdownMenuTrigger asChild>
                                <Button variant="ghost" className="h-8 w-8 p-0">
                                  <MoreHorizontal className="h-4 w-4" />
                                </Button>
                              </DropdownMenuTrigger>
                              <DropdownMenuContent align="end">
                                <DropdownMenuItem onClick={() => openForm(item)}>
                                  <Edit className="mr-2 h-4 w-4" /> Editar
                                </DropdownMenuItem>
                                <DropdownMenuItem onClick={() => openDeleteAlert(item)} className="text-destructive">
                                  <Trash2 className="mr-2 h-4 w-4" /> Excluir
                                </DropdownMenuItem>
                              </DropdownMenuContent>
                            </DropdownMenu>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell colSpan={3} className="h-24 text-center text-muted-foreground">
                          Nenhum motivo encontrado.
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </ScrollArea>
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button variant="outline" size="sm" className="flex-1 h-9 text-xs font-semibold"
                onClick={() => setImportOpen(true)}>
                <Upload className="mr-1.5 size-3.5" /> Importar Excel/CSV
              </Button>
              <Button size="sm" className="flex-1 h-9 text-xs font-semibold bg-primary hover:bg-primary/90 shadow-sm"
                onClick={() => openForm()}>
                <PlusCircle className="mr-1.5 size-3.5" /> Novo Motivo
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">
          <div className="grid grid-cols-1 gap-2">
            {[
              { label: "Total de Motivos", value: items.length.toLocaleString("pt-BR"), icon: Tag, highlight: false, color: "" },
              { label: "Culpa Logística (SIM)", value: culpaLogistica.toLocaleString("pt-BR"), icon: XCircle, highlight: false, color: "text-red-600" },
              { label: "Sem Culpa (NAO)", value: semCulpa.toLocaleString("pt-BR"), icon: CheckCircle2, highlight: true, color: "" },
            ].map(stat => {
              const Icon = stat.icon
              return (
                <div key={stat.label} className={cn(
                  "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                  stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                )}>
                  <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                    stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                    <Icon className={cn("size-3.5", stat.color || (stat.highlight ? "text-primary" : "text-muted-foreground"))} />
                  </div>
                  <div>
                    <p className={cn("text-sm font-bold leading-tight", stat.highlight ? "text-primary" : "text-foreground")}>
                      {stat.value}
                    </p>
                    <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                  </div>
                </div>
              )
            })}
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[200px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0 ? (
                  <span className="text-slate-500 italic">Aguardando operações...</span>
                ) : (
                  logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))
                )}
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>
        </div>
      </div>

      {/* ── Dialog Form ── */}
      <Dialog open={isFormOpen} onOpenChange={setFormOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingItem ? "Editar" : "Novo"} Motivo de Devolução</DialogTitle>
            <DialogDescription>
              {editingItem ? "Altere os dados do motivo abaixo." : "Preencha os dados do novo motivo."}
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            {fields.map(field => (
              <div key={field.name} className="grid grid-cols-4 items-center gap-4">
                <Label htmlFor={field.name} className="text-right">{field.label}</Label>
                {field.type === "select" ? (
                  <Select
                    value={formData[field.name as keyof MotivoDev] || ""}
                    onValueChange={(value) => handleInputChange(field.name, value)}
                  >
                    <SelectTrigger className="col-span-3">
                      <SelectValue placeholder="Selecione uma opção" />
                    </SelectTrigger>
                    <SelectContent>
                      {field.options?.map(opt => <SelectItem key={opt} value={opt}>{opt}</SelectItem>)}
                    </SelectContent>
                  </Select>
                ) : (
                  <Input
                    id={field.name}
                    type={field.type}
                    value={formData[field.name as keyof MotivoDev] ?? ""}
                    onChange={(e) => handleInputChange(field.name, e.target.value)}
                    className="col-span-3"
                  />
                )}
              </div>
            ))}
          </div>
          <DialogFooter>
            <DialogClose asChild><Button variant="outline">Cancelar</Button></DialogClose>
            <Button onClick={handleSave} disabled={isProcessing}>
              {isProcessing && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Salvar
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ── Dialog Import ── */}
      <Dialog open={isImportOpen} onOpenChange={setImportOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Importar Motivos de Devolução</DialogTitle>
            <DialogDescription>Selecione um arquivo Excel ou CSV para importar em lote.</DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid grid-cols-4 items-center gap-4">
              <Label htmlFor="import-file" className="text-right">Arquivo</Label>
              <Input
                id="import-file"
                type="file"
                className="col-span-3"
                accept=".xlsx,.xls,.csv"
                onChange={(e) => setImportFile(e.target.files?.[0] ?? null)}
              />
            </div>
            <p className="text-xs text-muted-foreground px-4 text-center">
              Cabeçalhos esperados: MOTIVO_DEV, CONSIDERA.
            </p>
          </div>
          <DialogFooter>
            <DialogClose asChild><Button variant="outline">Cancelar</Button></DialogClose>
            <Button onClick={handleImport} disabled={isImporting || !importFile}>
              {isImporting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Confirmar Importação
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ── Alert Delete ── */}
      <AlertDialog open={isAlertOpen} onOpenChange={setAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Você tem certeza?</AlertDialogTitle>
            <AlertDialogDescription>Esta ação não pode ser desfeita. O item será excluído permanentemente.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-destructive hover:bg-destructive/90">
              {isProcessing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : "Excluir"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Upload, Play, Trash2, FileCode, Loader2, Zap,
  HelpCircle, Download, Info, CheckCircle2, Circle,
  XCircle, AlertTriangle, ChevronRight, Terminal, Users, Database,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { AIParamAssistant } from "../../pages/AI-Param-Assistant"
import { ScrollArea } from "@/components/ui/scroll-area"
import { executePerformaxxiPipeline } from "@/app/actions/import-performaxxi-actions"
import { useToast } from "@/hooks/use-toast"
import { PipelineResult } from "@/lib/firebase"
import { DataViewer } from "../../pages/Data-Viewer"
import { Progress } from "@/components/ui/progress"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { downloadMultipleSheets } from "@/lib/excel-utils"
import { cn } from "@/lib/utils"

// ─── Tipos ────────────────────────────────────────────────────────────────────
type StageStatus = "idle" | "running" | "done" | "error" | "warn"
interface Stage { id: string; label: string; description: string; status: StageStatus }
interface LogEntry { time: string; message: string; type: "info" | "success" | "error" | "warn" | "step" }

// ─── Etapas ───────────────────────────────────────────────────────────────────
const INITIAL_STAGES: Stage[] = [
  { id: "load",    label: "Carregar arquivos",             description: "RelatorioAnaliticoRotaPedidos + Funcionario.xlsx", status: "idle" },
  { id: "routes",  label: "Etapa 1 — Processar rotas",    description: "Filtra StandBy · calcula pesos · gera resumo",     status: "idle" },
  { id: "drivers", label: "Etapa 2 — Performance Motoristas", description: "Raio · SLA · Tempo · Sequência (R$ 8,00)",     status: "idle" },
  { id: "helpers", label: "Etapa 3 — Performance Ajudantes",  description: "Raio · SLA · Tempo · Sequência (R$ 7,20)",     status: "idle" },
  { id: "export",  label: "Exportar / Salvar Firebase",    description: "7 abas: Base, Resumo, Detalhe e Consolidados",    status: "idle" },
]

const RULES = [
  { condition: "4/4 critérios OK",  result: "Motorista R$ 8,00 · Ajudante R$ 7,20",   variant: "success" as const },
  { condition: "3/4 critérios OK",  result: "Motorista R$ 6,00 · Ajudante R$ 5,40",   variant: "warn"    as const },
  { condition: "2/4 critérios OK",  result: "Motorista R$ 4,00 · Ajudante R$ 3,60",   variant: "warn"    as const },
  { condition: "1/4 critério OK",   result: "Motorista R$ 2,00 · Ajudante R$ 1,80",   variant: "warn"    as const },
  { condition: "0/4 critérios OK",  result: "R$ 0,00",                                 variant: "danger"  as const },
  { condition: "Mínimos exigidos",  result: "Raio ≥70% · SLA ≥80% · Tempo ≥100% · Seq ≥0%", variant: "info" as const },
]

// ─── Sub-componentes ──────────────────────────────────────────────────────────
function StageIcon({ status }: { status: StageStatus }) {
  if (status === "running") return <Loader2 className="size-4 animate-spin text-primary shrink-0" />
  if (status === "done")    return <CheckCircle2 className="size-4 text-emerald-500 shrink-0" />
  if (status === "error")   return <XCircle className="size-4 text-destructive shrink-0" />
  if (status === "warn")    return <AlertTriangle className="size-4 text-amber-500 shrink-0" />
  return <Circle className="size-4 text-muted-foreground/30 shrink-0" />
}

const stageBg: Record<StageStatus, string> = {
  idle:    "bg-muted/20 border-border/40",
  running: "bg-primary/5 border-primary/30",
  done:    "bg-emerald-50 border-emerald-200",
  error:   "bg-red-50 border-red-200",
  warn:    "bg-amber-50 border-amber-200",
}
const stageLabel: Record<StageStatus, string> = {
  idle:    "text-muted-foreground",
  running: "text-primary font-semibold",
  done:    "text-emerald-700 font-medium",
  error:   "text-red-700 font-semibold",
  warn:    "text-amber-700 font-medium",
}
const ruleColor = {
  success: "border-emerald-200 bg-emerald-50 text-emerald-700",
  danger:  "border-red-200 bg-red-50 text-red-700",
  warn:    "border-amber-200 bg-amber-50 text-amber-700",
  info:    "border-blue-200 bg-blue-50 text-blue-700",
}
const logColor: Record<LogEntry["type"], string> = {
  info:    "text-slate-400",
  success: "text-emerald-400",
  error:   "text-red-400 font-semibold",
  warn:    "text-amber-400",
  step:    "text-primary font-semibold",
}
const logPrefix: Record<LogEntry["type"], string> = {
  info: "   ", success: "✅ ", error: "❌ ", warn: "⚠️  ", step: "▶  ",
}

// ─── Componente principal ─────────────────────────────────────────────────────
export function PerformaxxiPipelineView() {
  const [year, setYear]           = React.useState(2026)
  const [month, setMonth]         = React.useState(1)
  const [files, setFiles]         = React.useState<File[]>([])
  const [isExecuting, setIsExecuting] = React.useState(false)
  const [progress, setProgress]   = React.useState(0)
  const [stages, setStages]       = React.useState<Stage[]>(INITIAL_STAGES)
  const [logs, setLogs]           = React.useState<LogEntry[]>([])
  const [lastResult, setLastResult] = React.useState<PipelineResult | null>(null)
  const [stats, setStats]         = React.useState<{
    motoristas: number; ajudantes: number; rotas: number
    bonifMot: number; bonifAjud: number
  } | null>(null)
  const logEndRef = React.useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  React.useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") => {
    setLogs(prev => [...prev, { time: new Date().toLocaleTimeString("pt-BR"), message, type }])
  }
  const setStage = (id: string, status: StageStatus) =>
    setStages(prev => prev.map(s => s.id === id ? { ...s, status } : s))
  const resetAll = () => {
    setStages(INITIAL_STAGES.map(s => ({ ...s, status: "idle" })))
    setProgress(0); setStats(null)
  }

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) setFiles(prev => [...prev, ...Array.from(e.target.files!)])
  }

  const runPipeline = async (downloadOnly = false) => {
    if (!files.length) return
    setIsExecuting(true); setLogs([]); resetAll()

    try {
      addLog(`Performaxxi iniciado — ${String(month).padStart(2,"0")}/${year}`, "step")
      addLog(`${files.length} arquivo(s): ${files.map(f => f.name).join(", ")}`)
      setStage("load", "running"); setProgress(8)
      await new Promise(r => setTimeout(r, 250))

      const relatorio = files.filter(f => !/funcionari/i.test(f.name))
      const funcFile  = files.filter(f => /funcionari/i.test(f.name))
      addLog(`Relatório: ${relatorio.length} · Funcionários: ${funcFile.length}`)
      setStage("load", "done"); setProgress(15)

      // Etapa 1
      addLog("Etapa 1 — Processando rotas e filtrando StandBy...", "step")
      setStage("routes", "running"); setProgress(25)

      const formData = new FormData()
      formData.append("year", year.toString())
      formData.append("month", month.toString())
      files.forEach(f => { formData.append("files", f); formData.append("fileNames", f.name) })

      const response = await executePerformaxxiPipeline(formData)
      if (!response?.success) throw new Error(response?.error || "Erro desconhecido.")

      setStage("routes", "done"); setProgress(45)
      addLog("Rotas processadas · StandBy removido.", "success")

      // Etapa 2
      addLog("Etapa 2 — Analisando performance dos Motoristas...", "step")
      setStage("drivers", "running"); setProgress(60)
      await new Promise(r => setTimeout(r, 150))
      setStage("drivers", "done"); setProgress(72)
      addLog("Performance de motoristas calculada.", "success")

      // Etapa 3
      addLog("Etapa 3 — Analisando performance dos Ajudantes...", "step")
      setStage("helpers", "running"); setProgress(82)
      await new Promise(r => setTimeout(r, 150))
      setStage("helpers", "done"); setProgress(92)
      addLog("Performance de ajudantes calculada.", "success")

      // Export
      setStage("export", "running"); setProgress(97)
      const result = response.result
      setLastResult(result)

      // Stats
      const mot  = result.data ?? []
      const ajud = result.extraSheets?.find((s: any) => s.name === "07_Consolidado_Ajudante")?.data ?? []
      const rotas = result.extraSheets?.find((s: any) => s.name === "02_Base_Dados")?.data?.length ?? 0
      const bonifMot  = mot.reduce((s: number, m: any)  => s + (m["Total Bonificação (R$)"] ?? 0), 0)
      const bonifAjud = ajud.reduce((s: number, m: any) => s + (m["Total Bonificação (R$)"] ?? 0), 0)
      setStats({ motoristas: mot.length, ajudantes: ajud.length, rotas, bonifMot, bonifAjud })

      if (downloadOnly) {
        downloadMultipleSheets(
          [{ data: mot, name: "05_Consolidado_Motorista" }, { data: ajud, name: "07_Consolidado_Ajudante" }],
          `Performaxxi_${month}_${year}`
        )
        addLog("Excel com 2 abas baixado.", "success")
      } else {
        addLog("Dados sincronizados com Firebase.", "success")
      }

      setStage("export", "done"); setProgress(100)
      addLog(result.summary ?? "Pipeline concluído.", "success")
      toast({ title: downloadOnly ? "Excel pronto" : "Pipeline concluído", description: result.summary })

    } catch (err: any) {
      addLog(`FALHA: ${err.message}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro no pipeline", description: err.message })
    } finally {
      setIsExecuting(false)
    }
  }

  const doneCount = stages.filter(s => s.status === "done" || s.status === "warn").length
  const hasError  = stages.some(s => s.status === "error")

  return (
    <div className="space-y-6">

      {/* Alert */}
      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Zap className="size-4 text-primary" />
          <AlertTitle className="mb-0">Performaxxi</AlertTitle>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="size-4 text-muted-foreground cursor-help" />
              </TooltipTrigger>
              <TooltipContent className="max-w-xs">
                <p>Processa 20k+ linhas. Ignora StandBy. Analisa Motoristas e Ajudantes com bonificação proporcional por critério.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <AlertDescription className="text-sm mt-2">
          Bonificação <strong>proporcional</strong> por 4 critérios: Raio, SLA, Tempo e Sequência.
          Motorista R$ 8,00 · Ajudante R$ 7,20.
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Zap className="size-5 text-primary" />
                Configuração Performaxxi
              </CardTitle>
              <CardDescription>Análise de Performance de Rotas</CardDescription>
            </CardHeader>

            <CardContent className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Ano</Label>
                  <Input type="number" value={year} onChange={e => setYear(parseInt(e.target.value))} />
                </div>
                <div className="space-y-2">
                  <Label>Mês</Label>
                  <Input type="number" min={1} max={12} value={month} onChange={e => setMonth(parseInt(e.target.value))} />
                </div>
              </div>

              <AIParamAssistant onParamsUpdate={(m, y) => { setMonth(m); setYear(y) }} currentMonth={month} currentYear={year} />

              {/* Upload */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <Label className="text-sm font-semibold text-primary">Arquivos ({files.length})</Label>
                  <Button variant="outline" size="sm" onClick={() => document.getElementById("perf-upload")?.click()}>
                    <Upload className="mr-2 size-4" /> Selecionar
                  </Button>
                  <input id="perf-upload" type="file" multiple className="hidden" onChange={handleFileChange} />
                </div>

                <div className="border-2 border-dashed rounded-xl bg-muted/10 min-h-[120px] flex flex-col items-center justify-center p-4">
                  {files.length === 0 ? (
                    <div className="text-center space-y-1.5">
                      <FileCode className="size-9 mx-auto opacity-20" />
                      <p className="text-xs text-muted-foreground italic">
                        RelatorioAnaliticoRotaPedidos.xlsx · Funcionario.xlsx (opcional)
                      </p>
                    </div>
                  ) : (
                    <ScrollArea className="w-full max-h-[160px]">
                      <div className="space-y-1.5">
                        {files.map((file, idx) => {
                          const isFunc = /funcionari/i.test(file.name)
                          return (
                            <div key={idx} className="flex items-center gap-2 bg-background px-3 py-2 rounded-lg border text-xs">
                              <FileCode className="size-3 text-muted-foreground shrink-0" />
                              <span className={cn(
                                "text-[10px] font-bold px-1.5 py-0.5 rounded shrink-0",
                                isFunc ? "bg-violet-100 text-violet-700" : "bg-primary/10 text-primary"
                              )}>
                                {isFunc ? "Funcionários" : "Relatório"}
                              </span>
                              <span className="truncate flex-1 font-medium">{file.name}</span>
                              <Button variant="ghost" size="icon" className="size-6 shrink-0"
                                onClick={() => setFiles(files.filter((_, i) => i !== idx))}>
                                <Trash2 className="size-3 text-destructive/70" />
                              </Button>
                            </div>
                          )
                        })}
                      </div>
                    </ScrollArea>
                  )}
                </div>
              </div>

              {/* Progresso */}
              {(isExecuting || progress > 0) && (
                <div className="space-y-2 pt-1">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-primary">
                      {hasError ? "Erro na execução" : progress === 100 ? "Concluído" : "Processando..."}
                    </span>
                    <span className="text-[10px] font-mono font-bold text-muted-foreground">{progress}%</span>
                  </div>
                  <Progress value={progress} className={cn("h-2", hasError && "[&>div]:bg-destructive")} />
                  <div className="flex justify-between text-[9px] text-muted-foreground">
                    <span>{doneCount}/{stages.length} etapas</span>
                    <span>{isExecuting ? (stages.find(s => s.status === "running")?.label ?? "...") : (progress === 100 ? "Pipeline finalizado" : "")}</span>
                  </div>
                </div>
              )}
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button
                variant="outline" size="sm"
                className="flex-1 h-9 text-xs font-semibold border-slate-300 text-slate-600 hover:bg-slate-50 hover:border-slate-400 transition-all"
                onClick={() => runPipeline(true)}
                disabled={isExecuting || !files.length}
              >
                <Download className="mr-1.5 size-3.5" /> Exportar Excel
              </Button>
              <Button
                size="sm"
                className="flex-1 h-9 text-xs font-semibold shadow-sm transition-all"
                onClick={() => runPipeline(false)}
                disabled={isExecuting || !files.length}
              >
                {isExecuting
                  ? <><Loader2 className="mr-1.5 size-3.5 animate-spin" /> Processando...</>
                  : <><Play className="mr-1.5 size-3.5 fill-current" /> Executar Pipeline</>}
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">

          {/* Etapas */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Etapas de Execução</span>
            </div>
            <div className="p-3 space-y-2">
              {stages.map((stage, idx) => (
                <div key={stage.id} className="flex items-start gap-2">
                  <div className="flex flex-col items-center pt-0.5">
                    <StageIcon status={stage.status} />
                    {idx < stages.length - 1 && (
                      <div className={cn("w-px mt-1 min-h-[14px]", stage.status === "done" ? "bg-emerald-300" : "bg-border/60")} />
                    )}
                  </div>
                  <div className={cn("flex-1 px-2.5 py-1.5 rounded-lg border text-xs transition-all", stageBg[stage.status])}>
                    <p className={cn("leading-tight", stageLabel[stage.status])}>{stage.label}</p>
                    <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{stage.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Stats */}
          {stats && (
            <div className="grid grid-cols-2 gap-2">
              {[
                { label: "Motoristas", value: stats.motoristas, icon: Users, highlight: true },
                { label: "Ajudantes",  value: stats.ajudantes,  icon: Users, highlight: false },
                { label: "Linhas processadas", value: stats.rotas.toLocaleString("pt-BR"), icon: Database, highlight: false },
                { label: "Bonif. Total", value: `R$ ${(stats.bonifMot + stats.bonifAjud).toFixed(2)}`, icon: CheckCircle2, highlight: true },
              ].map(stat => {
                const Icon = stat.icon
                return (
                  <div key={stat.label} className={cn(
                    "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                    stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                  )}>
                    <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                      stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                      <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                    </div>
                    <div className="min-w-0">
                      <p className={cn("text-sm font-bold leading-tight", stat.highlight ? "text-primary" : "text-foreground")}>
                        {stat.value}
                      </p>
                      <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          {/* Regras */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Regras de Bonificação</span>
            </div>
            <div className="p-3 space-y-1.5">
              {RULES.map((rule, idx) => (
                <div key={idx} className={cn("flex items-start gap-2 rounded-lg border px-2.5 py-2 text-[11px]", ruleColor[rule.variant])}>
                  <ChevronRight className="size-3 mt-0.5 shrink-0 opacity-60" />
                  <div>
                    <span className="font-semibold">{rule.condition}</span>
                    <span className="mx-1 opacity-50">→</span>
                    <span>{rule.result}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[220px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0
                  ? <span className="text-slate-500 italic">Aguardando execução...</span>
                  : logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))}
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>

        </div>
      </div>

      {lastResult && !isExecuting && <DataViewer result={lastResult} />}
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Play, Trash2, FileCode, Loader2, HelpCircle,
  Download, CheckCircle2, Circle, XCircle, AlertTriangle,
  ChevronRight, Terminal, Info, Database,
  Clock, Calendar as CalendarIcon, X, Users,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Input } from "@/components/ui/input"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Progress } from "@/components/ui/progress"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { Badge } from "@/components/ui/badge"
import { Checkbox } from "@/components/ui/checkbox"
import { Calendar } from "@/components/ui/calendar"
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import { AIParamAssistant } from "../../pages/AI-Param-Assistant"
import { executePontoPipeline } from "@/app/actions/import-ponto-actions"
import { useToast } from "@/hooks/use-toast"
import { PipelineResult } from "@/lib/firebase"
import { downloadMultipleSheets } from "@/lib/excel-utils"
import { format } from "date-fns"
import { ptBR } from "date-fns/locale"
import { cn } from "@/lib/utils"

// ─── Tipos ────────────────────────────────────────────────────────────────────
type StageStatus = "idle" | "running" | "done" | "error" | "warn"
interface Stage { id: string; label: string; description: string; status: StageStatus }
interface LogEntry { time: string; message: string; type: "info" | "success" | "error" | "warn" | "step" }

// ─── Etapas ───────────────────────────────────────────────────────────────────
const INITIAL_STAGES: Stage[] = [
  { id: "load",   label: "Carregar CSVs de ponto",     description: "Lê os arquivos de Motoristas e Ajudantes",              status: "idle" },
  { id: "parse",  label: "Parsear marcações",           description: "Extrai Entrada · Saída · Almoço · Retorno por dia",      status: "idle" },
  { id: "dedup",  label: "Remover duplicatas",          description: "Prioriza o registro mais completo por ID+Data",          status: "idle" },
  { id: "mot",    label: "Conformidade Motoristas",     description: "Marcações + 5 critérios → R$ 3,20/dia",                 status: "idle" },
  { id: "aju",    label: "Conformidade Ajudantes",      description: "Marcações + 5 critérios → R$ 4,80/dia",                 status: "idle" },
  { id: "abs",    label: "Análise de Absenteísmo",      description: "Presença física + Atestados/Férias → incentivo",        status: "idle" },
  { id: "export", label: "Exportar / Salvar Firebase",  description: "11 abas: ponto bruto · detalhe · consolidado · abs",   status: "idle" },
]

const REGRAS = [
  { condition: "Motorista — Marcações (4/4)", result: "R$ 1,60 GARANTIDO",         variant: "success" as const },
  { condition: "Motorista — 5 Critérios OK",  result: "R$ 1,60 TUDO OU NADA",      variant: "danger"  as const },
  { condition: "Ajudante — Marcações (4/4)",  result: "R$ 2,40 GARANTIDO",         variant: "success" as const },
  { condition: "Ajudante — 5 Critérios OK",   result: "R$ 2,40 TUDO OU NADA",      variant: "danger"  as const },
  { condition: "Presença 100%",               result: "Incentivo R$ 50,00",         variant: "success" as const },
  { condition: "Presença ≥ 90%",              result: "Incentivo R$ 40,00",         variant: "success" as const },
  { condition: "Presença ≥ 75%",              result: "Incentivo R$ 25,00",         variant: "warn"    as const },
  { condition: "Presença < 75%",              result: "Incentivo R$ 0,00",          variant: "danger"  as const },
  { condition: "Atestados / Férias",          result: "Contam como presença",       variant: "info"    as const },
]

const CRITERIOS = [
  "Jornada — não exceder carga padrão + 2h",
  "Hora Extra — máximo 2h de HE",
  "Almoço — mínimo 1h de intervalo",
  "Intrajornada — nenhum período > 6h seguidas",
  "Interjornada — mínimo 11h de descanso",
]

// ─── Sub-componentes ──────────────────────────────────────────────────────────
function StageIcon({ status }: { status: StageStatus }) {
  if (status === "running") return <Loader2 className="size-4 animate-spin text-primary shrink-0" />
  if (status === "done")    return <CheckCircle2 className="size-4 text-emerald-500 shrink-0" />
  if (status === "error")   return <XCircle className="size-4 text-destructive shrink-0" />
  if (status === "warn")    return <AlertTriangle className="size-4 text-amber-500 shrink-0" />
  return <Circle className="size-4 text-muted-foreground/30 shrink-0" />
}
const stageBg: Record<StageStatus, string> = {
  idle: "bg-muted/20 border-border/40", running: "bg-primary/5 border-primary/30",
  done: "bg-emerald-50 border-emerald-200", error: "bg-red-50 border-red-200", warn: "bg-amber-50 border-amber-200",
}
const stageLbl: Record<StageStatus, string> = {
  idle: "text-muted-foreground", running: "text-primary font-semibold",
  done: "text-emerald-700 font-medium", error: "text-red-700 font-semibold", warn: "text-amber-700 font-medium",
}
const ruleColor = {
  success: "border-emerald-200 bg-emerald-50 text-emerald-700",
  danger:  "border-red-200 bg-red-50 text-red-700",
  warn:    "border-amber-200 bg-amber-50 text-amber-700",
  info:    "border-blue-200 bg-blue-50 text-blue-700",
}
const logColor: Record<LogEntry["type"], string> = {
  info: "text-slate-400", success: "text-emerald-400",
  error: "text-red-400 font-semibold", warn: "text-amber-400", step: "text-primary font-semibold",
}
const logPrefix: Record<LogEntry["type"], string> = {
  info: "   ", success: "✅ ", error: "❌ ", warn: "⚠️  ", step: "▶  ",
}

function fileBadge(name: string) {
  const n = name.toLowerCase()
  if (/ajudante/i.test(n))    return { label: "Ajudante",    cls: "bg-violet-100 text-violet-700 border-violet-200" }
  if (/motorista/i.test(n))   return { label: "Motorista",   cls: "bg-sky-100 text-sky-700 border-sky-200" }
  return                               { label: "Ponto",      cls: "bg-slate-100 text-slate-600 border-slate-200" }
}

// ─── Componente principal ─────────────────────────────────────────────────────
export function PontoPipelineView() {
  const [year, setYear]           = React.useState(new Date().getFullYear())
  const [month, setMonth]         = React.useState(new Date().getMonth() + 1)
  const [files, setFiles]         = React.useState<File[]>([])
  const [excludedDates, setExcludedDates] = React.useState<Date[]>([])
  const [includeSundays, setIncludeSundays] = React.useState(false)
  const [isExecuting, setIsExecuting] = React.useState(false)
  const [progress, setProgress]   = React.useState(0)
  const [stages, setStages]       = React.useState<Stage[]>(INITIAL_STAGES)
  const [logs, setLogs]           = React.useState<LogEntry[]>([])
  const [lastResult, setLastResult] = React.useState<PipelineResult | null>(null)
  const [stats, setStats]         = React.useState<{
    motoristas: number; ajudantes: number; bonifPonto: number; bonifAbs: number
  } | null>(null)
  const logEndRef = React.useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  React.useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") =>
    setLogs(prev => [...prev, { time: new Date().toLocaleTimeString("pt-BR"), message, type }])

  const setStage = (id: string, status: StageStatus) =>
    setStages(prev => prev.map(s => s.id === id ? { ...s, status } : s))

  const resetAll = () => {
    setStages(INITIAL_STAGES.map(s => ({ ...s, status: "idle" })))
    setProgress(0); setStats(null)
  }

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) setFiles(prev => [...prev, ...Array.from(e.target.files!)])
  }
  const removeFile = (idx: number) => setFiles(prev => prev.filter((_, i) => i !== idx))
  const removeDate = (d: Date) => setExcludedDates(prev => prev.filter(x => x.getTime() !== d.getTime()))

  const runPipeline = async (downloadOnly = false) => {
    if (!files.length) return
    setIsExecuting(true); setLogs([]); resetAll()

    try {
      addLog(`Ponto — ${String(month).padStart(2,"0")}/${year}`, "step")
      addLog(`${files.length} arquivo(s) · ${excludedDates.length} feriado(s) excluído(s)`)
      addLog(`Domingos: ${includeSundays ? "Considerados" : "Ignorados"}`)

      // Etapa 1
      setStage("load", "running"); setProgress(8)
      files.forEach(f => {
        const b = fileBadge(f.name)
        addLog(`• [${b.label}] ${f.name}`)
      })
      setStage("load", "done"); setProgress(15)

      // Monta FormData
      const formData = new FormData()
      formData.append("year", String(year))
      formData.append("month", String(month))
      formData.append("includeSundays", String(includeSundays))
      formData.append("excludedDates", JSON.stringify(excludedDates.map(d => format(d, "dd/MM/yyyy"))))
      files.forEach(f => {
        formData.append("files", f)
        formData.append("fileNames", f.name)
      })

      // Etapa 2
      addLog("Parseando marcações por colaborador/dia...", "step")
      setStage("parse", "running"); setProgress(25)
      const response = await executePontoPipeline(formData)
      if (!response.success) throw new Error(response.error)
      setStage("parse", "done"); setProgress(35)
      addLog("Marcações extraídas.", "success")

      // Etapa 3
      addLog("Removendo duplicatas (prioriza registro mais completo)...", "step")
      setStage("dedup", "running"); setProgress(45)
      await new Promise(r => setTimeout(r, 100))
      setStage("dedup", "done"); setProgress(52)
      addLog("Deduplicação concluída.", "success")

      // Etapas 4 e 5
      addLog("Analisando conformidade de ponto — Motoristas...", "step")
      setStage("mot", "running"); setProgress(62)
      await new Promise(r => setTimeout(r, 100))
      setStage("mot", "done")

      addLog("Analisando conformidade de ponto — Ajudantes...", "step")
      setStage("aju", "running"); setProgress(72)
      await new Promise(r => setTimeout(r, 100))
      setStage("aju", "done")
      addLog("5 critérios avaliados.", "success")

      // Etapa 6
      addLog("Calculando absenteísmo (presença física + justificadas)...", "step")
      setStage("abs", "running"); setProgress(84)
      await new Promise(r => setTimeout(r, 100))
      setStage("abs", "done"); setProgress(93)
      addLog("Incentivo de presença calculado.", "success")

      // Etapa 7
      setStage("export", "running"); setProgress(97)
      const result = response.result
      setLastResult(result)

      // Extrai stats do summary
      const m = (result.summary ?? "").match(/(\d+) motoristas · (\d+) ajudantes · R\$ ([\d,.]+) ponto · R\$ ([\d,.]+) absenteísmo/)
      if (m) {
        setStats({
          motoristas: parseInt(m[1]),
          ajudantes:  parseInt(m[2]),
          bonifPonto: parseFloat(m[3].replace(",",".")),
          bonifAbs:   parseFloat(m[4].replace(",",".")),
        })
      }

      if (downloadOnly && result.extraSheets) {
        downloadMultipleSheets(
          result.extraSheets.map((s: any) => ({ data: s.data, name: s.name })),
          `Ponto_${String(month).padStart(2,"0")}_${year}`
        )
        addLog("Excel com 11 abas baixado.", "success")
      } else {
        addLog("Dados sincronizados com Firebase.", "success")
      }

      setStage("export", "done"); setProgress(100)
      addLog(result.summary ?? "Pipeline concluído.", "success")
      toast({ title: downloadOnly ? "Excel pronto" : "Pipeline concluído", description: result.summary })

    } catch (err: any) {
      addLog(`FALHA: ${err.message}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro no pipeline", description: err.message })
    } finally {
      setIsExecuting(false)
    }
  }

  const doneCount = stages.filter(s => s.status === "done" || s.status === "warn").length
  const hasError  = stages.some(s => s.status === "error")

  return (
    <div className="space-y-6">

      {/* Alert */}
      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Clock className="size-4 text-primary" />
          <AlertTitle className="mb-0">Ponto + Absenteísmo</AlertTitle>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="size-4 text-muted-foreground cursor-help" />
              </TooltipTrigger>
              <TooltipContent className="max-w-xs">
                <p>Analisa os CSVs de ponto de Motoristas e Ajudantes. Avalia 5 critérios de conformidade e calcula incentivo de absenteísmo por faixa de presença.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <AlertDescription className="text-xs mt-2">
          Gera <strong>11 abas</strong>: ponto bruto · sem marcação · detalhe diário · consolidado · absenteísmo (Motoristas e Ajudantes).
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Clock className="size-5 text-primary" />
                Configuração de Ponto
              </CardTitle>
              <CardDescription>Período · arquivos CSV · feriados e configurações de jornada.</CardDescription>
            </CardHeader>

            <CardContent className="space-y-5">
              {/* Período */}
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Ano</Label>
                  <Input type="number" value={year} onChange={e => setYear(parseInt(e.target.value))} />
                </div>
                <div className="space-y-2">
                  <Label>Mês</Label>
                  <Input type="number" min={1} max={12} value={month} onChange={e => setMonth(parseInt(e.target.value))} />
                </div>
              </div>

              <AIParamAssistant onParamsUpdate={(m, y) => { setMonth(m); setYear(y) }} currentMonth={month} currentYear={year} />

              {/* Domingos */}
              <div className="flex items-start gap-3 p-3 rounded-lg border bg-muted/5">
                <Checkbox
                  id="include-sundays"
                  checked={includeSundays}
                  onCheckedChange={c => setIncludeSundays(!!c)}
                  className="mt-0.5"
                />
                <div>
                  <label htmlFor="include-sundays" className="text-sm font-medium cursor-pointer">
                    Considerar domingos como dia útil
                  </label>
                  <p className="text-xs text-muted-foreground mt-0.5">
                    Por padrão, domingos são excluídos da base de cálculo de presença.
                  </p>
                </div>
              </div>

              {/* Feriados */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold flex items-center gap-2">
                  <CalendarIcon className="size-4 text-primary" /> Feriados / Datas Excluídas
                </Label>
                <div className="flex flex-wrap gap-1.5 min-h-[28px]">
                  {excludedDates.length === 0
                    ? <span className="text-xs text-muted-foreground italic">Nenhum feriado selecionado.</span>
                    : excludedDates.sort((a, b) => a.getTime() - b.getTime()).map((d, i) => (
                      <Badge key={i} variant="secondary" className="flex items-center gap-1 pr-1 text-xs">
                        {format(d, "dd/MM/yyyy")}
                        <button onClick={() => removeDate(d)} className="size-3.5 rounded-full hover:bg-destructive hover:text-white flex items-center justify-center transition-colors">
                          <X className="size-2" />
                        </button>
                      </Badge>
                    ))
                  }
                </div>
                <Popover>
                  <PopoverTrigger asChild>
                    <Button variant="outline" size="sm" className="h-7 text-xs">
                      <CalendarIcon className="mr-1.5 size-3" /> Selecionar datas
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-auto p-0" align="start">
                    <Calendar
                      mode="multiple" selected={excludedDates}
                      onSelect={dates => setExcludedDates(dates ?? [])}
                      locale={ptBR} initialFocus
                    />
                  </PopoverContent>
                </Popover>
              </div>

              {/* Arquivos */}
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label className="text-sm font-semibold text-primary">
                    Arquivos CSV de Ponto ({files.length})
                  </Label>
                  <Button variant="outline" size="sm" className="h-7 text-xs"
                    onClick={() => document.getElementById("ponto-file-input")?.click()}>
                    Adicionar arquivos
                  </Button>
                  <input
                    id="ponto-file-input" type="file" multiple className="hidden"
                    accept=".csv,.xlsx,.xls"
                    onChange={handleFileChange}
                  />
                </div>

                <div className={cn(
                  "rounded-xl border border-border/60 overflow-hidden",
                  files.length === 0 && "border-dashed"
                )}>
                  {files.length === 0
                    ? (
                      <div className="flex flex-col items-center justify-center py-8 text-muted-foreground">
                        <Clock className="size-8 mb-2 opacity-20" />
                        <p className="text-xs italic">Nenhum arquivo selecionado</p>
                        <p className="text-[10px] text-muted-foreground/70 mt-1">Arquivos: Ponto_Original_*-*.csv</p>
                      </div>
                    ) : (
                      <ScrollArea className="max-h-[180px]">
                        <div className="p-2 space-y-1.5">
                          {files.map((file, idx) => {
                            const b = fileBadge(file.name)
                            return (
                              <div key={idx} className="flex items-center gap-2 px-2.5 py-2 rounded-lg border bg-background hover:bg-muted/10 transition-colors">
                                <span className={cn("text-[10px] font-bold px-1.5 py-0.5 rounded border shrink-0", b.cls)}>
                                  {b.label}
                                </span>
                                <span className="text-xs truncate flex-1 font-medium">{file.name}</span>
                                <Button variant="ghost" size="icon" className="size-6 shrink-0"
                                  onClick={() => removeFile(idx)}>
                                  <Trash2 className="size-3 text-destructive/70" />
                                </Button>
                              </div>
                            )
                          })}
                        </div>
                      </ScrollArea>
                    )
                  }
                </div>
              </div>

              {/* Progresso */}
              {(isExecuting || progress > 0) && (
                <div className="space-y-2 pt-1">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-primary">
                      {hasError ? "Erro na execução" : progress === 100 ? "Concluído" : "Processando..."}
                    </span>
                    <span className="text-[10px] font-mono font-bold text-muted-foreground">{progress}%</span>
                  </div>
                  <Progress value={progress} className={cn("h-2", hasError && "[&>div]:bg-destructive")} />
                  <div className="flex justify-between text-[9px] text-muted-foreground">
                    <span>{doneCount}/{stages.length} etapas</span>
                    <span>{isExecuting ? (stages.find(s => s.status === "running")?.label ?? "...") : (progress === 100 ? "Pipeline finalizado" : "")}</span>
                  </div>
                </div>
              )}
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button
                variant="outline" size="sm"
                className="flex-1 h-9 text-xs font-semibold border-slate-300 text-slate-600 hover:bg-slate-50 hover:border-slate-400 transition-all"
                onClick={() => runPipeline(true)}
                disabled={isExecuting || !files.length}
              >
                <Download className="mr-1.5 size-3.5" /> Exportar Excel
              </Button>
              <Button
                size="sm"
                className="flex-1 h-9 text-xs font-semibold shadow-sm transition-all"
                onClick={() => runPipeline(false)}
                disabled={isExecuting || !files.length}
              >
                {isExecuting
                  ? <><Loader2 className="mr-1.5 size-3.5 animate-spin" /> Processando...</>
                  : <><Play className="mr-1.5 size-3.5 fill-current" /> Iniciar Pipeline</>}
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">

          {/* Etapas */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Etapas de Execução</span>
            </div>
            <div className="p-3 space-y-2">
              {stages.map((stage, idx) => (
                <div key={stage.id} className="flex items-start gap-2">
                  <div className="flex flex-col items-center pt-0.5">
                    <StageIcon status={stage.status} />
                    {idx < stages.length - 1 && (
                      <div className={cn("w-px mt-1 min-h-[12px]", stage.status === "done" ? "bg-emerald-300" : "bg-border/60")} />
                    )}
                  </div>
                  <div className={cn("flex-1 px-2.5 py-1.5 rounded-lg border text-xs transition-all", stageBg[stage.status])}>
                    <p className={cn("leading-tight", stageLbl[stage.status])}>{stage.label}</p>
                    <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{stage.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Stats */}
          {stats && (
            <div className="grid grid-cols-2 gap-2">
              {[
                { label: "Motoristas",      value: stats.motoristas,                    icon: Users,    highlight: false },
                { label: "Ajudantes",       value: stats.ajudantes,                     icon: Users,    highlight: false },
                { label: "Bônus Ponto",     value: `R$ ${stats.bonifPonto.toFixed(2)}`, icon: Database, highlight: true  },
                { label: "Incentivo Abs.",  value: `R$ ${stats.bonifAbs.toFixed(2)}`,   icon: Database, highlight: true  },
              ].map(stat => {
                const Icon = stat.icon
                return (
                  <div key={stat.label} className={cn(
                    "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                    stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                  )}>
                    <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                      stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                      <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                    </div>
                    <div className="min-w-0">
                      <p className={cn("text-sm font-bold leading-tight", stat.highlight ? "text-primary" : "text-foreground")}>
                        {stat.value}
                      </p>
                      <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          {/* 5 Critérios */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">5 Critérios de Conformidade</span>
            </div>
            <div className="p-3 space-y-1">
              {CRITERIOS.map((c, i) => (
                <div key={i} className="flex items-start gap-1.5 text-[11px] text-muted-foreground">
                  <span className="font-mono text-primary/60 shrink-0">{i + 1}.</span>
                  <span>{c}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Regras */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Regras de Bonificação</span>
            </div>
            <div className="p-3 space-y-1.5">
              {REGRAS.map((rule, idx) => (
                <div key={idx} className={cn("flex items-start gap-2 rounded-lg border px-2.5 py-2 text-[11px]", ruleColor[rule.variant])}>
                  <ChevronRight className="size-3 mt-0.5 shrink-0 opacity-60" />
                  <div>
                    <span className="font-semibold">{rule.condition}</span>
                    <span className="mx-1 opacity-50">→</span>
                    <span>{rule.result}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[220px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0
                  ? <span className="text-slate-500 italic">Aguardando arquivos de ponto...</span>
                  : logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))}
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>

        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Play,
  Trash2,
  FileCode,
  Loader2,
  Download,
  Info,
  HelpCircle,
  CheckCircle2,
  Circle,
  XCircle,
  AlertTriangle,
  ChevronRight,
  Terminal,
  FileText,
  FileSpreadsheet,
  Plus,
  Search,
  Users,
  Hash,
  BarChart2,
  Building2,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Input } from "@/components/ui/input"
import { ScrollArea } from "@/components/ui/scroll-area"
import { executeRetornoPedidosPipeline } from "@/app/actions/import-retorno-pedidos-actions"
import { useToast } from "@/hooks/use-toast"
import { PipelineResult } from "@/lib/firebase"
import { Progress } from "@/components/ui/progress"
import { downloadMultipleSheets } from "@/lib/excel-utils"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { Badge } from "@/components/ui/badge"
import { Separator } from "@/components/ui/separator"
import { cn } from "@/lib/utils"

// ─── Tipos ────────────────────────────────────────────────────────────────────

type StageStatus = "idle" | "running" | "done" | "error" | "warn"

interface Stage {
  id: string
  label: string
  description: string
  status: StageStatus
}

interface LogEntry {
  time: string
  message: string
  type: "info" | "success" | "error" | "warn" | "step"
}

// ─── Constantes ───────────────────────────────────────────────────────────────

const INITIAL_STAGES: Stage[] = [
  { id: "txt",     label: "Etapa 1 — Extração TXT",        description: "Regex \\d{9}\\d{3}(BV|RK|KP)\\d{2}\\d{6} · Data B1DDMMYY",    status: "idle" },
  { id: "excel",   label: "Etapa 2 — Carregar Excel",       description: "STATUS_PEDIDOS_MERCANETE · auto-detecção de colunas",           status: "idle" },
  { id: "norm",    label: "Etapa 3 — Padronização",         description: "Pedido → zfill(6) · Cliente → zfill(9) · remove não-numéricos", status: "idle" },
  { id: "compare", label: "Etapa 4 — Comparação",           description: "Chave: Codigo_Cliente_NumeroPedido · busca O(1) via Set",       status: "idle" },
  { id: "export",  label: "Exportar / Salvar Firebase",     description: "6 abas: Todos · Encontrados · Não Encontrados · Resumos",       status: "idle" },
]

const REGRAS = [
  { label: "Padrão extraído",  detail: "9d + 3d + BV/RK/KP + 2d + 6d",    color: "border-blue-200 bg-blue-50 text-blue-700" },
  { label: "Data TXT",        detail: "B1DDMMYY → DD/MM/YYYY",             color: "border-slate-200 bg-slate-50 text-slate-700" },
  { label: "Chave primária",  detail: "Codigo_Cliente + _ + Numero_Pedido", color: "border-primary/20 bg-primary/5 text-primary" },
  { label: "Pedido Excel",    detail: "Apenas dígitos → zfill(6)",          color: "border-emerald-200 bg-emerald-50 text-emerald-700" },
  { label: "Cliente Excel",   detail: "Apenas dígitos → [:9] → zfill(9)",  color: "border-amber-200 bg-amber-50 text-amber-700" },
]

// ─── Helpers visuais ──────────────────────────────────────────────────────────

function StageIcon({ status }: { status: StageStatus }) {
  if (status === "running") return <Loader2 className="size-4 animate-spin text-primary shrink-0" />
  if (status === "done")    return <CheckCircle2 className="size-4 text-emerald-500 shrink-0" />
  if (status === "error")   return <XCircle className="size-4 text-destructive shrink-0" />
  if (status === "warn")    return <AlertTriangle className="size-4 text-amber-500 shrink-0" />
  return <Circle className="size-4 text-muted-foreground/30 shrink-0" />
}

const stageBg: Record<StageStatus, string> = {
  idle:    "bg-muted/20 border-border/40",
  running: "bg-primary/5 border-primary/30",
  done:    "bg-emerald-50 border-emerald-200",
  error:   "bg-red-50 border-red-200",
  warn:    "bg-amber-50 border-amber-200",
}

const stageLabel: Record<StageStatus, string> = {
  idle:    "text-muted-foreground",
  running: "text-primary font-semibold",
  done:    "text-emerald-700 font-medium",
  error:   "text-red-700 font-semibold",
  warn:    "text-amber-700 font-medium",
}

const logColor: Record<LogEntry["type"], string> = {
  info:    "text-slate-400",
  success: "text-emerald-500",
  error:   "text-red-400 font-semibold",
  warn:    "text-amber-400",
  step:    "text-primary font-semibold",
}

const logPrefix: Record<LogEntry["type"], string> = {
  info:    "   ",
  success: "✅ ",
  error:   "❌ ",
  warn:    "⚠️  ",
  step:    "▶  ",
}

// ─── ResultViewer ─────────────────────────────────────────────────────────────

type TabId = "todos" | "encontrados" | "nao_encontrados" | "por_arquivo" | "por_empresa"

function RetornoPedidosResultViewer({ result }: { result: PipelineResult }) {
  const [activeTab, setActiveTab] = React.useState<TabId>("todos")

  const todos:         any[] = result.todosPedidos     ?? []
  const encontrados:   any[] = result.encontrados      ?? []
  const naoEncontrados:any[] = result.naoEncontrados   ?? []
  const porArquivo:    any[] = result.resumoPorArquivo ?? []
  const porEmpresa:    any[] = result.resumoPorEmpresa ?? []
  const resumoGeral:   any   = result.resumoGeral      ?? {}

  if (!todos.length) return null

  const TABS = [
    { id: "todos"         as TabId, label: "Todos",          count: todos.length,           icon: Hash     },
    { id: "encontrados"   as TabId, label: "Encontrados",    count: encontrados.length,     icon: CheckCircle2 },
    { id: "nao_encontrados" as TabId, label: "Não encontrados", count: naoEncontrados.length, icon: XCircle },
    { id: "por_arquivo"   as TabId, label: "Por arquivo",    count: porArquivo.length,      icon: FileText },
    { id: "por_empresa"   as TabId, label: "Por empresa",    count: porEmpresa.length,      icon: Building2 },
  ]

  const activeData: any[] = {
    todos, encontrados, nao_encontrados: naoEncontrados,
    por_arquivo: porArquivo, por_empresa: porEmpresa,
  }[activeTab]

  const LABELS: Record<string, string> = {
    Arquivo: "Arquivo", Codigo_Cliente: "Cód. Cliente", Numero_Pedido: "Nº Pedido",
    Tipo_Empresa: "Empresa", Chave_Primaria: "Chave Primária", Data_TXT: "Data TXT",
    Codigo_Completo: "Código Completo", Encontrado_Excel: "Encontrado?",
    Linha_Original: "Linha Original", Quantidade: "Qtde", Encontrado: "Encontrado?",
  }

  const COLS_MAP: Record<TabId, string[]> = {
    todos:           ["Arquivo","Codigo_Cliente","Numero_Pedido","Tipo_Empresa","Chave_Primaria","Data_TXT","Encontrado_Excel","Codigo_Completo"],
    encontrados:     ["Arquivo","Codigo_Cliente","Numero_Pedido","Tipo_Empresa","Chave_Primaria","Data_TXT","Codigo_Completo"],
    nao_encontrados: ["Arquivo","Codigo_Cliente","Numero_Pedido","Tipo_Empresa","Chave_Primaria","Data_TXT","Codigo_Completo"],
    por_arquivo:     ["Arquivo","Encontrado_Excel","Quantidade"],
    por_empresa:     ["Tipo_Empresa","Encontrado_Excel","Quantidade"],
  }

  const activeCols = COLS_MAP[activeTab].filter(c => activeData.length && c in activeData[0])

  function fmtCell(col: string, val: any) {
    if (val == null || val === "") return <span className="text-muted-foreground/40">—</span>
    if (col === "Encontrado_Excel") return val === "SIM"
      ? <Badge className="bg-emerald-100 text-emerald-700 border-emerald-200 hover:bg-emerald-100 text-[10px]">SIM</Badge>
      : <Badge className="bg-red-100 text-red-700 border-red-200 hover:bg-red-100 text-[10px]">NÃO</Badge>
    if (col === "Linha_Original") return (
      <span className="font-mono text-[9px] text-muted-foreground truncate max-w-[200px] block">{String(val)}</span>
    )
    if (col === "Chave_Primaria") return (
      <span className="font-mono text-[11px] font-semibold text-primary">{String(val)}</span>
    )
    return <span className="text-xs">{String(val)}</span>
  }

  const taxaSucesso = resumoGeral.totalPedidos
    ? +((resumoGeral.encontrados / resumoGeral.totalPedidos) * 100).toFixed(1)
    : 0

  return (
    <div className="space-y-4 animate-in fade-in duration-500">

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        {[
          { label: "Total extraído",    value: resumoGeral.totalPedidos  ?? 0,    icon: Hash,     highlight: false },
          { label: "Encontrados",       value: `${resumoGeral.encontrados ?? 0} (${resumoGeral.percEncontrados ?? 0}%)`,   icon: CheckCircle2, highlight: true  },
          { label: "Não encontrados",   value: `${resumoGeral.naoEncontrados ?? 0} (${resumoGeral.percNaoEncontrados ?? 0}%)`, icon: XCircle, highlight: false },
          { label: "Clientes únicos",   value: resumoGeral.clientesUnicos ?? 0,   icon: Users,    highlight: false },
        ].map(stat => {
          const Icon = stat.icon
          return (
            <div key={stat.label} className={cn(
              "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
              stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
            )}>
              <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
              </div>
              <div className="min-w-0">
                <p className={cn("text-sm font-bold leading-tight truncate",
                  stat.highlight ? "text-primary" : "text-foreground")}>
                  {typeof stat.value === "number" ? stat.value.toLocaleString("pt-BR") : stat.value}
                </p>
                <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
              </div>
            </div>
          )
        })}
      </div>

      {/* Barra de taxa de sucesso */}
      <div className="rounded-xl border border-border/60 bg-card shadow-sm px-4 py-3 space-y-2">
        <div className="flex justify-between items-center">
          <span className="text-xs font-bold text-foreground">Taxa de localização no Excel</span>
          <span className={cn("text-sm font-bold", taxaSucesso >= 80 ? "text-emerald-600" : taxaSucesso >= 50 ? "text-amber-600" : "text-red-500")}>
            {taxaSucesso}%
          </span>
        </div>
        <Progress value={taxaSucesso} className={cn("h-2", taxaSucesso >= 80 ? "[&>div]:bg-emerald-500" : taxaSucesso >= 50 ? "[&>div]:bg-amber-500" : "[&>div]:bg-red-500")} />
        <div className="flex justify-between text-[10px] text-muted-foreground">
          <span>0%</span>
          <span>{resumoGeral.encontrados} de {resumoGeral.totalPedidos} pedidos</span>
          <span>100%</span>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 flex-wrap">
        {TABS.map(tab => {
          const Icon = tab.icon
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={cn(
                "flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-semibold border transition-all",
                activeTab === tab.id
                  ? "bg-primary text-primary-foreground border-primary shadow-sm"
                  : "bg-card border-border/60 text-muted-foreground hover:bg-muted/30"
              )}
            >
              <Icon className="size-3.5" />
              {tab.label}
              <span className={cn(
                "text-[10px] font-bold px-1.5 py-0.5 rounded-full",
                activeTab === tab.id ? "bg-white/20" : "bg-muted"
              )}>
                {tab.count}
              </span>
            </button>
          )
        })}
      </div>

      {/* Tabela */}
      {activeData.length > 0 && (
        <div className="rounded-xl border border-border/60 bg-card shadow-sm overflow-hidden">
          <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
            <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
              {TABS.find(t => t.id === activeTab)?.label}
            </span>
            <span className="text-[10px] text-muted-foreground">{activeData.length} registros</span>
          </div>
          <ScrollArea className="h-[440px]">
            <div className="overflow-x-auto">
              <Table>
                <TableHeader className="sticky top-0 bg-muted/80 backdrop-blur-sm z-10">
                  <TableRow>
                    {activeCols.map(col => (
                      <TableHead key={col} className="text-[10px] font-bold uppercase whitespace-nowrap px-2 py-2">
                        {LABELS[col] ?? col}
                      </TableHead>
                    ))}
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {activeData.map((row, i) => (
                    <TableRow key={i} className={cn(
                      "text-xs",
                      row["Encontrado_Excel"] === "NÃO" && "bg-red-50/40",
                      row["Encontrado_Excel"] === "SIM" && "bg-emerald-50/20",
                    )}>
                      {activeCols.map(col => (
                        <TableCell key={col} className="px-2 py-1.5 whitespace-nowrap max-w-[250px]">
                          {fmtCell(col, row[col])}
                        </TableCell>
                      ))}
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          </ScrollArea>
        </div>
      )}
    </div>
  )
}

// ─── Componente principal ─────────────────────────────────────────────────────

export function RetornoPedidosPipelineView() {
  const [filesTxt,    setFilesTxt]    = React.useState<File[]>([])
  const [fileExcel,   setFileExcel]   = React.useState<File | null>(null)
  const [isExecuting, setIsExecuting] = React.useState(false)
  const [progress,    setProgress]    = React.useState(0)
  const [stages,      setStages]      = React.useState<Stage[]>(INITIAL_STAGES)
  const [logs,        setLogs]        = React.useState<LogEntry[]>([])
  const [lastResult,  setLastResult]  = React.useState<PipelineResult | null>(null)
  const [stats,       setStats]       = React.useState<{
    total: number; encontrados: number; naoEncontrados: number; arquivos: number
  } | null>(null)

  const logEndRef = React.useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  React.useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" })
  }, [logs])

  const addLog = (message: string, type: LogEntry["type"] = "info") => {
    const time = new Date().toLocaleTimeString("pt-BR")
    setLogs(prev => [...prev, { time, message, type }])
  }

  const setStage = (id: string, status: StageStatus) =>
    setStages(prev => prev.map(s => s.id === id ? { ...s, status } : s))

  const resetStages = () => setStages(INITIAL_STAGES.map(s => ({ ...s, status: "idle" })))

  // Upload múltiplo de TXTs
  const handleTxtChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selected = Array.from(e.target.files ?? [])
    if (!selected.length) return
    setFilesTxt(prev => {
      const existing = new Set(prev.map(f => f.name))
      return [...prev, ...selected.filter(f => !existing.has(f.name))]
    })
    e.target.value = ""
  }

  const removeTxt = (name: string) => setFilesTxt(prev => prev.filter(f => f.name !== name))

  const canRun = filesTxt.length > 0 && !!fileExcel

  const runPipeline = async (downloadOnly = false) => {
    if (!canRun) return
    setIsExecuting(true)
    setProgress(0)
    setLogs([])
    setStats(null)
    resetStages()

    try {
      addLog(`Análise iniciada — ${filesTxt.length} arquivo(s) TXT + Excel`, "step")
      filesTxt.forEach(f => addLog(`TXT: ${f.name} (${(f.size / 1024).toFixed(1)} KB)`))
      addLog(`Excel: ${fileExcel!.name}`)

      // ── Etapa 1: Extração TXT ──────────────────────────────────────────
      setStage("txt", "running")
      setProgress(10)
      addLog("Etapa 1 — Extraindo pedidos dos arquivos TXT...", "step")
      addLog("Regex: (\\d{9})(\\d{3})(BV|RK|KP)(\\d{2})(\\d{6})")
      addLog("Data: padrão B1DDMMYY")

      const formData = new FormData()
      filesTxt.forEach(f => formData.append("filesTxt", f))
      formData.append("fileExcel", fileExcel!)

      const response = await executeRetornoPedidosPipeline(formData)
      if (!response?.success) throw new Error(response?.error || "Erro desconhecido no servidor.")

      setStage("txt", "done")
      addLog(`${response.result.resumoGeral?.totalPedidos ?? "?"} pedidos extraídos dos TXTs.`, "success")
      setProgress(28)

      // ── Etapa 2: Excel ─────────────────────────────────────────────────
      setStage("excel", "running")
      setProgress(38)
      addLog("Etapa 2 — Carregando Excel e auto-detectando colunas...", "step")
      addLog(`Detectado: ${response.result.colunasDetectadas?.pedido ?? "?"} · ${response.result.colunasDetectadas?.cliente ?? "?"}`)
      await new Promise(r => setTimeout(r, 100))
      setStage("excel", "done")
      addLog(`${response.result.resumoGeral?.totalExcel ?? "?"} registros válidos no Excel.`, "success")
      setProgress(52)

      // ── Etapa 3: Padronização ──────────────────────────────────────────
      setStage("norm", "running")
      setProgress(60)
      addLog("Etapa 3 — Padronizando: Pedido → zfill(6) · Cliente → zfill(9)...", "step")
      await new Promise(r => setTimeout(r, 80))
      setStage("norm", "done")
      addLog(`${response.result.resumoGeral?.chavesPrimarias ?? "?"} chaves primárias únicas no Excel.`, "success")
      setProgress(72)

      // ── Etapa 4: Comparação ────────────────────────────────────────────
      setStage("compare", "running")
      setProgress(82)
      addLog("Etapa 4 — Comparando chaves via Set O(1)...", "step")
      await new Promise(r => setTimeout(r, 80))
      setStage("compare", "done")

      const rg = response.result.resumoGeral ?? {}
      addLog(`Encontrados: ${rg.encontrados ?? 0} (${rg.percEncontrados ?? 0}%)`, "success")
      if ((rg.naoEncontrados ?? 0) > 0) {
        addLog(`Não encontrados: ${rg.naoEncontrados} (${rg.percNaoEncontrados}%)`, "warn")
      } else {
        addLog("Todos os pedidos foram localizados no Excel!", "success")
      }
      setProgress(90)

      setStats({
        total:          rg.totalPedidos  ?? 0,
        encontrados:    rg.encontrados   ?? 0,
        naoEncontrados: rg.naoEncontrados ?? 0,
        arquivos:       rg.arquivosProcessados ?? filesTxt.length,
      })
      setLastResult(response.result)

      // ── Etapa 5: Export ────────────────────────────────────────────────
      setStage("export", "running")
      setProgress(96)

      if (downloadOnly) {
        addLog("Gerando Excel com 6 abas...", "step")
        downloadMultipleSheets(
          [
            { data: response.result.todosPedidos     ?? [], name: "Todos_Pedidos"     },
            { data: response.result.encontrados      ?? [], name: "Encontrados"        },
            { data: response.result.naoEncontrados   ?? [], name: "Nao_Encontrados"    },
            { data: response.result.resumoPorArquivo ?? [], name: "Resumo_por_Arquivo" },
            { data: response.result.resumoPorEmpresa ?? [], name: "Resumo_por_Empresa" },
            { data: response.result.resumoGeralSheet ?? [], name: "Resumo_Geral"       },
          ],
          `Resultado_Analise_TXT`
        )
        addLog("Arquivo Excel baixado.", "success")
      } else {
        addLog("Dados sincronizados com Firebase.", "success")
      }

      setStage("export", "done")
      setProgress(100)
      addLog(`Análise concluída em ${new Date().toLocaleTimeString("pt-BR")}.`, "success")

      toast({
        title: downloadOnly ? "Excel pronto" : "Análise concluída",
        description: response.result.summary ?? "",
      })

    } catch (error: any) {
      const msg = error?.message || String(error)
      addLog(`FALHA: ${msg}`, "error")
      setStages(prev => prev.map(s => s.status === "running" ? { ...s, status: "error" } : s))
      setProgress(0)
      toast({ variant: "destructive", title: "Erro na Análise de Pedidos", description: msg })
    } finally {
      setIsExecuting(false)
    }
  }

  const doneCount = stages.filter(s => s.status === "done" || s.status === "warn").length
  const hasError  = stages.some(s => s.status === "error")

  return (
    <div className="space-y-6">

      <Alert className="bg-primary/5 border-primary/20">
        <div className="flex items-center gap-2">
          <Search className="size-4 text-primary" />
          <AlertTitle className="mb-0">Análise de Retorno de Pedidos — TXT vs Excel</AlertTitle>
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <HelpCircle className="size-4 text-muted-foreground cursor-help" />
              </TooltipTrigger>
              <TooltipContent className="max-w-xs">
                <p>Extrai pedidos dos arquivos .txt via regex e compara com STATUS_PEDIDOS_MERCANETE.xlsx pela chave primária Codigo_Cliente_NumeroPedido.</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
        <AlertDescription className="text-sm mt-2">
          Padrão: <code className="bg-muted px-1 rounded text-[10px]">9d+3d+(BV|RK|KP)+2d+6d</code>
          {" · "}Chave: <code className="bg-muted px-1 rounded text-[10px]">Codigo_Cliente_NumeroPedido</code>
          {" · "}Múltiplos encodings (UTF-8, Latin-1, CP1252, ISO-8859-1)
        </AlertDescription>
      </Alert>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* ── Coluna principal ── */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="shadow-sm border-border/60">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Search className="size-5 text-primary" />
                Configuração da Análise
              </CardTitle>
              <CardDescription>Arquivos TXT de relatório + BASE Excel de referência</CardDescription>
            </CardHeader>

            <CardContent className="space-y-5">

              {/* Arquivos TXT */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold flex items-center gap-2">
                  <FileText className="size-3.5 text-slate-500" />
                  Arquivos TXT (relatórios)
                  <Badge variant="destructive" className="text-[9px] px-1.5 py-0 h-4 ml-auto">obrigatório</Badge>
                </Label>

                {/* Botão adicionar */}
                <button
                  className="w-full flex items-center gap-2 px-3 py-2.5 rounded-lg border border-dashed bg-background hover:bg-muted/20 transition-colors text-left"
                  onClick={() => document.getElementById("rp-txt-upload")?.click()}
                >
                  <Plus className="size-3.5 text-muted-foreground shrink-0" />
                  <span className="text-xs text-muted-foreground italic flex-1">
                    {filesTxt.length === 0
                      ? "Adicionar arquivo(s) .txt..."
                      : `Adicionar mais arquivos (${filesTxt.length} selecionado${filesTxt.length > 1 ? "s" : ""})`}
                  </span>
                  <input id="rp-txt-upload" type="file" className="hidden" accept=".txt" multiple onChange={handleTxtChange} />
                </button>

                {/* Lista de TXTs */}
                {filesTxt.length > 0 && (
                  <div className="space-y-1 max-h-36 overflow-y-auto pr-0.5">
                    {filesTxt.map(f => (
                      <div key={f.name} className="flex items-center gap-2 px-2.5 py-1.5 rounded-lg bg-muted/20 border text-xs">
                        <FileText className="size-3 text-slate-400 shrink-0" />
                        <span className="flex-1 truncate font-medium text-slate-700">{f.name}</span>
                        <span className="text-[10px] text-muted-foreground shrink-0">{(f.size / 1024).toFixed(1)} KB</span>
                        <Button variant="ghost" size="icon" className="size-5 shrink-0" onClick={() => removeTxt(f.name)}>
                          <Trash2 className="size-2.5 text-destructive/70" />
                        </Button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              <Separator />

              {/* Excel */}
              <div className="space-y-2">
                <Label className="text-sm font-semibold flex items-center gap-2">
                  <FileSpreadsheet className="size-3.5 text-emerald-600" />
                  Base de Referência Excel
                  <Badge variant="destructive" className="text-[9px] px-1.5 py-0 h-4 ml-auto">obrigatório</Badge>
                </Label>
                <div className="flex items-center gap-2 bg-background px-3 py-2.5 rounded-lg border text-xs">
                  <FileSpreadsheet className="size-3.5 text-emerald-500 shrink-0" />
                  <span className={cn("text-[10px] font-bold px-1.5 py-0.5 rounded shrink-0",
                    "bg-emerald-100 text-emerald-700")}>Mercanete</span>
                  <span className="truncate flex-1 font-medium text-muted-foreground">
                    {fileExcel ? fileExcel.name : <span className="italic">STATUS_PEDIDOS_MERCANETE.xlsx</span>}
                  </span>
                  {fileExcel && (
                    <Button variant="ghost" size="icon" className="size-6 shrink-0" onClick={() => setFileExcel(null)}>
                      <Trash2 className="size-3 text-destructive/70" />
                    </Button>
                  )}
                  <Button asChild variant="outline" size="sm" className="h-6 text-[10px] px-2 cursor-pointer shrink-0">
                    <Label htmlFor="rp-excel-upload">{fileExcel ? "Trocar" : "Selecionar"}</Label>
                  </Button>
                  <Input
                    id="rp-excel-upload" type="file" className="hidden" accept=".xlsx,.xls"
                    onChange={e => { if (e.target.files?.[0]) setFileExcel(e.target.files[0]); e.target.value = "" }}
                  />
                </div>
                <p className="text-[10px] text-muted-foreground pl-1">
                  Colunas detectadas automaticamente: Pedido (original/pedido) · Cliente (código_cliente / numérico 9d)
                </p>
              </div>

              {/* Progress */}
              {(isExecuting || progress > 0) && (
                <div className="space-y-2 pt-1">
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-bold uppercase tracking-wider text-primary">
                      {hasError ? "Erro na execução" : progress === 100 ? "Concluído" : "Processando..."}
                    </span>
                    <span className="text-[10px] font-mono font-bold text-muted-foreground">{progress}%</span>
                  </div>
                  <Progress
                    value={progress}
                    className={cn("h-2 transition-all", hasError && "[&>div]:bg-destructive")}
                  />
                  <div className="flex justify-between text-[9px] text-muted-foreground">
                    <span>{doneCount}/{stages.length} etapas</span>
                    <span>
                      {isExecuting
                        ? stages.find(s => s.status === "running")?.label ?? "..."
                        : progress === 100 ? "Análise finalizada" : ""}
                    </span>
                  </div>
                </div>
              )}
            </CardContent>

            <CardFooter className="bg-muted/5 border-t pt-4 pb-4 flex gap-2">
              <Button
                variant="outline"
                size="sm"
                className="flex-1 h-9 text-xs font-semibold border-slate-300 text-slate-600 hover:bg-slate-50 hover:text-slate-800 hover:border-slate-400 transition-all"
                onClick={() => runPipeline(true)}
                disabled={isExecuting || !canRun}
              >
                <Download className="mr-1.5 size-3.5" /> Exportar Excel
              </Button>
              <Button
                size="sm"
                className="flex-1 h-9 text-xs font-semibold bg-primary hover:bg-primary/90 shadow-sm transition-all"
                onClick={() => runPipeline(false)}
                disabled={isExecuting || !canRun}
              >
                {isExecuting
                  ? <><Loader2 className="mr-1.5 size-3.5 animate-spin" /> Processando...</>
                  : <><Play className="mr-1.5 size-3.5 fill-current" /> Iniciar Análise</>}
              </Button>
            </CardFooter>
          </Card>
        </div>

        {/* ── Coluna lateral ── */}
        <div className="space-y-4">

          {/* Etapas */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10">
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Etapas de Execução
              </span>
            </div>
            <div className="p-3 space-y-2">
              {stages.map((stage, idx) => (
                <div key={stage.id} className="flex items-start gap-2">
                  <div className="flex flex-col items-center pt-0.5">
                    <StageIcon status={stage.status} />
                    {idx < stages.length - 1 && (
                      <div className={cn(
                        "w-px mt-1 min-h-[14px]",
                        stage.status === "done" ? "bg-emerald-300" : "bg-border/60"
                      )} />
                    )}
                  </div>
                  <div className={cn("flex-1 px-2.5 py-1.5 rounded-lg border text-xs transition-all", stageBg[stage.status])}>
                    <p className={cn("leading-tight", stageLabel[stage.status])}>{stage.label}</p>
                    <p className="text-[10px] text-muted-foreground leading-tight mt-0.5">{stage.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Stats pós-execução */}
          {stats && (
            <div className="grid grid-cols-2 gap-2">
              {[
                { label: "Arquivos TXT",    value: stats.arquivos,       icon: FileText,    highlight: false },
                { label: "Total pedidos",   value: stats.total,          icon: Hash,        highlight: false },
                { label: "Encontrados",     value: stats.encontrados,    icon: CheckCircle2,highlight: true  },
                { label: "Não encontrados", value: stats.naoEncontrados, icon: XCircle,     highlight: stats.naoEncontrados > 0 },
              ].map(stat => {
                const Icon = stat.icon
                return (
                  <div key={stat.label} className={cn(
                    "rounded-xl border px-3 py-2.5 flex items-center gap-2 shadow-sm",
                    stat.highlight ? "bg-primary/5 border-primary/20" : "bg-card border-border/60"
                  )}>
                    <div className={cn("size-7 rounded-lg flex items-center justify-center shrink-0",
                      stat.highlight ? "bg-primary/10" : "bg-muted/30")}>
                      <Icon className={cn("size-3.5", stat.highlight ? "text-primary" : "text-muted-foreground")} />
                    </div>
                    <div className="min-w-0">
                      <p className={cn("text-sm font-bold leading-tight truncate",
                        stat.highlight ? "text-primary" : "text-foreground")}>
                        {stat.value.toLocaleString("pt-BR")}
                      </p>
                      <p className="text-[10px] text-muted-foreground leading-tight">{stat.label}</p>
                    </div>
                  </div>
                )
              })}
            </div>
          )}

          {/* Regras de extração */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center gap-2">
              <Info className="size-3 text-muted-foreground" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                Lógica de Extração
              </span>
            </div>
            <div className="p-3 space-y-1.5">
              {REGRAS.map((rule, idx) => (
                <div key={idx} className={cn(
                  "flex items-center gap-2 rounded-lg border px-2.5 py-1.5 text-[11px]",
                  rule.color
                )}>
                  <ChevronRight className="size-3 shrink-0 opacity-60" />
                  <span className="font-semibold shrink-0">{rule.label}</span>
                  <span className="opacity-50 shrink-0">→</span>
                  <span className="text-[10px] font-mono">{rule.detail}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Console */}
          <div className="rounded-xl border border-border/60 bg-card overflow-hidden shadow-sm">
            <div className="px-4 py-2.5 border-b bg-muted/10 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="size-3 text-muted-foreground" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Console</span>
              </div>
              {logs.length > 0 && (
                <button onClick={() => setLogs([])} className="text-[9px] text-muted-foreground hover:text-foreground transition-colors">
                  limpar
                </button>
              )}
            </div>
            <ScrollArea className="h-[180px] bg-slate-950">
              <div className="p-3 font-mono text-[10px] leading-relaxed space-y-0.5">
                {logs.length === 0
                  ? <span className="text-slate-500 italic">Aguardando execução...</span>
                  : logs.map((log, i) => (
                    <div key={i} className={cn("flex gap-1.5", logColor[log.type])}>
                      <span className="text-slate-600 shrink-0">{log.time}</span>
                      <span className="shrink-0">{logPrefix[log.type]}</span>
                      <span className="break-all">{log.message}</span>
                    </div>
                  ))
                }
                <div ref={logEndRef} />
              </div>
            </ScrollArea>
          </div>

        </div>
      </div>

      {lastResult && !isExecuting && <RetornoPedidosResultViewer result={lastResult} />}
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Play,
  Trash2,
  FileCode,
  Loader2,
  Download,
  Info,
  HelpCircle,
  CheckCircle2,
  Circle,
  XCircle,
  AlertTriangle,
  ChevronRight,
  Terminal,
  Truck,
  FileSpreadsheet,
  DollarSign,
  CalendarDays,
  TrendingUp,
  MapPin,
  Weight,
  Clock,
  BarChart2,
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardHeader, CardTitle, CardContent, CardDescription, CardFooter } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { AIParamAssistant } from "../../pages/AI-Param-Assistant"
import { ScrollArea } from "@/components/ui/scroll-area"
import { executeRoadshowPipeline } from "@/app/actions/import-roadshow-actions"
import { useToast } from "@/hooks/use-toast"
import { PipelineResult } from "@/lib/firebase"
import { Progress } from "@/components/ui/progress"
import { downloadMultipleSheets } from "@/lib/excel-utils"
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"

// ─── Tipos ────────────────────────────────────────────────────────────────────

type StageStatus = "idle" | "running" | "done" | "error" | "warn"

interface Stage {
  id: string
  label: string
  description: string
  status: StageStatus
}

interface LogEntry {
  time: string
  message: string
  type: "info" | "success" | "error" | "warn" | "step"
}

// ─── Constantes ───────────────────────────────────────────────────────────────

const DEFAULT_META_JORNADA_MAX = 100
const DEFAULT_META_VEICULO_MIN = 85
const DEFAULT_VALOR_MENSAL     = 400.0
const DEFAULT_DIAS_META        = 25

const INITIAL_STAGES: Stage[] = [
  { id: "load",    label: "Módulo 1 — Carregar arquivos",    description: "Consolidado + Performaxxi + Veículos (opcional)",  status: "idle" },
  { id: "prep",    label: "Módulo 2 — Preparar consolidado", description: "Filtro mês/ano · Tipagem · TEMPO → timedelta",     status: "idle" },
  { id: "prod",    label: "Módulo 3 — Tempo produtivo",      description: "Fim − Início por DATA + PLACA (Performaxxi)",       status: "idle" },
  { id: "ocup",    label: "Módulo 4 — Ocupações",            description: "Jornada (%) = Produtivo ÷ Jornada · Veículo (%) = Peso ÷ Cap", status: "idle" },
  { id: "inc",     label: "Módulo 5 — Incentivo por região", description: "Jornada ≤ 100% → Jornada | > 100% → Veículo",     status: "idle" },
  { id: "resumo",  label: "Módulo 6 — Resumo mensal",        description: "Totais por região + cálculo aritmético",           status: "idle" },
  { id: "export",  label: "Exportar / Salvar Firebase",      description: "6 abas: Consolidado · Diário · Incentivo · Detalhe · Resumo · Arit.", status: "idle" },
]

const REGRAS_INCENTIVO = [
  { condition: "Jornada ≤ 100%",   result: "Indicador = Jornada (100% do dia)",      variant: "success" as const },
  { condition: "Jornada > 100%",   result: "Indicador = % Ocupação Veículo",          variant: "warn"    as const },
  { condition: "Incentivo / dia",  result: "Indicador % × (R$ meta / dias_meta)",     variant: "info"    as const },
]

// ─── Helpers visuais ──────────────────────────────────────────────────────────

function StageIcon({ status }: { status: StageStatus }) {
  if (status === "running") return <Loader2 className="size-4 animate-spin text-primary shrink-0" />
  if (status === "done")    return <CheckCircle2 className="size-4 text-emerald-500 shrink-0" />
  if (status === "error")   return <XCircle className="size-4 text-destructive shrink-0" />
  if (status === "warn")    return <AlertTriangle className="size-4 text-amber-500 shrink-0" />
  return <Circle className="size-4 text-muted-foreground/30 shrink-0" />
}

const stageBg: Record<StageStatus, string> = {
  idle:    "bg-muted/20 border-border/40",
