// ─────────────────────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

const CAMPOS = [
  "DM_FILIAL","DT_FATURAMENTO","DT_RETORNO","DT_FECHAMENTO","DIAS_ABERTO",
  "CARGA","VIAGEM","PEDIDO","TIPO_OPERACAO","NOTA","MUNICIPIO","ENDERECO",
  "COD_CLIENTE","LOJA","CLIENTE","FATURAMENTO","FATURAMENTO_DEV","VOLUME",
